  var toggle_base_default = '<h1 id="togglebase"><a class="header-anchor" href="#togglebase">#</a>ToggleBase</h1><p>Base class for toggle components, used to implement custom toggle components.</p>\n<h2 id="description"><a class="header-anchor" href="#description">#</a>Description</h2><p>This is an internal base class, generally not used directly in applications unless you want to implement custom toggle interaction logic.</p>\n';

  // apps/doc/web/src/markdown-built/en/lupine.components/toggle-switch.html
  var toggle_switch_default = '<h1 id="toggleswitch"><a class="header-anchor" href="#toggleswitch">#</a>ToggleSwitch</h1><p>Toggle switch, commonly used for settings.</p>\n<h2 id="implementation-example"><a class="header-anchor" href="#implementation-example">#</a>Implementation Example</h2><pre><code class="language-typescript">import { ToggleSwitch, ToggleSwitchSize } from &#39;lupine.components&#39;;\n\n&lt;ToggleSwitch checked={true} size={ToggleSwitchSize.Medium} text={{ on: &#39;On&#39;, off: &#39;Off&#39; }} textWidth=&#39;60px&#39; /&gt;;\n</code></pre>\n';

  // apps/doc/web/src/markdown-built/en/lupine.press/index.html
  var lupine_default4 = "";

  // apps/doc/web/src/markdown-built/en/lupine.press/overview.html
  var overview_default = '<h1 id="lupine-press"><a class="header-anchor" href="#lupine-press">#</a>lupine.press</h1><p><code>lupine.press</code> is a lightweight, high-performance documentation site framework built on top of <code>lupine.web</code>. It provides a complete solution for rendering Markdown-based documentation websites with a responsive layout, sidebar navigation, and theming support.</p>\n<p>It is designed to work seamlessly with the <code>lupine</code> ecosystem, powering documentation sites like the official Lupine.js documentation.</p>\n<h2 id="features"><a class="header-anchor" href="#features">#</a>Features</h2><ul>\n<li><strong>Responsive Layout</strong>: Built-in <code>PressFrame</code> provides a standard documentation layout with a header, responsive sidebar, and content area.</li>\n<li><strong>Markdown Rendering</strong>: Optimized for rendering content generated from Markdown files, including syntax highlighting and standard typography.</li>\n<li><strong>Sidebar Navigation</strong>: Automatically generates a multi-level sidebar based on your configuration.</li>\n<li><strong>Theming</strong>: Built-in support for multiple themes (e.g., light/dark mode) via <code>lupine.components</code> theme system.</li>\n<li><strong>Routing</strong>: explicit integration with <code>PageRouter</code> for handling client-side navigation.</li>\n<li><strong>Multilingual Support</strong>: Automatically scans markdown files from multilingual directories and supports language switching.</li>\n<li><strong>Styles Support</strong>: You can set styles in markdown files.</li>\n</ul>\n<h2 id="usage-guide"><a class="header-anchor" href="#usage-guide">#</a>Usage Guide</h2><h3 id="1-create-a-project"><a class="header-anchor" href="#1-create-a-project">#</a>1. Create a Project</h3><p>To use <code>lupine.press</code>, you typically set up a <code>lupine.web</code> application and configure it to use <code>PressPage</code> as the main route handler.\nThe easiest way is to use the <code>create-lupine</code> command to create a new <code>lupine.press</code> application.</p>\n<pre><code class="language-bash">npx create-lupine@latest my-docs\n</code></pre>\n<p>Then select <code>doc-starter</code> template.</p>\n<h3 id="2-basic-setup"><a class="header-anchor" href="#2-basic-setup">#</a>2. Basic Setup</h3><p>You can see these configurations in the created application.\nIn your application entry point (e.g., <code>src/index.tsx</code>), you can see the necessary binding configurations and router settings.</p>\n<pre><code class="language-typescript">import { bindRouter, PageRouter, bindTheme, bindLang, setDefaultPageTitle } from &#39;lupine.components&#39;;\nimport { bindPressData, PressPage, pressThemes } from &#39;lupine.press&#39;;\nimport { markdownConfig } from &#39;./markdown-config&#39;; // Your generated markdown data\n\n// 1. Initialize core settings\nbindLang(&#39;en&#39;, {}); // Set default language\nbindTheme(&#39;light&#39;, pressThemes); // Bind themes (includes specific styles for press)\nsetDefaultPageTitle(&#39;My Documentation&#39;);\n\n// 2. Bind documentation data\n// markdownConfig is a dictionary containing HTML content and metadata generated from markdown files.\nbindPressData(markdownConfig);\n\n// 3. Configure Router\nconst pageRouter = new PageRouter();\n// Route all requests to PressPage, which handles looking up content in markdownConfig\npageRouter.use(&#39;*&#39;, PressPage);\n\n// 4. Start the application\nbindRouter(pageRouter);\n</code></pre>\n<h3 id="3-data-structure-markdownconfig"><a class="header-anchor" href="#3-data-structure-markdownconfig">#</a>3. Data Structure (<code>markdownConfig</code>)</h3><p>The <code>bindPressData</code> function expects a configuration object where keys are route paths (e.g., <code>/guide/started</code>) and values contain the content and metadata.</p>\n<p>Typically, this data is generated at build time from your Markdown files.</p>\n<pre><code class="language-typescript">export const markdownConfig = {\n  &#39;/en/guide/started&#39;: {\n    html: &#39;&lt;h1&gt;Getting Started&lt;/h1&gt;&lt;p&gt;...&lt;/p&gt;&#39;, // Pre-rendered HTML content\n    data: {\n      title: &#39;Getting Started&#39;,\n      sidebar: [\n        // Sidebar configuration for this page context\n        { type: &#39;group&#39;, text: &#39;Guide&#39;, level: 0 },\n        { type: &#39;link&#39;, text: &#39;Installation&#39;, link: &#39;/en/guide/install&#39;, level: 1 },\n      ],\n    },\n    headings: [{ level: 2, text: &#39;Prerequisites&#39;, id: &#39;prerequisites&#39; }],\n  },\n  // ... other pages\n};\n</code></pre>\n<h2 id="markdown-file-structure-association"><a class="header-anchor" href="#markdown-file-structure-association">#</a>Markdown File Structure &amp; Association</h2><h3 id="top-level-configuration"><a class="header-anchor" href="#top-level-configuration">#</a>Top-level Configuration</h3><p>A <code>index.md</code> file must exist in the top-level directory of your Markdown files. This file uses the <code>lang</code> field to specify all supported languages for the site.</p>\n<pre><code class="language-yaml">---\nlang:\n  - title: English\n    id: en\n  - title: \u7B80\u4F53\u4E2D\u6587\n    id: zh\n---\n</code></pre>\n<h3 id="multilingual-configuration"><a class="header-anchor" href="#multilingual-configuration">#</a>Multilingual Configuration</h3><p>Each language ID (e.g., <code>en</code>, <code>zh</code>) corresponds to a subdirectory, which must contain its own <code>index.md</code> file. This file configures global settings for that language version, such as layout, page title, and sidebar width. All Markdown content files for that language should be stored within this directory or its subdirectories.</p>\n<p>The <code>index.md</code> supports defining:</p>\n<ul>\n<li><strong>Hero &amp; Features</strong>: Homepage hero banner and feature introduction.</li>\n<li><strong>Nav</strong>: Top navigation links.</li>\n<li><strong>GitHub</strong>: Repository links.</li>\n<li><strong>Sidebar</strong>: Sidebar menu configuration (Core parameter).</li>\n</ul>\n<h3 id="sidebar-configuration"><a class="header-anchor" href="#sidebar-configuration">#</a>Sidebar Configuration</h3><p>The <code>sidebar</code> parameter is an array that supports three configuration patterns:</p>\n<ol>\n<li><strong>Submenu Pattern (<code>submenu</code>)</strong>:\nPoints to a subdirectory. The system will automatically expand the <code>sidebar</code> configuration defined in that subdirectory&#39;s <code>index.md</code> and merge its content into the current level.</li>\n<li><strong>Group Pattern (<code>text</code> + <code>items</code>)</strong>:\nDefines a menu group. <code>text</code> is the group title, and <code>items</code> is the list of links under this group.</li>\n<li><strong>Flat Pattern (<code>items</code> only)</strong>:\nDefines <code>items</code> without <code>text</code>. In this case, all links in <code>items</code> will be displayed directly at the current level without grouping.</li>\n</ol>\n<h2 id="architecture"><a class="header-anchor" href="#architecture">#</a>Architecture</h2><ul>\n<li><strong><code>PressFrame</code></strong>: The main layout component. It handles the specific CSS and structure for a documentation site, ensuring the sidebar and content area scroll independently.</li>\n<li><strong><code>PressPage</code></strong>: The &quot;controller&quot; component. It looks up the current URL in the bound <code>markdownConfig</code>, retrieves the corresponding HTML and metadata, and renders the <code>PressFrame</code> with the correct sidebar and content.</li>\n<li><strong><code>pressLoad</code></strong>: A navigation utility to handle link clicks within the documentation, ensuring smooth client-side transitions.</li>\n</ul>\n<h2 id="styles"><a class="header-anchor" href="#styles">#</a>Styles</h2><p>styles can define font, color styles and will be applied to all pages.</p>\n<pre><code class="language-css">styles:\n  &#39;:root&#39;: { &#39;--primary-accent-color&#39;: &#39;#0ac92a&#39; }\n  body: { font-family: var(--font-family-base); }\n</code></pre>\n';

  // apps/doc/web/src/markdown-built/en/lupine.web/index.html
  var lupine_default5 = `<h1 id="lupine-web"><a class="header-anchor" href="#lupine-web">#</a>lupine.web</h1><p><strong>lupine.web</strong> is a React-like, extremely fast, small-size, and lightweight frontend framework.</p>
<p>Explore the documentation:</p>
<ul>
<li><a href="javascript:lpPressLoad('/en/lupine.web/overview')">Overview</a></li>
</ul>
`;

  // apps/doc/web/src/markdown-built/en/lupine.web/overview.html
  var overview_default2 = `<h1 id="lupine-web"><a class="header-anchor" href="#lupine-web">#</a>lupine.web</h1><p><strong>lupine.web</strong> is a React-like, extremely fast, small-size, and lightweight frontend framework designed for modern web development. It focuses on performance, simplicity, and a full-stack experience when paired with <code>lupine.api</code>.</p>
<h2 id="why-lupine-web"><a class="header-anchor" href="#why-lupine-web">#</a>Why lupine.web?</h2><h3 id="zero-dependency-lightweight"><a class="header-anchor" href="#zero-dependency-lightweight">#</a>\u{1F680} Zero-Dependency &amp; Lightweight</h3><p>We believe in keeping things simple. <code>lupine.web</code> has <strong>zero external dependencies</strong>, resulting in a tiny bundle size and lightning-fast load times. It uses TSX syntax, so if you know React, you already feel at home.</p>
<h3 id="built-in-css-in-js-essentials-css-in-js"><a class="header-anchor" href="#built-in-css-in-js-essentials-css-in-js">#</a>\u{1F3A8} Built-in CSS-in-JS <a href="javascript:lpPressLoad('/en/essentials/css-in-js')">\u{1F517}</a></h3><p>Forget about setting up complex CSS loaders or external styling libraries. <code>lupine.web</code> comes with a powerful, built-in CSS-in-JS solution.</p>
<ul>
<li><strong>Scoped Styles</strong>: Styles are automatically scoped to your components to prevent collisions.</li>
<li><strong>Nesting Support</strong>: Write cleaner CSS with nested selectors (e.g., <code>&amp;:hover</code>, <code>&amp; &gt; span</code>).</li>
<li><strong>Theming</strong>: Native support for light/dark modes and custom themes.</li>
</ul>
<pre><code class="language-tsx">const MyButton = (props) =&gt; (
  &lt;button
    css={{
      backgroundColor: &#39;blue&#39;,
      color: &#39;white&#39;,
      &#39;&amp;:hover&#39;: { backgroundColor: &#39;darkblue&#39; },
      [MediaQueryRange.Mobile]: { width: &#39;100%&#39; },
    }}
  &gt;
    {props.children}
  &lt;/button&gt;
);
</code></pre>
<h3 id="powerful-router-essentials-page-route"><a class="header-anchor" href="#powerful-router-essentials-page-route">#</a>\u{1F6E3}\uFE0F Powerful Router <a href="javascript:lpPressLoad('/en/essentials/page-route')">\u{1F517}</a></h3><p>Our functional router is designed for flexibility and control.</p>
<ul>
<li><strong>Route Guards</strong>: Easily implement authentication checks or permissions.</li>
<li><strong>Nested Routes</strong>: Organize your application with sub-routers for modular architecture.</li>
<li><strong>SSR Ready</strong>: Routes work seamlessly on both server and client.</li>
</ul>
<pre><code class="language-typescript">const pageRouter = new PageRouter();
// Middleware/Guard example
pageRouter.setFilter(async (props) =&gt; {
  if (!checkAuth(props)) return &lt;Redirect to=&#39;/login&#39; /&gt;;
  return null; // Pass
});
pageRouter.use(&#39;/dashboard/*&#39;, DashboardRouter);
</code></pre>
<h3 id="server-side-rendering-ssr-first-essentials-ssr"><a class="header-anchor" href="#server-side-rendering-ssr-first-essentials-ssr">#</a>\u26A1 Server-Side Rendering (SSR) First <a href="javascript:lpPressLoad('/en/essentials/ssr')">\u{1F517}</a></h3><p>Visual performance is critical. <code>lupine.web</code> is built with SSR in mind from day one.</p>
<ul>
<li><strong>No Flashing</strong>: Content is rendered on the server, ensuring users see the page immediately.</li>
<li><strong>SEO Friendly</strong>: Fully customizable Metadata and Open Graph (OG) tags for social sharing.</li>
<li><strong>Hydration</strong>: The client takes over smoothly without re-rendering the entire tree.</li>
</ul>
<h3 id="internationalization-i18n"><a class="header-anchor" href="#internationalization-i18n">#</a>\u{1F30D} Internationalization (i18n)</h3><p>Go global with ease. Built-in support for multi-language applications allows you to switch languages dynamically without complex configuration.</p>
<h3 id="environment-configuration"><a class="header-anchor" href="#environment-configuration">#</a>\u{1F6E0}\uFE0F Environment Configuration</h3><p>Manage your application environments efficiently. <code>lupine.web</code> supports loading environment variables (from <code>.env</code> files via <code>lupine.api</code>) and injecting strictly filtered configurations into the frontend.</p>
`;

  // apps/doc/web/src/markdown-built/zh/articles/cross-platform-app.html
  var cross_platform_app_default2 = '<p>\u201C\u4E00\u6B21\u7F16\u5199\uFF0C\u5230\u5904\u8FD0\u884C\u201D\u7684\u68A6\u60F3\u5F80\u5F80\u4F34\u968F\u7740\u5DE8\u5927\u7684\u59A5\u534F\u3002\u6C89\u91CD\u7684\u6846\u67B6\u3001\u6DF7\u4E71\u7684\u6761\u4EF6\u5224\u65AD\u4EE3\u7801\u4EE5\u53CA\u7CDF\u7CD5\u7684\u6027\u80FD\uFF0C\u901A\u5E38\u662F\u8DE8\u5E73\u53F0\u5F00\u53D1\u7684\u5669\u68A6\u3002</p>\n<p><strong>Lupine.js</strong> \u6539\u53D8\u4E86\u8FD9\u4E00\u5207\u3002\u5B83\u4ECE\u5E95\u5C42\u8BBE\u8BA1\u5F00\u59CB\u5C31\u662F\u4E00\u4E2A<strong>\u901A\u7528\u6846\u67B6</strong>\u3002\u901A\u8FC7\u5229\u7528 <strong>Capacitor</strong> (\u79FB\u52A8\u7AEF) \u548C <strong>Electron</strong> (\u684C\u9762\u7AEF)\uFF0C\u4F60\u53EF\u4EE5\u5229\u7528\u540C\u4E00\u5957 TypeScript \u4EE3\u7801\u5E93\uFF0C\u5C06\u5E94\u7528\u53D1\u5E03\u5230 Web\u3001iOS\u3001Android\u3001Windows\u3001macOS \u548C Linux\u3002</p>\n<p><img src="/lupine.js/assets/architecture_cross_platform.png" alt="Lupine.js \u67B6\u6784"></p>\n<p>\u5728\u672C\u6307\u5357\u4E2D\uFF0C\u6211\u4EEC\u5C06\u4EE5\u5373\u5C06\u771F\u5B9E\u4E0A\u7EBF\u7684 <strong>Lupine \u793A\u4F8B\u5E94\u7528</strong> \u5E94\u7528\u4E3A\u4F8B\uFF0C\u6F14\u793A\u5982\u4F55\u5C06\u4E00\u4E2A\u6807\u7684 Lupine.js Web \u5E94\u7528\u6269\u5C55\u5230\u79FB\u52A8\u7AEF\u548C\u684C\u9762\u7AEF\u3002</p>\n<h2 id="1-\u6838\u5FC3-\u54CD\u5E94\u5F0F-web-\u5E94\u7528"><a class="header-anchor" href="#1-\u6838\u5FC3-\u54CD\u5E94\u5F0F-web-\u5E94\u7528">#</a>1. \u6838\u5FC3\uFF1A\u54CD\u5E94\u5F0F Web \u5E94\u7528</h2><p>\u5728\u63A5\u89E6\u4EFB\u4F55\u539F\u751F\u4EE3\u7801\u4E4B\u524D\uFF0C\u6211\u4EEC\u9700\u8981\u4E00\u4E2A\u54CD\u5E94\u5F0F\u7684 Web \u5E94\u7528\u3002Lupine.js \u901A\u8FC7\u5185\u7F6E\u7684\u54CD\u5E94\u5F0F\u5DE5\u5177\u548C CSS-in-JS \u5F15\u64CE\uFF0C\u8BA9\u8FD9\u4E00\u5207\u53D8\u5F97\u7B80\u5355\u3002</p>\n<h3 id="\u54CD\u5E94\u5F0F\u6837\u5F0F"><a class="header-anchor" href="#\u54CD\u5E94\u5F0F\u6837\u5F0F">#</a>\u54CD\u5E94\u5F0F\u6837\u5F0F</h3><p>\u4F60\u4E0D\u9700\u8981\u4E3A\u79FB\u52A8\u7AEF\u7F16\u5199\u5355\u72EC\u7684 CSS \u6587\u4EF6\uFF0C\u800C\u662F\u76F4\u63A5\u5728\u7EC4\u4EF6\u6837\u5F0F\u4E2D\u4F7F\u7528 <code>MediaQueryRange</code>\uFF1A</p>\n<pre><code class="language-tsx">import { MediaQueryRange, CssProps } from &#39;lupine.web&#39;;\n\nconst css: CssProps = {\n  // \u9ED8\u8BA4 (\u684C\u9762) \u6837\u5F0F\n  padding: &#39;50px&#39;,\n  fontSize: &#39;18px&#39;,\n\n  // \u79FB\u52A8\u7AEF\u8986\u76D6\u6837\u5F0F\n  [MediaQueryRange.MobileBelow]: {\n    padding: &#39;10px&#39;,\n    fontSize: &#39;14px&#39;,\n    flexDirection: &#39;column&#39;,\n  },\n};\n</code></pre>\n<h3 id="\u81EA\u9002\u5E94\u6846\u67B6-layout"><a class="header-anchor" href="#\u81EA\u9002\u5E94\u6846\u67B6-layout">#</a>\u81EA\u9002\u5E94\u6846\u67B6 Layout</h3><p>\u5BF9\u4E8E\u5BFC\u822A\uFF0C<code>ResponsiveFrame</code> \u7EC4\u4EF6\u4F1A\u6839\u636E\u8BBE\u5907\u81EA\u52A8\u5728\u201C\u684C\u9762\u9876\u90E8\u83DC\u5355\u201D\u548C\u201C\u79FB\u52A8\u7AEF\u5E95\u90E8\u5BFC\u822A\u680F\u201D\u4E4B\u95F4\u5207\u6362\u3002</p>\n<pre><code class="language-tsx">&lt;ResponsiveFrame\n  desktopHeaderTitle=&#39;\u6211\u7684\u5E94\u7528&#39;\n  // ... \u684C\u9762\u83DC\u5355\u9879\n  mobileBottomMenu={[\n    { title: &#39;\u9996\u9875&#39;, icon: &lt;HomeIcon /&gt;, link: &#39;/home&#39; },\n    { title: &#39;\u6211\u7684&#39;, icon: &lt;UserIcon /&gt;, link: &#39;/me&#39; },\n  ]}\n  mainContent={&lt;PageComponent /&gt;}\n/&gt;\n</code></pre>\n<h2 id="2-\u8FDB\u519B\u79FB\u52A8\u7AEF-ios-android"><a class="header-anchor" href="#2-\u8FDB\u519B\u79FB\u52A8\u7AEF-ios-android">#</a>2. \u8FDB\u519B\u79FB\u52A8\u7AEF (iOS &amp; Android)</h2><p>Lupine.js \u4F7F\u7528 <strong>Capacitor</strong> \u5C06\u4F60\u7684 Web \u5E94\u7528\u5305\u88C5\u6210\u539F\u751F App\u3002\u8FD9\u8BA9\u4F60\u65E2\u80FD\u8BBF\u95EE\u539F\u751F\u529F\u80FD\uFF08\u76F8\u673A\u3001\u6587\u4EF6\u7CFB\u7EDF\uFF09\uFF0C\u53C8\u80FD\u4FDD\u6301 Web \u5F00\u53D1\u7684\u6D41\u7545\u5DE5\u4F5C\u6D41\u3002</p>\n<h3 id="\u6B65\u9AA4-2-1-\u5B89\u88C5-capacitor"><a class="header-anchor" href="#\u6B65\u9AA4-2-1-\u5B89\u88C5-capacitor">#</a>\u6B65\u9AA4 2.1: \u5B89\u88C5 Capacitor</h3><p>\u5728\u9879\u76EE\u6839\u76EE\u5F55\uFF0C\u5B89\u88C5\u5FC5\u8981\u7684\u4F9D\u8D56\uFF1A</p>\n<pre><code class="language-bash"># Capacitor \u6838\u5FC3\u5E93\nnpm install @capacitor/cli@latest @capacitor/core@latest\nnpm install @capacitor/android @capacitor/ios\n\n# \u5E38\u7528\u63D2\u4EF6 (\u76F8\u673A, \u6587\u4EF6\u7CFB\u7EDF\u7B49)\nnpm install @capacitor/camera @capacitor/filesystem @capacitor/share\nnpm install @capacitor-community/keep-awake\n\n# \u521D\u59CB\u5316\nnpx cap init [MyAppName] [com.example.app]\n</code></pre>\n<h3 id="\u6B65\u9AA4-2-2-\u6DFB\u52A0\u5E73\u53F0"><a class="header-anchor" href="#\u6B65\u9AA4-2-2-\u6DFB\u52A0\u5E73\u53F0">#</a>\u6B65\u9AA4 2.2: \u6DFB\u52A0\u5E73\u53F0</h3><pre><code class="language-bash"># \u6DFB\u52A0 Android\nnpx cap add android\n\n# \u6DFB\u52A0 iOS (\u9700\u8981 Mac \u548C Xcode)\nnpx cap add ios\n</code></pre>\n<h3 id="\u6B65\u9AA4-2-3-\u914D\u7F6E\u79FB\u52A8\u7AEF\u73AF\u5883"><a class="header-anchor" href="#\u6B65\u9AA4-2-3-\u914D\u7F6E\u79FB\u52A8\u7AEF\u73AF\u5883">#</a>\u6B65\u9AA4 2.3: \u914D\u7F6E\u79FB\u52A8\u7AEF\u73AF\u5883</h3><p>\u79FB\u52A8\u7AEF\u5E94\u7528\u901A\u5E38\u901A\u8FC7\u672C\u5730\u6587\u4EF6\u7CFB\u7EDF (<code>file://</code>) \u8FD0\u884C\uFF0C\u56E0\u6B64\u65E0\u6CD5\u50CF Web \u90A3\u6837\u4F7F\u7528\u76F8\u5BF9\u8DEF\u5F84\u8BF7\u6C42 API\u3002\u4F60\u9700\u8981\u521B\u5EFA\u4E00\u4E2A <code>.env.mobile</code> \u6587\u4EF6\uFF1A</p>\n<pre><code class="language-ini"># .env.mobile\nWEB.API_BASE_URL=https://api.your-production-site.com\n</code></pre>\n<h3 id="\u6B65\u9AA4-2-4-\u6784\u5EFA\u4E0E\u540C\u6B65"><a class="header-anchor" href="#\u6B65\u9AA4-2-4-\u6784\u5EFA\u4E0E\u540C\u6B65">#</a>\u6B65\u9AA4 2.4: \u6784\u5EFA\u4E0E\u540C\u6B65</h3><p>\u5728 <code>package.json</code> \u4E2D\u6DFB\u52A0\u6784\u5EFA\u811A\u672C\uFF1A</p>\n<pre><code class="language-json">&quot;scripts&quot;: {\n  &quot;build-mobile&quot;: &quot;node ./dev/dev-watch --env=.env.mobile --dev=0 --mobile=1&quot;\n}\n</code></pre>\n<p>\u7136\u540E\u6267\u884C\u6784\u5EFA\u5E76\u540C\u6B65\u5230\u539F\u751F\u9879\u76EE\uFF1A</p>\n<pre><code class="language-bash">npm run build-mobile\nnpx cap sync\nnpx cap open android  # \u6253\u5F00 Android Studio\n</code></pre>\n<h3 id="\u6B65\u9AA4-2-5-\u539F\u751F\u903B\u8F91-\u53EF\u9009"><a class="header-anchor" href="#\u6B65\u9AA4-2-5-\u539F\u751F\u903B\u8F91-\u53EF\u9009">#</a>\u6B65\u9AA4 2.5: \u539F\u751F\u903B\u8F91 (\u53EF\u9009)</h3><p>\u4F60\u53EF\u4EE5\u4F7F\u7528 <code>#if MOBILE</code> \u7F16\u8BD1\u6307\u4EE4\u6765\u7F16\u5199\u5E73\u53F0\u7279\u5B9A\u4EE3\u7801\uFF0C\u800C\u4E14\u4E0D\u4F1A\u5BFC\u81F4 Web \u5305\u4F53\u79EF\u81A8\u80C0\uFF1A</p>\n<pre><code class="language-javascript">// #if MOBILE\nimport { Camera } from &#39;@capacitor/camera&#39;;\n\nconst takePhoto = async () =&gt; {\n  const image = await Camera.getPhoto({ ... });\n  // \u5904\u7406\u56FE\u7247...\n};\n// #else\nconst takePhoto = async () =&gt; {\n  alert(&quot;\u76F8\u673A\u4EC5\u5728\u79FB\u52A8\u7AEF App \u4E2D\u53EF\u7528\uFF01&quot;);\n};\n// #endif\n</code></pre>\n<h2 id="3-\u8FDB\u519B\u684C\u9762\u7AEF-windows-mac-linux"><a class="header-anchor" href="#3-\u8FDB\u519B\u684C\u9762\u7AEF-windows-mac-linux">#</a>3. \u8FDB\u519B\u684C\u9762\u7AEF (Windows, Mac, Linux)</h2><p>\u5BF9\u4E8E\u684C\u9762\u7AEF\uFF0CLupine.js \u96C6\u6210\u4E86 <strong>Electron</strong>\u3002</p>\n<h3 id="\u7ED3\u6784"><a class="header-anchor" href="#\u7ED3\u6784">#</a>\u7ED3\u6784</h3><p>\u6BCF\u4E2A Lupine \u9879\u76EE\u90FD\u81EA\u5E26\u4E00\u4E2A <code>electron</code> \u76EE\u5F55\uFF0C\u5305\u542B\u4E3B\u8FDB\u7A0B\u903B\u8F91\uFF1A</p>\n<ul>\n<li><code>electron/main.js</code>: Electron \u5E94\u7528\u7684\u5165\u53E3\u70B9\u3002</li>\n<li><code>electron/preload.js</code>: \u6E32\u67D3\u8FDB\u7A0B (Web) \u548C \u4E3B\u8FDB\u7A0B \u4E4B\u95F4\u7684\u5B89\u5168\u901A\u4FE1\u6865\u6881\u3002</li>\n</ul>\n<h3 id="\u6784\u5EFA\u684C\u9762\u5E94\u7528"><a class="header-anchor" href="#\u6784\u5EFA\u684C\u9762\u5E94\u7528">#</a>\u6784\u5EFA\u684C\u9762\u5E94\u7528</h3><p>Lupine \u5141\u8BB8\u4F60\u4F7F\u7528 <code>electron-builder</code> \u5C06\u5E94\u7528\u6253\u5305\u4E3A <code>.exe</code>, <code>.dmg</code>, \u6216 <code>.snap</code> \u5B89\u88C5\u5305\u3002</p>\n<p>\u8FD0\u884C <code>package.json</code> \u4E2D\u9884\u8BBE\u7684\u6784\u5EFA\u547D\u4EE4\uFF1A</p>\n<pre><code class="language-bash"># \u6784\u5EFA Windows \u7248\nnpm run app:build-win\n\n# \u6784\u5EFA Mac \u7248\nnpm run app:build-mac\n</code></pre>\n<p>\u6784\u5EFA\u8FC7\u7A0B\u5C06\u4F1A\uFF1A</p>\n<ol>\n<li>\u5C06 Lupine.js Web \u5E94\u7528\u7F16\u8BD1\u4E3A\u9759\u6001\u6587\u4EF6\u3002</li>\n<li>\u5C06\u8FD9\u4E9B\u6587\u4EF6\u4E0E Electron \u8FD0\u884C\u65F6\u6346\u7ED1\u3002</li>\n<li>\u8F93\u51FA\u72EC\u7ACB\u7684\u5B89\u88C5\u7A0B\u5E8F\u3002</li>\n</ol>\n<h2 id="\u603B\u7ED3"><a class="header-anchor" href="#\u603B\u7ED3">#</a>\u603B\u7ED3</h2><p>\u4F7F\u7528 <strong>Lupine.js</strong>\uFF0C\u4F60\u4E0D\u9700\u8981\u4E3A Web\u3001\u79FB\u52A8\u7AEF\u548C\u684C\u9762\u7AEF\u7EC4\u5EFA\u4E09\u4E2A\u72EC\u7ACB\u7684\u56E2\u961F\u3002\u4F60\u53EF\u4EE5\u7EF4\u62A4<strong>\u4E00\u5957</strong>\u4EE3\u7801\u5E93\uFF0C\u4F7F\u7528<strong>\u4E00\u5957</strong>\u7EC4\u4EF6\uFF0C\u7136\u540E\u53D1\u5E03\u5230\u6240\u6709\u5E73\u53F0\u3002</p>\n<p>\u65E0\u8BBA\u4F60\u662F\u6784\u5EFA SaaS \u5E73\u53F0\u3001\u6D88\u8D39\u8005 App \u8FD8\u662F\u5185\u90E8\u5DE5\u5177\uFF0CLupine.js \u90FD\u80FD\u8BA9\u4F60\u540C\u65F6\u62E5\u6709\u539F\u751F\u5E94\u7528\u7684\u89E6\u8FBE\u7387\u548C Web \u5F00\u53D1\u7684\u9AD8\u6548\u7387\u3002</p>\n';

  // apps/doc/web/src/markdown-built/zh/articles/css-in-js-lupine.js.html
  var css_in_js_lupine_js_default2 = '<h1 id="\u96F6\u4F9D\u8D56-lupine-js-\u5982\u4F55\u5B9E\u73B0\u539F\u751F-css-in-js"><a class="header-anchor" href="#\u96F6\u4F9D\u8D56-lupine-js-\u5982\u4F55\u5B9E\u73B0\u539F\u751F-css-in-js">#</a>\u96F6\u4F9D\u8D56\uFF0CLupine.js \u5982\u4F55\u5B9E\u73B0\u539F\u751F CSS-in-JS\uFF1F</h1><p>\u5728\u73B0\u4EE3\u524D\u7AEF\u5F00\u53D1\u4E2D\uFF0C\u6211\u4EEC\u5E38\u5E38\u9762\u4E34\u4E00\u4E2A\u4E24\u96BE\u7684\u9009\u62E9\uFF1A\u662F\u5FCD\u53D7 CSS \u6587\u4EF6\u5206\u79BB\u5E26\u6765\u7684\u7EF4\u62A4\u75DB\u82E6\uFF0C\u8FD8\u662F\u5F15\u5165\u5E9E\u5927\u7684 CSS-in-JS \u5E93\uFF08\u5982 Styled-components \u6216 Emotion\uFF09\u5BFC\u81F4\u5305\u4F53\u79EF\u5267\u589E\uFF1F</p>\n<p><strong>Lupine.js \u9009\u62E9\u4E86\u4E00\u6761\u4E0D\u540C\u7684\u8DEF\u3002</strong></p>\n<p>\u5B83\u5185\u7F6E\u4E86\u4E00\u4E2A\u8D85\u8F7B\u91CF\u7EA7\u7684 CSS-in-JS \u5F15\u64CE\uFF0C<strong>\u65E0\u9700\u4EFB\u4F55\u989D\u5916\u4F9D\u8D56</strong>\uFF0C\u5373\u53EF\u8BA9\u4F60\u5728\u7EC4\u4EF6\u5185\u90E8\u8212\u9002\u5730\u7F16\u5199\u6837\u5F0F\u3002\u5B83\u4E0D\u4EC5\u652F\u6301\u5D4C\u5957\u3001\u5A92\u4F53\u67E5\u8BE2\u3001\u5173\u952E\u5E27\u52A8\u753B\uFF0C\u8FD8\u62E5\u6709\u6781\u9AD8\u7684\u8FD0\u884C\u6548\u7387\u3002</p>\n<p>\u8BA9\u6211\u4EEC\u6765\u770B\u770B\u5B83\u662F\u5982\u4F55\u5DE5\u4F5C\u7684\uFF0C\u4EE5\u53CA\u5982\u4F55\u5728\u4F60\u7684\u9879\u76EE\u4E2D\u4F18\u96C5\u5730\u4F7F\u7528\u5B83\u3002</p>\n<p><img src="/lupine.js/assets/css-in-js.png" alt="Lupine.js CSS-in-JS"></p>\n<h2 id="1-\u544A\u522B-classname-\u7684\u70E6\u607C"><a class="header-anchor" href="#1-\u544A\u522B-classname-\u7684\u70E6\u607C">#</a>1. \u544A\u522B className \u7684\u70E6\u607C</h2><p>\u4F20\u7EDF\u7684 CSS \u5F00\u53D1\u5F80\u5F80\u9700\u8981\u4F60\u5728 <code>.css</code> \u6587\u4EF6\u548C <code>.tsx</code> \u6587\u4EF6\u4E4B\u95F4\u53CD\u590D\u6A2A\u8DF3\uFF0C\u8FD8\u8981\u6316\u7A7A\u5FC3\u601D\u7ED9 class \u8D77\u540D\u3002\u800C\u5728 Lupine.js \u4E2D\uFF0C\u4E00\u5207\u90FD\u5728\u7EC4\u4EF6\u5185\u90E8\u89E3\u51B3\u3002</p>\n<p>\u4F60\u53EA\u9700\u8981\u5B9A\u4E49\u4E00\u4E2A\u7B80\u5355\u7684\u5BF9\u8C61\uFF0C\u4F20\u9012\u7ED9 <code>css</code> \u5C5E\u6027\uFF1A</p>\n<pre><code class="language-tsx">const MyButton = () =&gt; {\n  const btnStyle = {\n    backgroundColor: &#39;#0070f3&#39;,\n    color: &#39;white&#39;,\n    padding: &#39;10px 20px&#39;,\n    borderRadius: &#39;5px&#39;,\n    border: &#39;none&#39;,\n    cursor: &#39;pointer&#39;,\n\n    // \u50CF SCSS \u4E00\u6837\u5D4C\u5957\uFF01\n    &#39;&amp;:hover&#39;: {\n      backgroundColor: &#39;#0051a2&#39;,\n    },\n\n    // \u8F7B\u677E\u641E\u5B9A\u4F2A\u5143\u7D20\n    &#39;&amp;::before&#39;: {\n      content: &#39;&quot;\u{1F680} &quot;&#39;,\n    },\n  };\n\n  return &lt;button css={btnStyle}&gt;\u70B9\u51FB\u53D1\u5C04&lt;/button&gt;;\n};\n</code></pre>\n<p>Lupine \u4F1A\u81EA\u52A8\u4E3A\u4F60\u751F\u6210\u4E00\u4E2A\u552F\u4E00\u7684 Class ID\uFF08\u7C7B\u4F3C\u4E8E <code>.L12345</code>\uFF09\uFF0C\u5E76\u5C06\u6837\u5F0F\u6CE8\u5165\u5230\u9875\u9762\u4E2D\uFF0C\u4F60\u5B8C\u5168\u4E0D\u7528\u62C5\u5FC3\u5168\u5C40\u6837\u5F0F\u51B2\u7A81\u3002</p>\n<h2 id="2-\u50CF-scss-\u4E00\u6837\u5F3A\u5927\u7684\u5D4C\u5957\u529F\u80FD"><a class="header-anchor" href="#2-\u50CF-scss-\u4E00\u6837\u5F3A\u5927\u7684\u5D4C\u5957\u529F\u80FD">#</a>2. \u50CF SCSS \u4E00\u6837\u5F3A\u5927\u7684\u5D4C\u5957\u529F\u80FD</h2><p>Lupine \u7684\u6837\u5F0F\u5F15\u64CE\u6DF1\u53D7 SCSS/Less \u7684\u542F\u53D1\uFF0C\u652F\u6301\u5F3A\u5927\u7684 <code>&amp;</code> \u7B26\u53F7\u5F15\u7528\u7236\u7EA7\u3002</p>\n<h3 id="\u5D4C\u5957\u5B50\u5143\u7D20"><a class="header-anchor" href="#\u5D4C\u5957\u5B50\u5143\u7D20">#</a>\u5D4C\u5957\u5B50\u5143\u7D20</h3><p>\u4E0D\u8981\u518D\u5199\u53C8\u81ED\u53C8\u957F\u7684 <code>div &gt; span &gt; a</code> \u4E86\uFF1A</p>\n<pre><code class="language-tsx">const cardStyle = {\n  padding: &#39;20px&#39;,\n  boxShadow: &#39;0 4px 14px rgba(0,0,0,0.1)&#39;,\n\n  // \u53EA\u6709\u5F53 h3 \u5728\u8FD9\u4E2A\u7EC4\u4EF6\u5185\u65F6\u624D\u751F\u6548\n  h3: {\n    marginTop: 0,\n    color: &#39;#333&#39;,\n  },\n\n  // \u9009\u4E2D\u7279\u5B9A\u7684 class\n  &#39;.description&#39;: {\n    color: &#39;#666&#39;,\n    fontSize: &#39;14px&#39;,\n  },\n};\n\n&lt;div css={cardStyle}&gt;\n  &lt;h3&gt;\u6807\u9898&lt;/h3&gt;\n  &lt;p class=&#39;description&#39;&gt;\u8FD9\u662F\u63CF\u8FF0\u5185\u5BB9...&lt;/p&gt;\n&lt;/div&gt;;\n</code></pre>\n<h3 id="\u7EC4\u5408\u9009\u62E9\u5668"><a class="header-anchor" href="#\u7EC4\u5408\u9009\u62E9\u5668">#</a>\u7EC4\u5408\u9009\u62E9\u5668</h3><p>\u8FD9\u5728\u5904\u7406\u590D\u6742\u7684\u7EC4\u4EF6\u72B6\u6001\u65F6\u975E\u5E38\u6709\u7528\uFF1A</p>\n<pre><code class="language-tsx">const itemStyle = {\n  color: &#39;#888&#39;,\n\n  // \u5F53\u540C\u65F6\u62E5\u6709 .active \u7C7B\u65F6\n  &#39;&amp;.active&#39;: {\n    color: &#39;#0070f3&#39;,\n    fontWeight: &#39;bold&#39;,\n  },\n};\n</code></pre>\n<h2 id="3-\u54CD\u5E94\u5F0F\u8BBE\u8BA1-\u5A92\u4F53\u67E5\u8BE2\u4ECE\u672A\u5982\u6B64\u7B80\u5355"><a class="header-anchor" href="#3-\u54CD\u5E94\u5F0F\u8BBE\u8BA1-\u5A92\u4F53\u67E5\u8BE2\u4ECE\u672A\u5982\u6B64\u7B80\u5355">#</a>3. \u54CD\u5E94\u5F0F\u8BBE\u8BA1\uFF1A\u5A92\u4F53\u67E5\u8BE2\u4ECE\u672A\u5982\u6B64\u7B80\u5355</h2><p>\u5728 Lupine \u4E2D\uFF0C\u5A92\u4F53\u67E5\u8BE2\u4E0D\u518D\u662F\u6E38\u79BB\u4E8E\u7EC4\u4EF6\u4E4B\u5916\u7684\u4EE3\u7801\u5757\u3002\u4F60\u53EF\u4EE5\u5C06\u5B83\u4EEC\u76F4\u63A5\u628A\u5B83\u4EEC\u5199\u5728\u9700\u8981\u751F\u6548\u7684\u5C5E\u6027\u65C1\u8FB9\u3002</p>\n<pre><code class="language-tsx">const responsiveBox = {\n  width: &#39;100%&#39;,\n  padding: &#39;20px&#39;,\n  backgroundColor: &#39;lightblue&#39;,\n\n  // \u9488\u5BF9\u684C\u9762\u7AEF\u7684\u6837\u5F0F\n  &#39;@media (min-width: 768px)&#39;: {\n    width: &#39;50%&#39;, // \u5728\u5927\u5C4F\u4E0A\u53D8\u4E3A\u4E00\u534A\u5BBD\u5EA6\n    backgroundColor: &#39;lightgreen&#39;,\n\n    // \u751A\u81F3\u53EF\u4EE5\u5728\u5A92\u4F53\u67E5\u8BE2\u91CC\u7EE7\u7EED\u5D4C\u5957\uFF01\n    &#39;&amp;:hover&#39;: {\n      backgroundColor: &#39;green&#39;,\n    },\n  },\n};\n</code></pre>\n<p>\u8FD9\u79CD\u5199\u6CD5\u8BA9\u201C\u7EC4\u4EF6\u5728\u4E0D\u540C\u5C4F\u5E55\u4E0B\u7684\u8868\u73B0\u201D\u8FD9\u4E00\u903B\u8F91\u9AD8\u5EA6\u5185\u805A\uFF0C\u7EF4\u62A4\u8D77\u6765\u975E\u5E38\u8212\u670D\u3002</p>\n<h2 id="4-\u52A8\u753B\u5927\u5E08-\u5185\u7F6E-keyframes-\u652F\u6301"><a class="header-anchor" href="#4-\u52A8\u753B\u5927\u5E08-\u5185\u7F6E-keyframes-\u652F\u6301">#</a>4. \u52A8\u753B\u5927\u5E08\uFF1A\u5185\u7F6E Keyframes \u652F\u6301</h2><p>\u4EE5\u524D\u4E3A\u4E86\u5199\u4E2A\u7B80\u5355\u7684\u52A8\u753B\uFF0C\u4F60\u53EF\u80FD\u5F97\u53BB\u5168\u5C40 CSS \u91CC\u5B9A\u4E49 <code>@keyframes</code>\u3002Lupine \u8BA9\u4F60\u76F4\u63A5\u5728\u7EC4\u4EF6\u91CC\u5B9A\u4E49\u5173\u952E\u5E27\uFF1A</p>\n<pre><code class="language-tsx">const spinnerStyle = {\n  width: &#39;40px&#39;,\n  height: &#39;40px&#39;,\n  border: &#39;4px solid #f3f3f3&#39;,\n  borderTop: &#39;4px solid #3498db&#39;,\n  borderRadius: &#39;50%&#39;,\n\n  // \u76F4\u63A5\u5B9A\u4E49 Keyframes\n  &#39;@keyframes spin&#39;: {\n    &#39;0%&#39;: { transform: &#39;rotate(0deg)&#39; },\n    &#39;100%&#39;: { transform: &#39;rotate(360deg)&#39; },\n  },\n\n  // \u76F4\u63A5\u5F15\u7528\u4E0A\u9762\u5B9A\u4E49\u7684\u540D\u5B57\n  animation: &#39;spin 1s linear infinite&#39;,\n};\n</code></pre>\n<p>\u5F15\u64CE\u4F1A\u81EA\u52A8\u5904\u7406\u4F5C\u7528\u57DF\uFF0C\u4F60\u7684 <code>spin</code> \u52A8\u753B\u7EDD\u4E0D\u4F1A\u6C61\u67D3\u5176\u4ED6\u7EC4\u4EF6\u7684\u540C\u540D\u52A8\u753B\u3002</p>\n<h2 id="5-\u52A8\u6001\u6837\u5F0F\u66F4\u65B0"><a class="header-anchor" href="#5-\u52A8\u6001\u6837\u5F0F\u66F4\u65B0">#</a>5. \u52A8\u6001\u6837\u5F0F\u66F4\u65B0</h2><p>\u65E2\u7136\u662F CSS-in-JS\uFF0C\u4E0D\u4EC5\u8981\u9759\u6001\u7F16\u8BD1\uFF0C\u8FD8\u8981\u80FD\u52A8\u6001\u53D8\u5316\u3002Lupine \u63D0\u4F9B\u4E86\u4E00\u4E2A\u5E95\u5C42\u7684 <code>updateStyles</code> API\uFF0C\u5141\u8BB8\u4F60\u6839\u636E\u903B\u8F91\u52A8\u6001\u4FEE\u6539\u6837\u5F0F\u3002</p>\n<blockquote>\n<p><strong>\u6CE8\u610F</strong>\uFF1A\u5BF9\u4E8E\u7B80\u5355\u7684\u52A8\u6001\u53D8\u5316\uFF08\u5982\u5F00\u5173\u3001\u989C\u8272\u5207\u6362\uFF09\uFF0C\u901A\u5E38\u5EFA\u8BAE\u5207\u6362 <code>class</code> \u6216\u4F7F\u7528 <code>style={{ ... }}</code> \u884C\u5185\u6837\u5F0F\u3002\u4F46\u5982\u679C\u4F60\u9700\u8981\u52A8\u6001\u4FEE\u6539<strong>\u4F2A\u7C7B</strong>\uFF08\u5982 hover \u989C\u8272\uFF09\u6216<strong>\u5A92\u4F53\u67E5\u8BE2</strong>\uFF0C<code>updateStyles</code> \u5C31\u6D3E\u4E0A\u7528\u573A\u4E86\u3002</p>\n</blockquote>\n<pre><code class="language-tsx">import { updateStyles, RefProps } from &#39;lupine.web&#39;;\n\nconst DynamicComponent = () =&gt; {\n  // \u5B9A\u4E49\u521D\u59CB\u6837\u5F0F\u5BF9\u8C61\n  const css: any = {\n    color: &#39;blue&#39;,\n    &#39;&amp;:hover&#39;: { color: &#39;darkblue&#39; }, // \uFF01\uFF01\uFF01\u52A8\u6001\u4FEE\u6539 hover \u989C\u8272\uFF0C\u884C\u5185\u6837\u5F0F\u505A\u4E0D\u5230\uFF01\uFF01\uFF01\n  };\n\n  const ref: RefProps = {}; // \u7528\u6765\u83B7\u53D6\u7EC4\u4EF6\u751F\u6210\u7684\u552F\u4E00 ID\n\n  const toggleTheme = () =&gt; {\n    // \u4FEE\u6539\u6837\u5F0F\u5BF9\u8C61\n    css.color = &#39;red&#39;;\n    css[&#39;&amp;:hover&#39;].color = &#39;darkred&#39;;\n\n    // \u5E94\u7528\u66F4\u65B0\n    // ref.id \u4F1A\u62FF\u5230\u7C7B\u4F3C L123 \u7684 ID\uFF0CupdateStyles \u4F1A\u627E\u5230\u5BF9\u5E94\u7684 &lt;style&gt; \u6807\u7B7E\u5E76\u66F4\u65B0\u5B83\n    updateStyles(`${ref.id}`, css);\n  };\n\n  return (\n    &lt;div ref={ref} css={css} onClick={toggleTheme}&gt;\n      \u70B9\u6211\u6539\u53D8\u4E3B\u9898\u8272\uFF08\u5305\u62EC Hover \u989C\u8272\uFF01\uFF09\n    &lt;/div&gt;\n  );\n};\n</code></pre>\n<h2 id="6-\u5168\u5C40\u6837\u5F0F-bindglobalstyle"><a class="header-anchor" href="#6-\u5168\u5C40\u6837\u5F0F-bindglobalstyle">#</a>6. \u5168\u5C40\u6837\u5F0F\uFF1AbindGlobalStyle</h2><p>\u867D\u7136\u7EC4\u4EF6\u5316\u5F88\u597D\uFF0C\u4F46\u6709\u65F6\u6211\u4EEC\u786E\u5B9E\u9700\u8981\u5168\u5C40\u6837\u5F0F\uFF08\u6BD4\u5982 Reset CSS\u3001\u5168\u5C40\u5B57\u4F53\u5B9A\u4E49\u7B49\uFF09\u3002<code>bindGlobalStyle</code> \u53EF\u4EE5\u786E\u4FDD\u4F60\u7684\u5168\u5C40\u6837\u5F0F\u53EA\u88AB\u6CE8\u5165\u4E00\u6B21\uFF0C\u54EA\u6015\u7EC4\u4EF6\u88AB\u6E32\u67D3\u4E86\u591A\u6B21\u3002</p>\n<pre><code class="language-tsx">import { bindGlobalStyle } from &#39;lupine.web&#39;;\n\n// \u6BD4\u5982\u5B9A\u4E49\u4E00\u4E2A\u5168\u5C40\u7684\u5DE5\u5177\u7C7B\nconst globalUtils = {\n  &#39;.text-center&#39;: { textAlign: &#39;center&#39; },\n  &#39;.flex-center&#39;: { display: &#39;flex&#39;, justifyContent: &#39;center&#39; },\n};\n\n// \u6CE8\u5165\u5230 &lt;head&gt; \u4E2D\uFF0CID \u4E3A &#39;global-utils&#39;\nbindGlobalStyle(&#39;global-utils&#39;, globalUtils);\n</code></pre>\n<h2 id="7-\u4F20\u7EDF\u6D3E-\u5BFC\u5165-css-\u6587\u4EF6"><a class="header-anchor" href="#7-\u4F20\u7EDF\u6D3E-\u5BFC\u5165-css-\u6587\u4EF6">#</a>7. \u4F20\u7EDF\u6D3E\uFF1A\u5BFC\u5165 .css \u6587\u4EF6</h2><p>\u5F53\u7136\uFF0CLupine.js \u5E76\u6CA1\u6709\u5FD8\u8BB0\u8FD9\u4E00\u6700\u57FA\u7840\u7684\u9700\u6C42\u3002\u5982\u679C\u4F60\u6709\u4E00\u4E2A\u5E9E\u5927\u7684\u65E7\u9879\u76EE\u9700\u8981\u8FC1\u79FB\uFF0C\u6216\u8005\u5C31\u662F\u559C\u6B22\u5199 <code>.css</code> \u6587\u4EF6\uFF0C\u5B8C\u5168\u6CA1\u6709\u95EE\u9898\u3002</p>\n<p>\u4F60\u53EF\u4EE5\u5728\u4EFB\u4F55 <code>.tsx</code> \u6587\u4EF6\u4E2D\u76F4\u63A5\u5BFC\u5165 CSS \u6587\u4EF6\uFF1A</p>\n<pre><code class="language-tsx">// \u5728\u5165\u53E3\u6587\u4EF6 index.tsx \u4E2D\nimport &#39;./styles/global.css&#39;;\nimport &#39;./styles/app.css&#39;;\n\n// \u987A\u5E8F\u5F88\u91CD\u8981\uFF1Aglobal.css \u7684\u6837\u5F0F\u4F1A\u5148\u88AB\u52A0\u8F7D\n</code></pre>\n<p>\u6784\u5EFA\u7CFB\u7EDF\u4F1A\u81EA\u52A8\u5C06\u6240\u6709\u5BFC\u5165\u7684 CSS \u63D0\u53D6\u5E76\u538B\u7F29\u6210\u4E00\u4E2A\u6587\u4EF6\u3002\u5BF9\u4E8E\u751F\u4EA7\u73AF\u5883\u6784\u5EFA\uFF0CLupine \u4F1A\u81EA\u52A8\u5728 <code>index.html</code> \u4E2D\u6CE8\u5165\u7C7B\u4F3C <code>&lt;link rel=&quot;stylesheet&quot; href=&quot;/index.css?t=...&quot; /&gt;</code> \u7684\u6807\u7B7E\uFF0C\u786E\u4FDD\u4F60\u7684\u6837\u5F0F\u88AB\u6B63\u786E\u52A0\u8F7D\u548C\u7F13\u5B58\u3002</p>\n<h2 id="\u603B\u7ED3"><a class="header-anchor" href="#\u603B\u7ED3">#</a>\u603B\u7ED3</h2><p>Lupine.js \u7684 CSS-in-JS \u5F15\u64CE\u5E76\u4E0D\u662F\u4E3A\u4E86\u53D6\u4EE3\u6240\u6709 CSS \u5199\u6CD5\uFF0C\u800C\u662F\u63D0\u4F9B\u4E86\u4E00\u79CD<strong>\u96F6\u8D1F\u62C5\u3001\u9AD8\u6027\u80FD\u4E14\u5F00\u53D1\u4F53\u9A8C\u6781\u4F73</strong>\u7684\u9009\u62E9\u3002</p>\n<ul>\n<li><strong>\u96F6\u4F9D\u8D56</strong>\uFF1A\u4E0D\u9700\u8981\u5B89\u88C5\u4EFB\u4F55\u989D\u5916\u7684\u5305\u3002</li>\n<li><strong>\u9AD8\u6027\u80FD</strong>\uFF1A\u6837\u5F0F\u5728 SSR \u9636\u6BB5\u5373\u53EF\u751F\u6210\uFF0C\u65E0\u8FD0\u884C\u65F6\u95EA\u70C1\u3002</li>\n<li><strong>\u5168\u529F\u80FD</strong>\uFF1A\u5D4C\u5957\u3001\u5A92\u4F53\u67E5\u8BE2\u3001\u52A8\u753B\u4E00\u5E94\u4FF1\u5168\u3002</li>\n<li><strong>\u5F00\u53D1\u723D</strong>\uFF1A\u5F3A\u7C7B\u578B\u7684 TypeScript \u652F\u6301\uFF0C\u5199 CSS \u4E5F\u6709\u4EE3\u7801\u63D0\u793A\u3002</li>\n</ul>\n<p>\u4E0B\u6B21\u6784\u5EFA UI \u65F6\uFF0C\u4E0D\u59A8\u8BD5\u8BD5\u76F4\u63A5\u5728\u7EC4\u4EF6\u91CC <code>const css = { ... }</code>\uFF0C\u4F53\u9A8C\u4E00\u4E0B\u8FD9\u79CD\u201C\u539F\u751F\u201D\u7684\u6D41\u7545\u611F\u5427\uFF01</p>\n';

  // apps/doc/web/src/markdown-built/zh/articles/cv-generator.html
  var cv_generator_default2 = '<h1 id="\u5341\u5206\u949F-\u7528-markdown-\u6781\u901F\u6784\u5EFA\u9AD8\u989C\u503C\u7684\u4E2A\u4EBA\u7B80\u5386\u7F51\u7AD9"><a class="header-anchor" href="#\u5341\u5206\u949F-\u7528-markdown-\u6781\u901F\u6784\u5EFA\u9AD8\u989C\u503C\u7684\u4E2A\u4EBA\u7B80\u5386\u7F51\u7AD9">#</a>\u5341\u5206\u949F\uFF01\u7528 Markdown \u6781\u901F\u6784\u5EFA\u9AD8\u989C\u503C\u7684\u4E2A\u4EBA\u7B80\u5386\u7F51\u7AD9</h1><p>\u60F3\u627E\u4E00\u4EFD\u597D\u5DE5\u4F5C\uFF0C\u5199\u4E00\u4EFD\u597D\u7684\u5DE5\u4F5C\u7B80\u5386\uFF08CV\uFF09\u81F3\u5173\u91CD\u8981\u3002\u5982\u679C\u80FD\u628A\u8FD9\u4EFD\u7B80\u5386\u505A\u6210\u4E00\u4E2A\u4E13\u4E1A\u7684\u4E2A\u4EBA\u7F51\u7AD9\uFF0C\u90A3\u66F4\u662F\u9526\u4E0A\u6DFB\u82B1\uFF0C\u80FD\u8BA9\u62DB\u8058\u8005\u773C\u524D\u4E00\u4EAE\u3002</p>\n<p>\u8FD9\u7BC7\u6587\u7AE0\u5C06\u4ECB\u7ECD\u5982\u4F55\u5229\u7528 <strong>Lupine.js</strong> \u6846\u67B6\u63D0\u4F9B\u7684 <strong>CV Starter</strong> \u6A21\u677F\uFF0C\u53EA\u9700\u8981\u5199\u7B80\u5355\u7684 Markdown \u6587\u4EF6\uFF0C\u5C31\u80FD\u751F\u6210\u4E00\u4E2A\u6F02\u4EAE\u7684\u3001\u54CD\u5E94\u5F0F\u7684\u7B80\u5386\u7F51\u7AD9\u3002\u5B83\u81EA\u5E26\u9ED1\u767D\u4E3B\u9898\u5207\u6362\u3001\u591A\u8BED\u8A00\u652F\u6301\uFF0C\u5E76\u4E14\u53EF\u4EE5<strong>\u514D\u8D39\u6258\u7BA1\u5728 GitHub Pages \u4E0A</strong>\u3002</p>\n<p><img src="/lupine.js/assets/cv-generator-zh.png" alt="Lupine.js CV Starter"></p>\n<p>\u4E3A\u4E86\u8BA9\u60A8\u66F4\u76F4\u89C2\u5730\u4E86\u89E3\u6548\u679C\uFF0C\u6211\u4EEC\u4E3A\u60A8\u51C6\u5907\u4E86\u4E00\u4E2A\u5B8C\u6574\u7684\u6F14\u793A\u9879\u76EE\u3002\u60A8\u53EF\u4EE5\u76F4\u63A5\u8BBF\u95EE\u6E90\u7801\u4ED3\u5E93\uFF0C\u751A\u81F3\u76F4\u63A5 Fork \u5B83\u4F5C\u4E3A\u60A8\u7684\u8D77\u70B9\uFF1A</p>\n<ul>\n<li><strong>\u6E90\u7801\u4ED3\u5E93</strong>: <a href="https://github.com/uuware/lupine-template-cv-starter">https://github.com/uuware/lupine-template-cv-starter</a></li>\n</ul>\n<p>\u60A8\u4E5F\u53EF\u4EE5\u70B9\u51FB\u4E0B\u65B9\u94FE\u63A5\uFF0C\u5728\u7EBF\u67E5\u770B\u8BE5\u9879\u76EE\u7684\u5B9E\u9645\u8FD0\u884C\u6548\u679C\uFF1A</p>\n<ul>\n<li><strong>\u5728\u7EBF\u6F14\u793A</strong>: <a href="https://uuware.github.io/lupine-template-cv-starter/">https://uuware.github.io/lupine-template-cv-starter/</a></li>\n</ul>\n<h2 id="\u4E3A\u4EC0\u4E48\u9009\u62E9-lupine-cv-starter"><a class="header-anchor" href="#\u4E3A\u4EC0\u4E48\u9009\u62E9-lupine-cv-starter">#</a>\u4E3A\u4EC0\u4E48\u9009\u62E9 Lupine CV Starter\uFF1F</h2><ul>\n<li><strong>\u6781\u7B80 Markdown</strong>: \u4E13\u6CE8\u4E8E\u5185\u5BB9\uFF0C\u50CF\u5199\u6587\u6863\u4E00\u6837\u5199\u7B80\u5386\u3002</li>\n<li><strong>\u9AD8\u989C\u503C\u8BBE\u8BA1</strong>: \u9ED8\u8BA4\u4E3B\u9898\u6E05\u65B0\u4E13\u4E1A\uFF0C\u652F\u6301<strong>\u6D45\u8272\u4E3B\u9898</strong>\u548C<strong>\u6DF1\u8272\u4E3B\u9898</strong>\u3002</li>\n<li><strong>\u591A\u8BED\u8A00\u652F\u6301</strong>: \u8F7B\u677E\u6784\u5EFA\u4E2D\u82F1\u6587\u53CC\u8BED\u7B80\u5386\uFF0C\u5C55\u73B0\u56FD\u9645\u5316\u89C6\u91CE\u3002</li>\n<li><strong>\u79FB\u52A8\u7AEF\u9002\u914D</strong>: \u5B8C\u7F8E\u9002\u914D\u624B\u673A\u684C\u9762\uFF0C\u968F\u65F6\u968F\u5730\u4F18\u96C5\u5C55\u793A\u3002</li>\n<li><strong>\u514D\u8D39\u6258\u7BA1</strong>: \u7EAF\u9759\u6001\u9875\u9762\uFF0C\u53EF\u76F4\u63A5\u90E8\u7F72\u5230 GitHub Pages\uFF0C\u96F6\u6210\u672C\u4E0A\u7EBF\u3002</li>\n</ul>\n<h2 id="\u5FEB\u901F\u5F00\u59CB"><a class="header-anchor" href="#\u5FEB\u901F\u5F00\u59CB">#</a>\u{1F680} \u5FEB\u901F\u5F00\u59CB</h2><h3 id="1-\u521B\u5EFA\u9879\u76EE"><a class="header-anchor" href="#1-\u521B\u5EFA\u9879\u76EE">#</a>1. \u521B\u5EFA\u9879\u76EE</h3><p>\u53EA\u9700\u4E00\u884C\u547D\u4EE4\uFF0C\u5373\u53EF\u521D\u59CB\u5316\u4F60\u7684\u7B80\u5386\u9879\u76EE\uFF1A</p>\n<pre><code class="language-bash">npx create-lupine@latest my-cv\n</code></pre>\n<p>\u5728\u63D0\u793A\u4E2D\u9009\u62E9 <strong><code>cv-starter</code></strong> \u6A21\u677F\u3002</p>\n<h3 id="2-\u542F\u52A8\u9884\u89C8"><a class="header-anchor" href="#2-\u542F\u52A8\u9884\u89C8">#</a>2. \u542F\u52A8\u9884\u89C8</h3><p>\u8FDB\u5165\u9879\u76EE\u76EE\u5F55\u5E76\u542F\u52A8\u672C\u5730\u5F00\u53D1\u670D\u52A1\u5668\uFF1A</p>\n<pre><code class="language-bash">cd my-cv\nnpm install\nnpm run dev\n</code></pre>\n<p>\u73B0\u5728\uFF0C\u6253\u5F00\u6D4F\u89C8\u5668\uFF0C\u4F60\u5C31\u80FD\u770B\u5230\u4E00\u4E2A\u5305\u542B<strong>\u4E2A\u4EBA\u7B80\u4ECB\u3001\u5DE5\u4F5C\u7ECF\u5386\u3001\u9879\u76EE\u7ECF\u9A8C\u3001\u4E13\u4E1A\u6280\u80FD\u3001\u6559\u80B2\u80CC\u666F</strong>\u7B49\u5B8C\u6574\u677F\u5757\u7684\u7B80\u5386\u96CF\u5F62\u4E86\uFF01</p>\n<h2 id="\u5B9A\u5236\u4F60\u7684\u7B80\u5386"><a class="header-anchor" href="#\u5B9A\u5236\u4F60\u7684\u7B80\u5386">#</a>\u{1F4DD} \u5B9A\u5236\u4F60\u7684\u7B80\u5386</h2><p>\u6A21\u677F\u5DF2\u7ECF\u4E3A\u4F60\u9884\u8BBE\u4E86\u6807\u51C6\u7684\u7B80\u5386\u7ED3\u6784\uFF0C\u4F60\u53EA\u9700\u8981\u6839\u636E\u81EA\u5DF1\u7684\u60C5\u51B5\u8FDB\u884C\u589E\u5220\u6539\u67E5\u3002</p>\n<h3 id="\u4FEE\u6539\u5185\u5BB9"><a class="header-anchor" href="#\u4FEE\u6539\u5185\u5BB9">#</a>\u4FEE\u6539\u5185\u5BB9</h3><p>\u6240\u6709\u7684\u5185\u5BB9\u90FD\u4F4D\u4E8E <code>web/markdown</code> \u76EE\u5F55\u4E0B\u3002</p>\n<ul>\n<li><code>zh/</code>: \u4E2D\u6587\u7248\u7B80\u5386\u5185\u5BB9</li>\n<li><code>en/</code>: \u82F1\u6587\u7248\u7B80\u5386\u5185\u5BB9</li>\n</ul>\n<p>\u4F60\u53EF\u4EE5\u76F4\u63A5\u4FEE\u6539 Markdown \u6587\u4EF6\u3002\u66F4\u68D2\u7684\u662F\uFF0C\u4F60\u5B8C\u5168\u53EF\u4EE5\u53EA\u7CBE\u5FC3\u64B0\u5199\u4E00\u4E2A\u8BED\u8A00\u7248\u672C\uFF08\u6BD4\u5982\u4E2D\u6587\uFF09\uFF0C\u7136\u540E<strong>\u8BA9 AI \u5E2E\u4F60\u7FFB\u8BD1\u6210\u53E6\u4E00\u4E2A\u8BED\u8A00</strong>\u3002\u73B0\u5728\u7684 AI \u975E\u5E38\u64C5\u957F\u5904\u7406 Markdown \u683C\u5F0F\uFF0C\u7FFB\u8BD1\u8D28\u91CF\u901A\u5E38\u5F88\u9AD8\uFF0C\u8FD9\u80FD\u4E3A\u4F60\u8282\u7701\u5927\u91CF\u65F6\u95F4\u3002</p>\n<h3 id="\u7BA1\u7406\u76EE\u5F55\u4E0E\u4FA7\u8FB9\u680F"><a class="header-anchor" href="#\u7BA1\u7406\u76EE\u5F55\u4E0E\u4FA7\u8FB9\u680F">#</a>\u7BA1\u7406\u76EE\u5F55\u4E0E\u4FA7\u8FB9\u680F</h3><p>\u5F53\u4F60\u6DFB\u52A0\u6216\u5220\u9664\u4E86\u67D0\u4E2A\u9875\u9762\uFF08\u4F8B\u5982\u6DFB\u52A0\u4E86\u201C\u5F00\u6E90\u8D21\u732E\u201D\u7AE0\u8282\uFF09\uFF0C\u4F60\u9700\u8981\u544A\u8BC9\u7F51\u7AD9\u5982\u4F55\u663E\u793A\u4FA7\u8FB9\u680F\u5BFC\u822A\u3002</p>\n<p>\u6253\u5F00\u8BED\u8A00\u6839\u76EE\u5F55\u4E0B\u7684 <code>index.md</code> \u6587\u4EF6\uFF08\u4F8B\u5982 <code>web/markdown/zh/index.md</code>\uFF09\uFF0C\u627E\u5230 <code>sidebar</code> \u914D\u7F6E\u9879\u8FDB\u884C\u4FEE\u6539\uFF1A</p>\n<pre><code class="language-yaml">sidebar:\n  - text: \u8BE6\u7EC6\u4ECB\u7ECD\n    items:\n      - /zh/01-experience/index\n      - /zh/02-projects/index\n      - /zh/03-skills/index\n      - /zh/04-education/index\n      # - /zh/05-open-source/index  &lt;-- \u65B0\u589E\u7684\u9875\u9762\n</code></pre>\n<p>\u4FDD\u5B58\u6587\u4EF6\u540E\uFF0C\u6D4F\u89C8\u5668\u9875\u9762\u4F1A\u81EA\u52A8\u66F4\u65B0\uFF0C\u6240\u89C1\u5373\u6240\u5F97\u3002</p>\n<h3 id="\u914D\u7F6E\u9876\u90E8\u5BFC\u822A-\u53EF\u9009"><a class="header-anchor" href="#\u914D\u7F6E\u9876\u90E8\u5BFC\u822A-\u53EF\u9009">#</a>\u914D\u7F6E\u9876\u90E8\u5BFC\u822A (\u53EF\u9009)</h3><p>\u7531\u4E8E\u7B80\u5386\u901A\u5E38\u5305\u542B\u7684\u9875\u9762\u4E0D\u591A\uFF0C\u6A21\u677F\u9ED8\u8BA4\u6CA1\u6709\u5F00\u542F\u9876\u90E8\u5BFC\u822A\u83DC\u5355\u3002\u5982\u679C\u4F60\u5E0C\u671B\u5728\u9875\u9762\u9876\u90E8\u4E5F\u663E\u793A\u5BFC\u822A\uFF0C\u53EF\u4EE5\u5728 <code>index.md</code> \u4E2D\u6DFB\u52A0 <code>nav</code> \u914D\u7F6E\uFF1A</p>\n<pre><code class="language-yaml">nav:\n  - text: \u5DE5\u4F5C\u7ECF\u5386\n    link: /zh/01-experience/index\n  - text: \u9879\u76EE\u7ECF\u9A8C\n    link: /zh/02-projects/index\n</code></pre>\n<p>\u8FD9\u6837\uFF0CHeader \u5DE6\u4FA7\u5C31\u4F1A\u51FA\u73B0\u4F60\u914D\u7F6E\u7684\u83DC\u5355\u9879\u3002</p>\n<h3 id="\u4E2A\u6027\u5316\u8BBE\u7F6E"><a class="header-anchor" href="#\u4E2A\u6027\u5316\u8BBE\u7F6E">#</a>\u4E2A\u6027\u5316\u8BBE\u7F6E</h3><p>\u5728 <code>index.md</code> \u7684 Frontmatter \u4E2D\uFF0C\u4F60\u8FD8\u53EF\u4EE5\u8FDB\u884C\u66F4\u591A\u4E2A\u6027\u5316\u8BBE\u7F6E\u3002</p>\n<h4 id="github-\u94FE\u63A5"><a class="header-anchor" href="#github-\u94FE\u63A5">#</a>GitHub \u94FE\u63A5</h4><p>Header \u53F3\u4FA7\u9ED8\u8BA4\u663E\u793A GitHub \u9879\u76EE\u94FE\u63A5\u3002\u5982\u679C\u4F60\u60F3\u4FEE\u6539\u6216\u9690\u85CF\u5B83\uFF1A</p>\n<pre><code class="language-yaml"># \u4FEE\u6539\u94FE\u63A5\ngithub-title: View on GitHub\ngithub-link: https://github.com/yourusername/my-cv\n# \u6216\u8005\u76F4\u63A5\u5220\u9664\u8FD9\u4E24\u884C\u4EE5\u9690\u85CF\n</code></pre>\n<h4 id="\u81EA\u5B9A\u4E49\u6837\u5F0F"><a class="header-anchor" href="#\u81EA\u5B9A\u4E49\u6837\u5F0F">#</a>\u81EA\u5B9A\u4E49\u6837\u5F0F</h4><p>\u60F3\u6362\u4E2A\u4E3B\u9898\u8272\uFF1F\u60F3\u8C03\u6574\u4FA7\u8FB9\u680F\u5BBD\u5EA6\uFF1F\u6CA1\u95EE\u9898\uFF01\u4F60\u53EF\u4EE5\u5728 <code>index.md</code> \u4E2D\u901A\u8FC7 <code>styles</code> \u5C5E\u6027\u76F4\u63A5\u8986\u76D6 CSS \u53D8\u91CF\uFF1A</p>\n<pre><code class="language-yaml">styles:\n  &#39;:root&#39;: { &#39;--primary-accent-color&#39;: &#39;#0ac92a&#39; } # \u4FEE\u6539\u4E3B\u8272\u8C03\u4E3A\u7EFF\u8272\n  # body: { font-family: &#39;Inter&#39;, sans-serif; }    # \u4FEE\u6539\u5168\u5C40\u5B57\u4F53\n</code></pre>\n<p>\u5173\u4E8E\u66F4\u591A\u6837\u5F0F\u914D\u7F6E\uFF0C\u53EF\u4EE5\u53C2\u8003 <a href="https://uuware.github.io/lupine.js/zh/articles/introduce-lupine.press">\u8FD9\u7BC7\u5173\u4E8E Lupine.Press \u7684\u4ECB\u7ECD</a>\u3002</p>\n<h2 id="\u7ED3\u8BED"><a class="header-anchor" href="#\u7ED3\u8BED">#</a>\u7ED3\u8BED</h2><p>\u4F7F\u7528 Lupine.js \u6784\u5EFA\u7B80\u5386\u7F51\u7AD9\uFF0C\u4E0D\u4EC5\u662F\u5C55\u793A\u4E13\u4E1A\u6280\u80FD\u7684\u6700\u4F73\u65B9\u5F0F\uFF0C\u66F4\u4F53\u73B0\u4E86\u60A8\u5BF9\u6280\u672F\u7684\u70ED\u60C5\u4E0E\u8FFD\u6C42\u3002\u5982\u679C\u60A8\u559C\u6B22\u8FD9\u4E2A\u6A21\u7248\uFF0C\u6216\u8005\u5B83\u5BF9\u60A8\u6709\u6240\u5E2E\u52A9\uFF0C\u6B22\u8FCE\u5728 GitHub \u4E0A\u4E3A\u6211\u4EEC\u70B9\u4EAE\u4E00\u9897\u661F \u2B50\uFE0F</p>\n<p>\u{1F449} <strong><a href="https://github.com/uuware/lupine.js">https://github.com/uuware/lupine.js</a></strong></p>\n<p>\u795D\u4F60\u65E9\u65E5\u62FF\u5230\u5FC3\u4EEA\u7684 Offer\uFF01</p>\n';

  // apps/doc/web/src/markdown-built/zh/articles/how-to-build-fast-ssr-app.html
  var how_to_build_fast_ssr_app_default2 = '<p>\u5728 2026 \u5E74\u6784\u5EFA\u73B0\u4EE3 Web \u5E94\u7528\uFF0C\u5F80\u5F80\u8981\u5728\u201C\u6C89\u91CD\u4F46\u5F3A\u5927\u201D\uFF08\u5982 Next.js, Remix\uFF09\u4E0E\u201C\u8F7B\u91CF\u4F46\u53D7\u9650\u201D\uFF08\u5982 Vanilla JS, \u5FAE\u578B\u5E93\uFF09\u4E4B\u95F4\u505A\u9009\u62E9\u3002\u4F46\u5982\u679C\u4F60\u80FD\u540C\u65F6\u62E5\u6709\u4E24\u8005\u7684\u4F18\u70B9\u5462\uFF1F</p>\n<p>\u9047\u89C1 <strong>Lupine.js</strong> \u2014\u2014 \u4E00\u4E2A <strong>7kb</strong> (gzipped) \u7684\u5168\u6808\u6846\u67B6\uFF0C\u5B83\u5E26\u6765\u4E86\u670D\u52A1\u7AEF\u6E32\u67D3 (SSR)\u3001CSS-in-JS \u4EE5\u53CA\u7C7B React \u7684 TSX \u5F00\u53D1\u4F53\u9A8C\uFF0C\u5374\u6CA1\u6709\u4EFB\u4F55\u81C3\u80BF\u7684\u6253\u5305\u4F53\u79EF\u3002</p>\n<p>\u5728\u672C\u6587\u4E2D\uFF0C\u6211\u5C06\u5C55\u793A\u5982\u4F55\u4F7F\u7528 Lupine.js \u6784\u5EFA\u4E00\u4E2A\u95EA\u7535\u822C\u5FEB\u901F\u3001SEO \u53CB\u597D\u7684 Web \u5E94\u7528\u3002</p>\n<p><img src="/lupine.js/assets/ssr.png" alt="Lupine.js Architecture"></p>\n<h2 id="\u4E3A\u4EC0\u4E48\u9009\u62E9-lupine-js"><a class="header-anchor" href="#\u4E3A\u4EC0\u4E48\u9009\u62E9-lupine-js">#</a>\u4E3A\u4EC0\u4E48\u9009\u62E9 Lupine.js\uFF1F</h2><ul>\n<li><strong>\u26A1 \u6781\u901F\u6027\u80FD</strong>: \u6CA1\u6709\u865A\u62DF DOM (Virtual DOM) \u7684\u5F00\u9500\u3002\u901A\u8FC7\u667A\u80FD\u7ED1\u5B9A\u76F4\u63A5\u64CD\u4F5C DOM\u3002</li>\n<li><strong>\u{1FAB6} \u6781\u5C0F\u4F53\u79EF</strong>: \u4E00\u4E2A\u529F\u80FD\u5B8C\u5907\u3001\u5305\u542B SSR \u548C\u8DEF\u7531\u7684 &quot;Hello World&quot; \u5E94\u7528\uFF0Cgzip \u540E\u4EC5\u9700 ~7kb\u3002</li>\n<li><strong>\u{1F9E9} \u7C7B React \u8BED\u6CD5</strong>: \u4F7F\u7528 JSX/TSX\u3002\u5982\u679C\u4F60\u719F\u6089 React\uFF0C\u901A\u8FC7 Lupine \u4E0A\u624B\u51E0\u4E4E\u53EA\u9700\u51E0\u5206\u949F\u3002</li>\n<li><strong>\u{1F578}\uFE0F \u539F\u751F SSR</strong>: \u670D\u52A1\u7AEF\u6E32\u67D3\u662F\u7684\u4E00\u7B49\u516C\u6C11\uFF0C\u800C\u975E\u4E8B\u540E\u8865\u5145\u3002\u5185\u7F6E\u81EA\u52A8\u5316\u7684 SEO \u652F\u6301\u3002</li>\n<li><strong>\u{1F3A8} \u5185\u7F6E CSS-in-JS</strong>: \u652F\u6301\u4F5C\u7528\u57DF\u6837\u5F0F\u3001\u5D4C\u5957\u548C\u5A92\u4F53\u67E5\u8BE2\uFF0C\u65E0\u9700\u5F15\u5165\u4EFB\u4F55\u989D\u5916\u5E93\u3002</li>\n</ul>\n<h2 id="1-\u51E0\u79D2\u949F\u5185\u5F00\u59CB"><a class="header-anchor" href="#1-\u51E0\u79D2\u949F\u5185\u5F00\u59CB">#</a>1. \u51E0\u79D2\u949F\u5185\u5F00\u59CB</h2><p>Lupine.js \u63D0\u4F9B\u4E86\u4E00\u4E2A\u547D\u4EE4\u884C\u5DE5\u5177 (CLI) \u6765\u5FEB\u901F\u751F\u6210\u9879\u76EE\u811A\u624B\u67B6\u3002</p>\n<pre><code class="language-bash">npx create-lupine@latest my-app\ncd my-app\nnpm install\nnpm run dev\n</code></pre>\n<p>\u8BBF\u95EE <code>http://localhost:11080</code>\uFF0C\u4F60\u5C31\u80FD\u770B\u5230\u4F60\u7684\u670D\u52A1\u7AEF\u6E32\u67D3\u5E94\u7528\u6B63\u5728\u8FD0\u884C\u4E86\u3002</p>\n<h2 id="2-hello-world-\u4EA6\u5728\u670D\u52A1\u7AEF\u6E32\u67D3"><a class="header-anchor" href="#2-hello-world-\u4EA6\u5728\u670D\u52A1\u7AEF\u6E32\u67D3">#</a>2. &quot;Hello World&quot; (\u4EA6\u5728\u670D\u52A1\u7AEF\u6E32\u67D3)</h2><p>Lupine.js \u7EC4\u4EF6\u770B\u8D77\u6765\u975E\u5E38\u4EB2\u5207\u3002\u8FD9\u662F\u4E00\u4E2A\u7B80\u5355\u7684\u8BA1\u6570\u5668\u7EC4\u4EF6 (<code>src/pages/home.tsx</code>)\uFF1A</p>\n<pre><code class="language-tsx">import { HtmlVar, CssProps } from &#39;lupine.web&#39;;\n\nexport const HomePage = () =&gt; {\n  // 1. \u54CD\u5E94\u5F0F\u72B6\u6001 (Signals)\n  // &#39;0&#39; \u662F\u521D\u59CB\u503C\u3002\n  const count = new HtmlVar(&#39;0&#39;);\n\n  // 2. CSS-in-JS (\u5185\u7F6E\u652F\u6301!)\n  const css: CssProps = {\n    textAlign: &#39;center&#39;,\n    padding: &#39;50px&#39;,\n    h1: {\n      color: &#39;#333&#39;,\n      fontSize: &#39;2.5rem&#39;,\n    },\n    button: {\n      padding: &#39;10px 20px&#39;,\n      fontSize: &#39;1.2rem&#39;,\n      cursor: &#39;pointer&#39;,\n      &#39;&amp;:hover&#39;: {\n        backgroundColor: &#39;#eee&#39;,\n      },\n    },\n  };\n\n  return (\n    &lt;div css={css}&gt;\n      &lt;h1&gt;Hello Lupine.js!&lt;/h1&gt;\n      &lt;p&gt;Current Count: {count.node}&lt;/p&gt;\n\n      {/* \u76F4\u63A5 DOM \u66F4\u65B0\uFF0C\u65E0 VDOM diffing */}\n      &lt;button\n        onClick={() =&gt; {\n          const current = Number(count.value);\n          count.value = (current + 1).toString();\n        }}\n      &gt;\n        Increment\n      &lt;/button&gt;\n    &lt;/div&gt;\n  );\n};\n</code></pre>\n<h3 id="\u8FD9\u91CC\u53D1\u751F\u4E86\u4EC0\u4E48"><a class="header-anchor" href="#\u8FD9\u91CC\u53D1\u751F\u4E86\u4EC0\u4E48">#</a>\u8FD9\u91CC\u53D1\u751F\u4E86\u4EC0\u4E48\uFF1F</h3><ol>\n<li><strong><code>HtmlVar</code></strong>: \u8FD9\u662F Lupine \u7248\u672C\u7684 Signals\uFF08\u4FE1\u53F7\u91CF\uFF09\u3002\u5B83\u76F4\u63A5\u7ED1\u5B9A\u5230\u6587\u672C\u8282\u70B9\u3002\u5F53\u4F60\u66F4\u65B0 <code>count.value</code> \u65F6\uFF0C\u53EA\u6709\u90A3\u4E2A\u7279\u5B9A\u7684\u6587\u672C\u8282\u70B9\u4F1A\u66F4\u65B0\u3002\u7EC4\u4EF6\u672C\u8EAB\u4E0D\u4F1A\u91CD\u65B0\u6E32\u67D3\uFF01</li>\n<li><strong><code>css</code> \u5C5E\u6027</strong>: \u6837\u5F0F\u4F1A\u81EA\u52A8\u8FDB\u884C\u4F5C\u7528\u57DF\u9694\u79BB\u3002SSR \u4F1A\u5C06\u5173\u952E CSS \u6CE8\u5165\u5230 <code>&lt;head&gt;</code> \u4E2D\uFF0C\u56E0\u6B64<strong>\u5B8C\u5168\u6CA1\u6709\u6837\u5F0F\u95EA\u70C1 (FOUC)</strong>\u3002</li>\n</ol>\n<h2 id="3-\u96F6\u914D\u7F6E-ssr-\u4E0E-seo"><a class="header-anchor" href="#3-\u96F6\u914D\u7F6E-ssr-\u4E0E-seo">#</a>3. \u96F6\u914D\u7F6E SSR \u4E0E SEO</h2><p>\u73B0\u4EE3 SPA \u5F00\u53D1\u4E2D\u6700\u5927\u7684\u75DB\u70B9\u4E4B\u4E00\u5C31\u662F SEO\u3002Lupine \u539F\u751F\u89E3\u51B3\u4E86\u8FD9\u4E2A\u95EE\u9898\u3002\u4F60\u4E0D\u9700\u8981 <code>react-helmet</code> \u6216\u590D\u6742\u7684\u5E03\u5C40\u914D\u7F6E\u3002</p>\n<pre><code class="language-tsx">import { MetaData, PageProps } from &#39;lupine.web&#39;;\n\nexport const ProductPage = async (props: PageProps) =&gt; {\n  // 1. \u83B7\u53D6\u6570\u636E (\u5728 SSR \u671F\u95F4\u8FD0\u884C\u4E8E\u670D\u52A1\u7AEF\uFF0C\u6216\u8005\u5728\u9875\u9762\u5BFC\u822A\u65F6\u8FD0\u884C\u4E8E\u5BA2\u6237\u7AEF)\n  // \u6CE8\u610F\uFF1A\u53EF\u4EE5\u76F4\u63A5\u4F7F\u7528\u6807\u51C6 fetch\uFF01\n  const product = await fetch(`https://api.example.com/products/${props.urlParameters[&#39;id&#39;]}`).then((res) =&gt;\n    res.json()\n  );\n\n  return (\n    &lt;div&gt;\n      {/* 2. \u76F4\u63A5\u5728\u7EC4\u4EF6\u4E2D\u5B9A\u4E49 SEO \u5143\u6570\u636E */}\n      &lt;MetaData property=&#39;og:title&#39; content={product.name} /&gt;\n      &lt;MetaData property=&#39;og:description&#39; content={product.description} /&gt;\n      &lt;MetaData property=&#39;og:image&#39; content={product.imageUrl} /&gt;\n\n      &lt;h1&gt;{product.name}&lt;/h1&gt;\n      &lt;p&gt;{product.description}&lt;/p&gt;\n    &lt;/div&gt;\n  );\n};\n</code></pre>\n<p>\u5F53\u722C\u866B\uFF08\u5982 Googlebot, Twitter card\uFF09\u8BBF\u95EE\u8FD9\u4E2A URL \u65F6\uFF0CLupine \u7684\u670D\u52A1\u7AEF\u4F1A\u5728\u8FD4\u56DE HTML \u4E4B\u524D\u6E32\u67D3\u597D\u6240\u6709\u8FD9\u4E9B\u5143\u6807\u7B7E\u3002</p>\n<h2 id="4-\u5F3A\u5927\u7684\u8DEF\u7531\u7CFB\u7EDF"><a class="header-anchor" href="#4-\u5F3A\u5927\u7684\u8DEF\u7531\u7CFB\u7EDF">#</a>4. \u5F3A\u5927\u7684\u8DEF\u7531\u7CFB\u7EDF</h2><p>Lupine \u7684 <code>PageRouter</code> \u5F00\u7BB1\u5373\u652F\u6301\u5D4C\u5957\u8DEF\u7531\u3001\u4E2D\u95F4\u4EF6 (Middleware) \u548C\u5E03\u5C40 (Layouts)\u3002</p>\n<pre><code class="language-tsx">import { PageRouter, bindRouter } from &#39;lupine.web&#39;;\n\nconst router = new PageRouter();\n\n// \u4E2D\u95F4\u4EF6 (\u4F8B\u5982\uFF1AAuth \u68C0\u67E5)\nrouter.setFilter(async (props) =&gt; {\n  // \u68C0\u67E5\u767B\u5F55\u903B\u8F91...\n  return null; // \u7EE7\u7EED\u8DEF\u7531\n});\n\n// \u5B9A\u4E49\u8DEF\u7531\nrouter.use(&#39;/home&#39;, HomePage);\nrouter.use(&#39;/product/:id&#39;, ProductPage);\nrouter.use(&#39;*&#39;, NotFoundPage);\n\n// \u7ED1\u5B9A\u5230\u5E94\u7528\nbindRouter(router);\n</code></pre>\n<h2 id="\u603B\u7ED3"><a class="header-anchor" href="#\u603B\u7ED3">#</a>\u603B\u7ED3</h2><p>Lupine.js \u65E0\u610F\u5728\u5E9E\u5927\u7684\u4F01\u4E1A\u7EA7\u751F\u6001\u5E94\u7528\u4E2D\u53D6\u4EE3 React\u3002\u4F46\u5BF9\u4E8E<strong>\u535A\u5BA2\u3001\u843D\u5730\u9875\u3001\u4EEA\u8868\u76D8 (Dashboards) \u548C\u8FFD\u6C42\u521B\u65B0\u7684 Web \u5E94\u7528</strong>\uFF0C\u5982\u679C\u901F\u5EA6\u548C\u5305\u4F53\u79EF\u81F3\u5173\u91CD\u8981\uFF0C\u90A3\u4E48 Lupine.js \u5C06\u662F\u4E00\u80A1\u6E05\u65B0\u7684\u7A7A\u6C14\u3002</p>\n<p>\u5B83\u5C06 <strong>2026 \u5E74\u7684\u5F00\u53D1\u4F53\u9A8C (DX)</strong> \u5E26\u56DE\u4E86 <strong>2010 \u5E74\u7684\u6781\u81F4\u6027\u80FD</strong>\u3002</p>\n<p><strong>\u8BD5\u4E00\u8BD5\u5427\uFF0C\u671F\u5F85\u4F60\u7684\u53CD\u9988\uFF01</strong></p>\n<hr>\n<p>\u{1F517} <strong>Github</strong>: <a href="https://github.com/uuware/lupine.js">https://github.com/uuware/lupine.js</a>\n\u2B50 <strong>\u5982\u679C\u559C\u6B22\u8F7B\u91CF\u7EA7 Web \u6280\u672F\uFF0C\u8BF7\u7ED9\u6211\u4EEC\u70B9\u4E2A Star\uFF01</strong></p>\n';

  // apps/doc/web/src/markdown-built/zh/articles/introduce-lupine.js.html
  var introduce_lupine_js_default2 = '<h1 id="\u4ECB\u7ECD-lupine-js-\u4E00\u6B3E-\u6781\u5176-\u9AD8\u6548\u7684-web-\u6846\u67B6"><a class="header-anchor" href="#\u4ECB\u7ECD-lupine-js-\u4E00\u6B3E-\u6781\u5176-\u9AD8\u6548\u7684-web-\u6846\u67B6">#</a>\u4ECB\u7ECD Lupine.js\uFF1A\u4E00\u6B3E&quot;\u6781\u5176&quot;\u9AD8\u6548\u7684 Web \u6846\u67B6</h1><p>\u5728\u4E00\u4E2A\u88AB\u5E9E\u5927\u7684\u5143\u6846\u67B6 (Meta-frameworks) \u548C\u590D\u6742\u6784\u5EFA\u94FE\u4E3B\u5BFC\u7684\u4E16\u754C\u91CC\uFF0C<strong>Lupine.js</strong> \u63D0\u51FA\u4E86\u4E00\u4E2A\u7B80\u5355\u7684\u95EE\u9898\uFF1A<em>\u5982\u679C\u6211\u4EEC\u80FD\u62E5\u6709\u73B0\u4EE3\u5168\u6808\u6846\u67B6\u7684\u5A01\u529B\uFF0C\u5374\u4E0D\u9700\u8981\u90A3\u4E9B\u81C3\u80BF\u7684\u8D1F\u62C5\uFF0C\u4F1A\u600E\u6837\uFF1F</em></p>\n<p>Lupine.js \u662F\u4E00\u4E2A <strong>\u8F7B\u91CF\u7EA7 (7kb gzipped)</strong> \u7684 <strong>\u5168\u6808</strong> Web \u6846\u67B6\uFF0C\u5B83\u7ED3\u5408\u4E86\u7C7B React \u7684\u524D\u7AEF\u4F53\u9A8C\u548C\u7C7B Express \u7684\u540E\u7AEF\u67B6\u6784\u3002\u5B83\u662F\u5B8C\u5168\u4ECE\u96F6\u5F00\u59CB\u8BBE\u8BA1\uFF0C\u65E8\u5728\u5B9E\u73B0\u6781\u81F4\u7684\u901F\u5EA6\u3001\u7B80\u6D01\u548C\u9AD8\u6548\u3002</p>\n<p><img src="/lupine.js/assets/og-image.png" alt="Lupine.js"></p>\n<h2 id="\u4E3A\u4EC0\u4E48\u9009\u62E9-lupine-js"><a class="header-anchor" href="#\u4E3A\u4EC0\u4E48\u9009\u62E9-lupine-js">#</a>\u4E3A\u4EC0\u4E48\u9009\u62E9 Lupine.js\uFF1F</h2><h3 id="1-\u6781\u5176\u8F7B\u91CF\u7684\u524D\u7AEF"><a class="header-anchor" href="#1-\u6781\u5176\u8F7B\u91CF\u7684\u524D\u7AEF">#</a>1. \u{1FAB6} \u6781\u5176\u8F7B\u91CF\u7684\u524D\u7AEF</h3><p><code>lupine.web</code> \u524D\u7AEF\u5305\u6781\u5176\u5C0F\u5DE7\u2014\u2014\u4EC5 <strong>7kb gzipped</strong>\u3002\u7136\u800C\uFF0C\u5B83\u4FDD\u7559\u4E86\u4F60\u719F\u6089\u548C\u559C\u7231\u7684\u5F00\u53D1\u4F53\u9A8C\uFF1A<strong>TSX \u8BED\u6CD5</strong> (React JSX)\u3001\u7EC4\u4EF6\u548C Hooks\u3002\u6CA1\u6709\u6C89\u91CD\u7684\u8FD0\u884C\u65F6\u9700\u8981\u4E0B\u8F7D\uFF0C\u8FD9\u610F\u5473\u7740\u5373\u4F7F\u5728\u6162\u901F\u7F51\u7EDC\u4E0B\uFF0C\u4F60\u7684\u9875\u9762\u4E5F\u80FD\u77AC\u95F4\u52A0\u8F7D\u3002</p>\n<h3 id="2-\u5185\u7F6E\u670D\u52A1\u7AEF\u6E32\u67D3-ssr"><a class="header-anchor" href="#2-\u5185\u7F6E\u670D\u52A1\u7AEF\u6E32\u67D3-ssr">#</a>2. \u26A1 \u5185\u7F6E\u670D\u52A1\u7AEF\u6E32\u67D3 (SSR)</h3><p>\u5927\u591A\u6570\u6846\u67B6\u5C06 SSR \u89C6\u4E3A\u9644\u52A0\u529F\u80FD\u3002\u5728 Lupine \u4E2D\uFF0CSSR \u662F <strong>\u4E00\u7B49\u516C\u6C11</strong>\u3002<code>lupine.api</code> \u540E\u7AEF\u7ECF\u8FC7\u4F18\u5316\uFF0C\u80FD\u591F\u81EA\u52A8\u5728\u670D\u52A1\u5668\u4E0A\u6E32\u67D3\u4F60\u7684\u524D\u7AEF\u9875\u9762\u3002</p>\n<ul>\n<li><strong>\u65E0\u6837\u5F0F\u95EA\u70C1 (No FOUC)</strong>: \u5173\u952E CSS \u7531\u670D\u52A1\u7AEF\u6CE8\u5165\u3002</li>\n<li><strong>\u96F6\u914D\u7F6E SEO</strong>: Meta \u6807\u7B7E (<code>og:image</code>, <code>description</code>) \u5728\u9875\u9762\u79BB\u5F00\u670D\u52A1\u5668\u524D\u5C31\u5DF2\u7ECF\u8BA1\u7B97\u5B8C\u6BD5\u3002</li>\n<li><strong>\u793E\u4EA4\u5206\u4EAB\u5C31\u7EEA</strong>: \u5206\u4EAB\u5230 Twitter/\u5FAE\u4FE1/Facebook \u7684\u94FE\u63A5\u5F00\u7BB1\u5373\u7528\uFF0C\u6548\u679C\u5B8C\u7F8E\u3002</li>\n</ul>\n<h3 id="3-\u539F\u751F-css-in-js-\u5F15\u64CE"><a class="header-anchor" href="#3-\u539F\u751F-css-in-js-\u5F15\u64CE">#</a>3. \u{1F3A8} \u539F\u751F CSS-in-JS \u5F15\u64CE</h3><p>\u544A\u522B\u914D\u7F6E PostCSS\u3001Tailwind \u6216 styled-components \u7684\u70E6\u607C\u3002Lupine \u5185\u7F6E\u4E86\u4E00\u4E2A\u5F3A\u5927\u7684 CSS-in-JS \u5F15\u64CE\u3002</p>\n<ul>\n<li><strong>\u6837\u5F0F\u9694\u79BB</strong>: \u6837\u5F0F\u81EA\u52A8\u9694\u79BB\u5230\u4F60\u7684\u7EC4\u4EF6\u3002</li>\n<li><strong>\u5D4C\u5957\u652F\u6301</strong>: \u652F\u6301 <code>.parent &amp;</code> \u8BED\u6CD5\u3002</li>\n<li><strong>\u9AD8\u6027\u80FD</strong>: \u6837\u5F0F\u5728 SSR \u671F\u95F4\u88AB\u9AD8\u6548\u63D0\u53D6\u548C\u6CE8\u5165\u3002</li>\n</ul>\n<pre><code class="language-tsx">const Button = () =&gt; {\n  const css = {\n    backgroundColor: &#39;#0ac92a&#39;,\n    &#39;&amp;:hover&#39;: {\n      backgroundColor: &#39;#08a823&#39;,\n    },\n  };\n  return &lt;button css={css}&gt;\u70B9\u51FB\u6211&lt;/button&gt;;\n};\n</code></pre>\n<h3 id="4-\u5168\u6808\u5408\u4E00"><a class="header-anchor" href="#4-\u5168\u6808\u5408\u4E00">#</a>4. \u{1F680} \u5168\u6808\u5408\u4E00</h3><p>Lupine \u4E0D\u4EC5\u4EC5\u662F\u4E00\u4E2A\u524D\u7AEF\u5E93\uFF1B\u5B83\u662F\u5B8C\u6574\u7684\u5E94\u7528\u89E3\u51B3\u65B9\u6848\u3002</p>\n<ul>\n<li><strong>\u540E\u7AEF (<code>lupine.api</code>)</strong>: \u4E00\u4E2A\u9AD8\u6548\u3001\u6781\u7B80\u7684 Node.js \u6846\u67B6\uFF0C\u7C7B\u4F3C\u4E8E Express\u3002</li>\n<li><strong>\u524D\u7AEF (<code>lupine.web</code>)</strong>: \u4E00\u4E2A\u54CD\u5E94\u5F0F\u7684 UI \u5E93\u3002</li>\n<li><strong>\u5F00\u53D1\u4F53\u9A8C</strong>: \u8FD0\u884C <code>npm run dev</code>\uFF0C\u5373\u53EF\u5728\u540C\u4E00\u4E2A VS Code \u4F1A\u8BDD\u4E2D\u540C\u65F6\u8C03\u8BD5\u524D\u7AEF\u548C\u540E\u7AEF\u3002</li>\n</ul>\n<h2 id="\u5FEB\u901F\u5F00\u59CB"><a class="header-anchor" href="#\u5FEB\u901F\u5F00\u59CB">#</a>\u5FEB\u901F\u5F00\u59CB</h2><p>\u51C6\u5907\u597D\u5C1D\u8BD5\u4E86\u5417\uFF1F\u51E0\u79D2\u949F\u5C31\u80FD\u642D\u5EFA\u4E00\u4E2A\u65B0\u7684\u9879\u76EE\u3002</p>\n<h3 id="\u7B2C\u4E00\u6B65-\u521B\u5EFA\u9879\u76EE"><a class="header-anchor" href="#\u7B2C\u4E00\u6B65-\u521B\u5EFA\u9879\u76EE">#</a>\u7B2C\u4E00\u6B65\uFF1A\u521B\u5EFA\u9879\u76EE</h3><p>\u4F7F\u7528\u6211\u4EEC\u7684 CLI \u5DE5\u5177\u521B\u5EFA\u4E00\u4E2A\u65B0\u5E94\u7528\u3002</p>\n<pre><code class="language-bash">npx create-lupine@latest my-awesome-app\n</code></pre>\n<h3 id="\u7B2C\u4E8C\u6B65-\u8FD0\u884C\u9879\u76EE"><a class="header-anchor" href="#\u7B2C\u4E8C\u6B65-\u8FD0\u884C\u9879\u76EE">#</a>\u7B2C\u4E8C\u6B65\uFF1A\u8FD0\u884C\u9879\u76EE</h3><p>\u8FDB\u5165\u76EE\u5F55\u5E76\u542F\u52A8\u5F00\u53D1\u670D\u52A1\u5668\u3002</p>\n<pre><code class="language-bash">cd my-awesome-app\nnpm install\nnpm run dev\n</code></pre>\n<p>\u8BBF\u95EE <code>http://localhost:11080</code>\uFF0C\u4F60\u5C06\u770B\u5230\u4F60\u7684\u7B2C\u4E00\u4E2A Lupine \u5E94\u7528\u6B63\u5728\u8FD0\u884C\uFF01</p>\n<h2 id="\u4EE3\u7801\u6D3B\u8DC3\u5EA6"><a class="header-anchor" href="#\u4EE3\u7801\u6D3B\u8DC3\u5EA6">#</a>\u4EE3\u7801\u6D3B\u8DC3\u5EA6</h2><p>Lupine \u6B63\u5728\u79EF\u6781\u5F00\u53D1\u4E2D\u3002\u4F60\u53EF\u4EE5\u76F4\u63A5\u5728 GitHub \u4E0A\u67E5\u770B\u6211\u4EEC\u7684\u4EE3\u7801\u9891\u7387\u548C\u8D21\u732E\uFF1A\n\u{1F449} <a href="https://github.com/uuware/lupine.js">https://github.com/uuware/lupine.js</a></p>\n<h2 id="\u603B\u7ED3"><a class="header-anchor" href="#\u603B\u7ED3">#</a>\u603B\u7ED3</h2><p>Lupine.js \u975E\u5E38\u9002\u5408\u8FD9\u6837\u7684\u5F00\u53D1\u8005\uFF1A</p>\n<ul>\n<li><strong>\u638C\u63A7\u529B</strong>: \u60F3\u8981\u4E86\u89E3\u6280\u672F\u6808\u7684\u6BCF\u4E00\u4E2A\u90E8\u5206\u3002</li>\n<li><strong>\u901F\u5EA6</strong>: \u60F3\u4E3A\u7528\u6237\u63D0\u4F9B\u6700\u5FEB\u7684\u4F53\u9A8C\u3002</li>\n<li><strong>\u7B80\u6D01</strong>: \u6CA1\u6709\u9690\u85CF\u7684\u9B54\u6CD5\uFF0C\u53EA\u6709\u5E72\u51C0\u7684\u4EE3\u7801\u3002</li>\n</ul>\n<p>\u7ED9 <strong>Lupine.js</strong> \u5728 GitHub \u4E0A\u70B9\u4E2A Star\uFF0C\u5E76\u5728\u4F60\u7684\u4E0B\u4E00\u4E2A\u9879\u76EE\u4E2D\u5C1D\u8BD5\u4E00\u4E0B\u5427\uFF01</p>\n';

  // apps/doc/web/src/markdown-built/zh/articles/introduce-lupine.press.html
  var introduce_lupine_press_default2 = '<h1 id="lupine-press-\u4E3A\u6781\u901F\u6587\u6863\u800C\u751F"><a class="header-anchor" href="#lupine-press-\u4E3A\u6781\u901F\u6587\u6863\u800C\u751F">#</a>Lupine.Press\uFF1A\u4E3A\u6781\u901F\u6587\u6863\u800C\u751F</h1><p>\u5199\u6587\u6863\u4E0D\u5E94\u8BE5\u662F\u4E00\u4EF6\u75DB\u82E6\u7684\u4E8B\u3002\u4F46\u5728\u73B0\u6709\u7684\u751F\u6001\u4E2D\uFF0C\u6211\u4EEC\u5F80\u5F80\u9700\u8981\u5728\u201C\u590D\u6742\u7684\u914D\u7F6E\u201D\u548C\u201C\u4E11\u964B\u7684\u9ED8\u8BA4\u6837\u5F0F\u201D\u4E4B\u95F4\u505A\u9009\u62E9\u3002</p>\n<p><strong>Lupine.Press</strong> \u7684\u51FA\u73B0\uFF0C\u5C31\u662F\u4E3A\u4E86\u6253\u7834\u8FD9\u4E2A\u50F5\u5C40\u3002</p>\n<p>\u5B83\u662F\u57FA\u4E8E <strong>Lupine.js</strong> \u6784\u5EFA\u7684\u6587\u6863\u6846\u67B6\uFF0C\u7EE7\u627F\u4E86\u540E\u8005 <strong>\u201C\u6781\u81F4\u8F7B\u91CF\u201D</strong> \u548C <strong>\u201C\u9AD8\u6027\u80FD\u201D</strong> \u7684\u57FA\u56E0\u3002\u5B83\u80FD\u8BA9\u4F60\u7528\u6700\u7B80\u5355\u7684 Markdown\uFF0C\u6784\u5EFA\u51FA\u4E13\u4E1A\u3001\u54CD\u5E94\u5F0F\u4E14\u652F\u6301\u591A\u8BED\u8A00\u7684\u6587\u6863\u7F51\u7AD9\u3002</p>\n<p><img src="/lupine.js/assets/lupine.press.png" alt="Lupine.Press"></p>\n<p>\u4E3A\u4E86\u8BA9\u60A8\u66F4\u76F4\u89C2\u5730\u4E86\u89E3\u6548\u679C\uFF0C\u6211\u4EEC\u4E3A\u60A8\u51C6\u5907\u4E86\u4E00\u4E2A\u5B8C\u6574\u7684\u6F14\u793A\u9879\u76EE\u3002\u60A8\u53EF\u4EE5\u76F4\u63A5\u8BBF\u95EE\u6E90\u7801\u4ED3\u5E93\uFF0C\u751A\u81F3\u76F4\u63A5 Fork \u5B83\u4F5C\u4E3A\u60A8\u7684\u8D77\u70B9\uFF1A</p>\n<ul>\n<li><strong>\u6E90\u7801\u4ED3\u5E93</strong>: <a href="https://github.com/uuware/lupine-template-doc-starter">https://github.com/uuware/lupine-template-doc-starter</a></li>\n</ul>\n<p>\u60A8\u4E5F\u53EF\u4EE5\u70B9\u51FB\u4E0B\u65B9\u94FE\u63A5\uFF0C\u5728\u7EBF\u67E5\u770B\u8BE5\u9879\u76EE\u7684\u5B9E\u9645\u8FD0\u884C\u6548\u679C\uFF1A</p>\n<ul>\n<li><strong>\u5728\u7EBF\u6F14\u793A</strong>: <a href="https://uuware.github.io/lupine-template-doc-starter/">https://uuware.github.io/lupine-template-doc-starter/</a></li>\n</ul>\n<h2 id="\u4E3A\u4EC0\u4E48\u9009\u62E9-lupine-press"><a class="header-anchor" href="#\u4E3A\u4EC0\u4E48\u9009\u62E9-lupine-press">#</a>\u4E3A\u4EC0\u4E48\u9009\u62E9 Lupine.Press\uFF1F</h2><h3 id="1-\u96BE\u4EE5\u7F6E\u4FE1\u7684\u5FEB"><a class="header-anchor" href="#1-\u96BE\u4EE5\u7F6E\u4FE1\u7684\u5FEB">#</a>1. \u26A1 \u96BE\u4EE5\u7F6E\u4FE1\u7684\u5FEB</h3><p>\u8FD9\u5C31\u4E0D\u7528\u591A\u8BF4\u4E86\u3002\u57FA\u4E8E Lupine.js \u6838\u5FC3\uFF08\u4EC5 7kb\uFF09\uFF0C\u4F60\u7684\u6587\u6863\u7F51\u7AD9\u52A0\u8F7D\u901F\u5EA6\u4F1A\u5FEB\u5F97\u60CA\u4EBA\u3002\u6CA1\u6709\u81C3\u80BF\u7684 hydration \u8FC7\u7A0B\uFF0C\u5185\u5BB9\u5373\u523B\u5448\u73B0\u3002</p>\n<h3 id="2-markdown-\u9A71\u52A8\u7684\u4E00\u5207"><a class="header-anchor" href="#2-markdown-\u9A71\u52A8\u7684\u4E00\u5207">#</a>2. \u{1F4DD} Markdown \u9A71\u52A8\u7684\u4E00\u5207</h3><p>\u5728 Lupine.Press \u4E2D\uFF0C\u6587\u4EF6\u7ED3\u6784\u5373\u8DEF\u7531\u3002</p>\n<ul>\n<li>\u53EA\u8981\u5728\u76EE\u5F55\u4E0B\u653E\u4E00\u4E2A <code>guide.md</code>\uFF0C\u5B83\u5C31\u4F1A\u81EA\u52A8\u53D8\u6210 <code>/guide</code> \u9875\u9762\u3002</li>\n<li>\u4FA7\u8FB9\u680F\u914D\u7F6E\uFF1F\u76F4\u63A5\u5199\u5728 <code>index.md</code> \u7684 Frontmatter \u91CC\u3002</li>\n<li>\u591A\u8BED\u8A00\uFF1F\u53EA\u9700\u5EFA\u7ACB <code>en</code> \u548C <code>zh</code> \u6587\u4EF6\u5939\uFF0C\u6846\u67B6\u81EA\u52A8\u5904\u7406\u5207\u6362\u3002</li>\n</ul>\n<h3 id="3-\u5F00\u7BB1\u5373\u7528\u7684\u4E13\u4E1A\u8BBE\u8BA1"><a class="header-anchor" href="#3-\u5F00\u7BB1\u5373\u7528\u7684\u4E13\u4E1A\u8BBE\u8BA1">#</a>3. \u{1F3A8} \u5F00\u7BB1\u5373\u7528\u7684\u4E13\u4E1A\u8BBE\u8BA1</h3><p>\u4F60\u4E0D\u9700\u8981\u61C2 CSS \u4E5F\u80FD\u62E5\u6709\u6F02\u4EAE\u7684\u6587\u6863\u7AD9\u3002<code>PressFrame</code> \u7EC4\u4EF6\u5185\u7F6E\u4E86\uFF1A</p>\n<ul>\n<li><strong>\u54CD\u5E94\u5F0F\u4FA7\u8FB9\u680F</strong>\uFF1A\u5728\u79FB\u52A8\u7AEF\u81EA\u52A8\u6298\u53E0\u3002</li>\n<li><strong>\u4EAE\u8272/\u6697\u8272\u6A21\u5F0F</strong>\uFF1A\u81EA\u52A8\u8DDF\u968F\u7CFB\u7EDF\u6216\u624B\u52A8\u5207\u6362\u3002</li>\n<li><strong>\u4EE3\u7801\u9AD8\u4EAE</strong>\uFF1A\u5185\u7F6E\u652F\u6301\u3002</li>\n</ul>\n<h3 id="4-\u7075\u6D3B\u7684\u6269\u5C55\u6027"><a class="header-anchor" href="#4-\u7075\u6D3B\u7684\u6269\u5C55\u6027">#</a>4. \u{1F6E0}\uFE0F \u7075\u6D3B\u7684\u6269\u5C55\u6027</h3><p>\u867D\u7136\u5B83\u5F88\u8F7B\uFF0C\u4F46\u5B83\u4E0D\u201C\u6B7B\u677F\u201D\u3002\u56E0\u4E3A\u672C\u8D28\u4E0A\u5B83\u5C31\u662F\u4E00\u4E2A Lupine.js \u5E94\u7528\u3002\u4F60\u53EF\u4EE5\u968F\u65F6\uFF1A</p>\n<ul>\n<li>\u4F7F\u7528 TSX \u8BED\u6CD5\u7F16\u5199\u7C7B\u4F3C React \u98CE\u683C\u7684\u7EC4\u4EF6\u3002</li>\n<li>\u6DFB\u52A0\u81EA\u5B9A\u4E49\u4EFB\u610F\u6837\u5F0F\u7684\u9875\u9762\u3002</li>\n<li>\u6DFB\u52A0\u4EFB\u610F\u81EA\u52A8\u7684\u5F0F\u6837\u8986\u76D6\u5DF2\u6709\u5F0F\u6837\u3002</li>\n</ul>\n<h2 id="\u90E8\u7F72\u9ED1\u79D1\u6280-github-pages-\u4E5F\u80FD\u8DD1-spa"><a class="header-anchor" href="#\u90E8\u7F72\u9ED1\u79D1\u6280-github-pages-\u4E5F\u80FD\u8DD1-spa">#</a>\u90E8\u7F72\u9ED1\u79D1\u6280\uFF1AGitHub Pages \u4E5F\u80FD\u8DD1 SPA\uFF1F</h2><p>\u4F17\u6240\u5468\u77E5\uFF0CGitHub Pages \u7B49\u9759\u6001\u6258\u7BA1\u670D\u52A1\u5BF9\u5355\u9875\u5E94\u7528\uFF08SPA\uFF09\u7684\u652F\u6301\u5E76\u4E0D\u53CB\u597D\u3002\u56E0\u4E3A\u5B83\u4EEC\u4E0D\u77E5\u9053 <code>/guide/started</code> \u5176\u5B9E\u5E94\u8BE5\u6307\u5411 <code>index.html</code>\uFF0C\u5F80\u5F80\u4F1A\u76F4\u63A5\u8FD4\u56DE <strong>404</strong>\u3002</p>\n<p>Lupine.Press \u63D0\u4F9B\u4E86\u4E00\u4E2A\u806A\u660E\u7684\u89E3\u51B3\u65B9\u6848\u3002</p>\n<h3 id="\u806A\u660E\u4EBA\u90FD\u77E5\u9053\u7684-404-html"><a class="header-anchor" href="#\u806A\u660E\u4EBA\u90FD\u77E5\u9053\u7684-404-html">#</a>\u806A\u660E\u4EBA\u90FD\u77E5\u9053\u7684 <code>404.html</code></h3><p>\u6211\u4EEC\u5728 <code>docs/404.html</code> \u4E2D\u5185\u7F6E\u4E86\u4E00\u6BB5\u795E\u5947\u7684\u4EE3\u7801\uFF1A</p>\n<pre><code class="language-html">&lt;script type=&quot;text/javascript&quot;&gt;\n  // Single Page Apps for GitHub Pages\n  if (window.location.pathname.includes(&#39;/lupine.js/&#39;)) {\n    // \u5C06\u5F53\u524D\u8DEF\u5F84\u4F5C\u4E3A\u53C2\u6570\uFF0C\u91CD\u5B9A\u5411\u56DE\u9996\u9875\n    window.location.href = &#39;/lupine.js/?redirect=&#39; + window.location.pathname;\n  }\n&lt;/script&gt;\n</code></pre>\n<p>\u914D\u5408\u524D\u7AEF\u8DEF\u7531\u7684\u81EA\u52A8\u6062\u590D\u903B\u8F91\uFF0C\u8FD9\u610F\u5473\u7740\uFF1A</p>\n<ol>\n<li>\u7528\u6237\u8BBF\u95EE\u6DF1\u5C42\u94FE\u63A5 <code>/guide/started</code>\u3002</li>\n<li>GitHub Pages \u8FD4\u56DE 404 \u9875\u9762\u3002</li>\n<li>\u811A\u672C\u7ACB\u523B\u5C06\u9875\u9762\u91CD\u5B9A\u5411\u4E3A <code>/?redirect=/guide/started</code>\u3002</li>\n<li>Lupine.js \u5E94\u7528\u542F\u52A8\uFF0C\u8BFB\u53D6 <code>redirect</code> \u53C2\u6570\uFF0C\u65E0\u7F1D\u6062\u590D\u5230\u7528\u6237\u60F3\u770B\u7684\u9875\u9762\u3002</li>\n</ol>\n<p><strong>\u7ED3\u679C\u5C31\u662F\uFF1A\u4F60\u53EF\u4EE5\u514D\u8D39\u4F7F\u7528 GitHub Pages \u6258\u7BA1\u4E00\u4E2A\u4F53\u9A8C\u5B8C\u7F8E\u7684 SPA \u6587\u6863\u7AD9\uFF01</strong></p>\n<h2 id="\u5FEB\u901F\u4E0A\u624B"><a class="header-anchor" href="#\u5FEB\u901F\u4E0A\u624B">#</a>\u5FEB\u901F\u4E0A\u624B</h2><p>\u53EA\u9700\u4E00\u884C\u547D\u4EE4\uFF0C\u7ACB\u523B\u62E5\u6709\u4F60\u7684\u6587\u6863\u7AD9\uFF1A</p>\n<pre><code class="language-bash">npx create-lupine@latest my-docs\n# \u9009\u62E9 &#39;doc-starter&#39; \u6A21\u677F\n</code></pre>\n<p>\u542F\u52A8\u9879\u76EE\uFF1A</p>\n<pre><code class="language-bash">cd my-docs\nnpm install\nnpm run dev\n</code></pre>\n<p>\u73B0\u5728\uFF0C\u5F00\u59CB\u4E13\u6CE8\u4E8E\u5199\u4F5C\u5427\uFF01</p>\n<h2 id="\u53D1\u5E03\u5230-github-pages"><a class="header-anchor" href="#\u53D1\u5E03\u5230-github-pages">#</a>\u53D1\u5E03\u5230 GitHub Pages</h2><p>\u5728 <code>apps/[\u60A8\u7684\u9879\u76EE\u540D]/web</code> \u76EE\u5F55\u4E0B\uFF0C\u60A8\u4F1A\u627E\u5230\u4E00\u4E2A\u540D\u4E3A <code>github-pj-name</code> \u7684\u6587\u4EF6\u5939\u3002\u8BF7\u5C06\u5176\u91CD\u547D\u540D\u4E3A\u60A8\u7684 GitHub \u9879\u76EE\u540D\u79F0\u3002\u63A5\u7740\uFF0C\u5728\u5168\u5C40\u8303\u56F4\u5185\u641C\u7D22 <code>github-pj-name</code> \u5E76\u5C06\u5176\u5168\u90E8\u66FF\u6362\u4E3A\u60A8\u7684 GitHub \u9879\u76EE\u540D\u79F0\u3002\u8FD9\u662F\u4E3A\u4E86\u9002\u914D GitHub Pages \u7684\u8DEF\u5F84\u7ED3\u6784\uFF1A<code>[github-account].github.io/[github-pj-name]/</code>\u3002</p>\n<p>\u7F16\u8F91\u5B8C\u6587\u6863\u540E\uFF0C\u8BF7\u6267\u884C <code>npm run build</code>\u3002\u786E\u8BA4\u7F16\u8BD1\u65E0\u8BEF\u540E\uFF0C\u8FD0\u884C <code>npm run cp-docs</code>\u3002\u6B64\u547D\u4EE4\u4F1A\u5C06 <code>build</code> \u76EE\u5F55\u4E0B\u7684\u9759\u6001\u6587\u4EF6\u590D\u5236\u5230 <code>/docs</code> \u76EE\u5F55\u3002\u5C06\u6240\u6709\u66F4\u6539\u63D0\u4EA4\u5230 GitHub \u4ED3\u5E93\u540E\uFF0C\u8FDB\u5165\u4ED3\u5E93\u7684 Settings -&gt; Pages \u8BBE\u7F6E\u9875\u3002\u5728 Build and deployment \u4E0B\uFF0C\u9009\u62E9 <strong>main</strong> \u5206\u652F\u548C <strong>/docs</strong> \u6587\u4EF6\u5939\uFF0C\u7136\u540E\u70B9\u51FB\u4FDD\u5B58\u3002\u7A0D\u540E\u60A8\u5373\u53EF\u901A\u8FC7 <code>https://[github-account].github.io/[github-pj-name]/</code> \u8BBF\u95EE\u60A8\u7684\u6587\u6863\u7F51\u7AD9\u3002</p>\n<p>\u82E5\u8981\u5728\u4ED3\u5E93\u4E3B\u9875\u7684 About \u533A\u57DF\u663E\u793A\u6B64\u94FE\u63A5\uFF0C\u70B9\u51FB About \u65C1\u7684\u8BBE\u7F6E\u56FE\u6807 (\u9F7F\u8F6E)\uFF0C\u52FE\u9009 &quot;Use your GitHub Pages website&quot; \u5373\u53EF\u3002</p>\n';

  // apps/doc/web/src/markdown-built/zh/articles/lupine-components.html
  var lupine_components_default2 = '<h1 id="\u544A\u522B\u56DB\u5904\u627E\u8F6E\u5B50-\u53EA\u9700\u8981-7kb-\u5185\u6838-\u8FD9\u4E2A\u795E\u4ED9\u7EA7\u524D\u7AEF\u5F00\u6E90\u7EC4\u4EF6\u5E93\u5FC5\u987B\u6536\u85CF"><a class="header-anchor" href="#\u544A\u522B\u56DB\u5904\u627E\u8F6E\u5B50-\u53EA\u9700\u8981-7kb-\u5185\u6838-\u8FD9\u4E2A\u795E\u4ED9\u7EA7\u524D\u7AEF\u5F00\u6E90\u7EC4\u4EF6\u5E93\u5FC5\u987B\u6536\u85CF">#</a>\u544A\u522B\u56DB\u5904\u627E\u8F6E\u5B50\uFF01\u53EA\u9700\u8981 7kb \u5185\u6838\uFF0C\u8FD9\u4E2A\u795E\u4ED9\u7EA7\u524D\u7AEF\u5F00\u6E90\u7EC4\u4EF6\u5E93\u5FC5\u987B\u6536\u85CF</h1><p>\u65E5\u5E38\u7684\u524D\u7AEF\u5F00\u53D1\u4E2D\uFF0C\u6211\u4EEC\u5E38\u5E38\u9677\u5165\u8FD9\u6837\u7684\u5C34\u5C2C\u5883\u5730\uFF1A\u4E3A\u4E86\u5B9E\u73B0\u4E00\u4E2A\u5C0F\u5C0F\u7684\u4FA7\u8FB9\u62BD\u5C49\u83DC\u5355\uFF08Side Menu\uFF09\uFF0C\u6216\u8005\u4E00\u4E2A\u53EF\u62D6\u62FD\u7684\u5206\u5272\u9762\u677F\uFF08Splitter\uFF09\uFF0C\u6211\u4EEC\u4E0D\u5F97\u4E0D\u5F15\u5165\u5E9E\u5927\u7684 UI \u7EC4\u4EF6\u5E93\uFF08\u5982 Ant Design\u3001Element UI \u7B49\uFF09\uFF0C\u751A\u81F3\u56DB\u5904\u5BFB\u627E\u5E74\u4E45\u5931\u4FEE\u7684\u7B2C\u4E09\u65B9 npm \u5305\u62FC\u51D1\u3002\u9879\u76EE\u4F53\u79EF\u8D8A\u6765\u8D8A\u81C3\u80BF\uFF0C\u751A\u81F3\u4E0D\u540C\u5E93\u4E4B\u95F4\u7684\u6837\u5F0F\u8FD8\u4F1A\u6253\u67B6\u3002</p>\n<p>\u53EA\u6709 7kb \u5185\u6838\u7684 <strong>Lupine.js</strong>\uFF0C\u80FD\u7ED9\u60A8\u5E26\u6765\u54EA\u4E9B\u5F00\u53D1\u7684\u4FBF\u5229\u5462\uFF1F</p>\n<p><strong>Lupine.js</strong> \u662F\u4E00\u4E2A <strong>\u8F7B\u91CF\u7EA7</strong> \u7684 <strong>\u5168\u6808</strong> Web \u6846\u67B6\uFF0C\u5B83\u7ED3\u5408\u4E86 <strong>\u7C7B React</strong> \u7684\u524D\u7AEF\u4F53\u9A8C\u548C <strong>\u7C7B Express</strong> \u7684\u540E\u7AEF\u67B6\u6784\uFF0C\u65E8\u5728\u5B9E\u73B0\u6781\u81F4\u7684\u901F\u5EA6\u3001\u7B80\u6D01\u548C\u9AD8\u6548\u3002\u4E3A\u4E86\u52A0\u901F\u5F00\u53D1\u8005\u7684\u5F00\u53D1\u6548\u7387\uFF0CLupine.js \u9664\u4E86\u63D0\u4F9B\u4E86\u9875\u9762\u8DEF\u7531\u3001\u9ED1\u767D\u4E3B\u9898\u7B49\u5FC5\u5907\u529F\u80FD\uFF0C\u8FD8\u63D0\u4F9B\u4E86\u6781\u5176\u4E30\u5BCC\u4E14\u5F00\u7BB1\u5373\u7528\u7684\u7EC4\u4EF6\u5E93 \u2014\u2014 <strong>Lupine.components</strong>\u3002\u4E0D\u4EC5\u5168\u9762\u8986\u76D6\u4E86\u684C\u9762\u7AEF\uFF0C\u8FD8\u539F\u751F\u8003\u8651\u4E86\u79FB\u52A8\u7AEF\u7684\u5E38\u89C1\u4EA4\u4E92\u573A\u666F\u3002</p>\n<p>\u4ECA\u5929\uFF0C\u5C31\u5E26\u5927\u5BB6\u76D8\u70B9\u4E00\u4E0B Lupine.components \u91CC\u90A3\u4E9B\u8BA9\u4EBA\u76F8\u89C1\u6068\u665A\u7684\u201C\u5B9D\u85CF\u201D\u7EC4\u4EF6\u3002</p>\n<hr>\n<h2 id="\u6DB5\u76D6-90-\u65E5\u5E38\u4E1A\u52A1\u7684\u57FA\u7840\u4E0E\u8868\u5355\u7EC4\u4EF6"><a class="header-anchor" href="#\u6DB5\u76D6-90-\u65E5\u5E38\u4E1A\u52A1\u7684\u57FA\u7840\u4E0E\u8868\u5355\u7EC4\u4EF6">#</a>\u{1F3A8} \u6DB5\u76D6 90% \u65E5\u5E38\u4E1A\u52A1\u7684\u57FA\u7840\u4E0E\u8868\u5355\u7EC4\u4EF6</h2><p>\u4E0D\u518D\u9700\u8981\u5F15\u5165\u522B\u7684\u57FA\u7840 UI \u5E93\uFF0CLupine.js \u628A\u6700\u5E38\u7528\u7684\u7269\u6599\u90FD\u51C6\u5907\u597D\u4E86\u3002</p>\n<h3 id="1-\u7075\u6D3B\u7684\u8F93\u5165\u4E0E\u8868\u5355-form-input"><a class="header-anchor" href="#1-\u7075\u6D3B\u7684\u8F93\u5165\u4E0E\u8868\u5355-form-input">#</a>1. \u7075\u6D3B\u7684\u8F93\u5165\u4E0E\u8868\u5355 (Form &amp; Input)</h3><p><img src="/lupine.js/assets/components-input.png" alt="Lupine.Press"></p>\n<ul>\n<li>\u9664\u4E86\u5E38\u89C4\u7684\u5404\u79CD <code>Input</code>\uFF0C\u5B83\u8FD8\u5185\u7F6E\u4E86\u5F00\u7BB1\u5373\u7528\u7684<strong>\u6570\u5B57\u8F93\u5165\u6846 (Number Input)</strong>\u3001<strong>\u6807\u7B7E\u8F93\u5165\u6846 (Tag Input)</strong>\u3001\u548C<strong>\u641C\u7D22\u6846 (Search Input)</strong>\u3002</li>\n<li>\u5982\u679C\u4F60\u7684\u4E1A\u52A1\u9700\u8981\u590D\u6742\u7684\u7B5B\u9009\uFF0C\u5185\u7F6E\u7684 <strong>\u7EA7\u8054\u9009\u62E9\u5668 (Cascader)</strong>\u3001<strong>\u8303\u56F4\u9009\u62E9\u6761 (Range Input)</strong>\u3001\u751A\u81F3\u5E26\u6709\u4EEA\u8868\u76D8\u98CE\u683C\u7684 <strong>Gauge / Dial Input</strong> \u7EDD\u5BF9\u80FD\u8BA9\u4F60\u773C\u524D\u4E00\u4EAE\u3002</li>\n<li>\u8FD8\u6709\u8D34\u5FC3\u7684\u4E24\u79CD <strong>\u65F6\u95F4\u9009\u62E9\u5668 (Time Picker)</strong> \u548C <strong>\u65E5\u671F\u9009\u62E9\u5668 (Date Picker)</strong>\u3002</li>\n</ul>\n<h3 id="2-\u57FA\u7840\u7EC4\u4EF6\u5BB6\u65CF-basic-components"><a class="header-anchor" href="#2-\u57FA\u7840\u7EC4\u4EF6\u5BB6\u65CF-basic-components">#</a>2. \u57FA\u7840\u7EC4\u4EF6\u5BB6\u65CF (Basic Components)</h3><p>\u4E30\u5BCC\u7684\u6309\u94AE\u5F62\u6001\u4E0D\u8BF4\uFF0C\u50CF <strong>\u5FAE\u8C03\u5F00\u5173 (Toggle Switch/Button)</strong>\u3001<strong>\u5FBD\u6807 (Badge)</strong>\u3001<strong>\u52A0\u8F7D\u52A8\u753B (Spinner)</strong>\u3001<strong>\u661F\u7EA7\u6253\u5206 (Stars Input)</strong> \u90FD\u5728\u8FD9\u4E00\u5E94\u4FF1\u5168\u3002\u60F3\u8981\u5B9E\u73B0\u70B9\u51FB\u590D\u5236\u529F\u80FD\uFF1F\u5185\u7F6E\u4E86\u73B0\u6210\u7684 <strong>\u6587\u672C\u590D\u5236\u6309\u94AE (Copy Button)</strong>\u3002</p>\n<hr>\n<h2 id="\u539F\u751F\u7167\u987E\u79FB\u52A8\u7AEF-\u5BFC\u822A\u4E0E\u83DC\u5355-navigation-menu"><a class="header-anchor" href="#\u539F\u751F\u7167\u987E\u79FB\u52A8\u7AEF-\u5BFC\u822A\u4E0E\u83DC\u5355-navigation-menu">#</a>\u{1F4F1} \u539F\u751F\u7167\u987E\u79FB\u52A8\u7AEF\uFF1A\u5BFC\u822A\u4E0E\u83DC\u5355 (Navigation &amp; Menu)</h2><p>\u505A\u8FC7\u54CD\u5E94\u5F0F\u6216\u8005\u79FB\u52A8 Web \u7684\u540C\u5B66\u90FD\u77E5\u9053\uFF0C\u5199\u4E00\u4E2A\u4E1D\u6ED1\u5F39\u51FA\u7684\u5E95\u90E8\u83DC\u5355\u6709\u591A\u70E6\u3002</p>\n<p><img src="/lupine.js/assets/components-button.png" alt="Lupine.Press">\n<img src="/lupine.js/assets/components-badge.png" alt="Lupine.Press"></p>\n<ul>\n<li><strong>\u79FB\u52A8\u7AEF\u4E13\u5C5E</strong>\uFF1A\u5185\u7F6E\u4E86 <strong>App \u98CE\u683C\u4FA7\u6ED1\u83DC\u5355 (Mobile Side Menu)</strong>\u3001<strong>\u5E95\u90E8\u52A8\u4F5C\u9762\u677F (Action Sheet)</strong>\u3001\u548C\u57FA\u4E8E\u5E95\u90E8\u62BD\u5C49\u5F0F\u7684 <strong>\u5E26\u6807\u9898\u9009\u62E9\u5668 (Select With Title)</strong>\u3002</li>\n<li><strong>\u684C\u9762\u7AEF\u5229\u5668</strong>\uFF1A\u5E26\u6709\u4E30\u5BCC\u52A8\u6548\u7684 <strong>\u6ED1\u52A8\u6807\u7B7E\u9875 (Slide Tabs)</strong>\u3001\u652F\u6301\u5C42\u7EA7\u5C55\u793A\u7684 <strong>\u9762\u5305\u5C51 (Breadcrumbs)</strong>\u3001\u4EE5\u53CA\u968F\u5904\u53EF\u5F39\u7684 <strong>\u6D6E\u52A8\u83DC\u5355 (Floating Menu) \u548C \u6C14\u6CE1\u83DC\u5355 (Popup Menu)</strong>\u3002</li>\n</ul>\n<hr>\n<h2 id="\u6570\u636E\u4E0D\u6B62\u4E8E\u5C55\u793A-\u539F\u751F\u7684\u6570\u636E\u9762\u677F\u4E0E\u56FE\u8868-charts-data"><a class="header-anchor" href="#\u6570\u636E\u4E0D\u6B62\u4E8E\u5C55\u793A-\u539F\u751F\u7684\u6570\u636E\u9762\u677F\u4E0E\u56FE\u8868-charts-data">#</a>\u{1F4CA} \u6570\u636E\u4E0D\u6B62\u4E8E\u5C55\u793A\uFF1A\u539F\u751F\u7684\u6570\u636E\u9762\u677F\u4E0E\u56FE\u8868 (Charts &amp; Data)</h2><p>\u5F88\u591A\u65F6\u5019\u6211\u4EEC\u53EA\u662F\u60F3\u8981\u753B\u4E00\u4E2A\u7B80\u5355\u7684\u997C\u56FE\uFF0C\u5374\u4E0D\u5F97\u4E0D\u5F15\u5165 ECharts \u6216\u8005 Chart.js \u8FD9\u6837\u51E0\u767E KB \u7684\u5DE8\u65E0\u9738\u3002</p>\n<p><img src="/lupine.js/assets/components-chart.png" alt="Lupine.Press"></p>\n<ul>\n<li><strong>\u7EAF\u539F\u751F Charts \u56FE\u8868\u7EC4\u4EF6</strong>\uFF1ALupine.js \u76F4\u63A5\u5185\u7F6E\u4E86\u5E38\u7528\u7684\u56FE\u8868\uFF01\u65E0\u8BBA\u662F \u997C\u56FE(Pie)\u3001\u73AF\u5F62\u56FE(Donut)\u3001\u67F1\u72B6\u56FE(Column/Bar)\u3001\u6298\u7EBF\u56FE(Line)\u3001\u9762\u79EF\u56FE(Area)\u3001\u96F7\u8FBE\u56FE(Radar)\u3001\u751A\u81F3 \u6563\u70B9\u56FE(Scatter) \u548C \u4EEA\u8868\u56FE(Gauge)\uFF0C\u7EDF\u7EDF\u81EA\u5E26\u3002\u4E0D\u7528\u518D\u5916\u6302\u6C89\u91CD\u7684\u7B2C\u4E09\u65B9\u56FE\u8868\u5E93\uFF01</li>\n<li><strong>\u4E30\u5BCC\u7684\u6570\u636E\u5448\u73B0\u65B9\u5F0F</strong>\uFF1A\u4ECE\u57FA\u7840\u7684 <strong>\u5361\u7247 (Card)</strong>\u3001<strong>\u5934\u50CF (Avatar)</strong> \u5230\u590D\u6742\u7684 <strong>\u8F6E\u64AD\u56FE (Carousel)</strong>\u3001<strong>\u65F6\u95F4\u8F74 (Timeline)</strong>\uFF0C\u4E00\u5E94\u4FF1\u5168\u3002\u5982\u679C\u6570\u636E\u8FD8\u6CA1\u52A0\u8F7D\u5B8C\uFF1F\u9AA8\u67B6\u5C4F <strong>(Skeleton)</strong> \u4E5F\u5E2E\u4F60\u51C6\u5907\u597D\u4E86\u3002</li>\n<li><strong>\u5B9E\u7528\u591A\u5A92\u4F53\u7EC4\u4EF6</strong>\uFF1A\u4E0D\u4EC5\u6709\u7EBF\u6027\u7684<strong>\u8FDB\u5EA6\u6761 (Progress)</strong>\uFF0C\u8FD8\u6709\u73AF\u72B6\u8FDB\u5EA6\u6761 <strong>(Radial Progress)</strong>\u3002\u5982\u679C\u8981\u5728\u9875\u9762\u91CC\u5185\u5D4C\u89C6\u9891\u6216\u5730\u56FE\uFF0C\u76F4\u63A5\u4F7F\u7528\u73B0\u6210\u7684 <strong>YouTube \u64AD\u653E\u5668 (YouTube Player)</strong> \u548C <strong>Google \u5730\u56FE\u5305\u88C5\u5668 (Google Map Wrapper)</strong>\u3002\u5BF9\u4E86\uFF0C\u5B83\u751A\u81F3\u81EA\u5E26\u4E8C\u7EF4\u7801\u751F\u6210\u7EC4\u4EF6 <strong>(QR Code Generator)</strong>\uFF01</li>\n</ul>\n<hr>\n<h2 id="\u5F00\u53D1\u63D0\u6548\u6838\u5F39-\u91CD\u578B-\u7F16\u8F91\u5668\u4E0E\u6D6E\u5C42\u7CFB\u7EDF"><a class="header-anchor" href="#\u5F00\u53D1\u63D0\u6548\u6838\u5F39-\u91CD\u578B-\u7F16\u8F91\u5668\u4E0E\u6D6E\u5C42\u7CFB\u7EDF">#</a>\u{1F6E0} \u5F00\u53D1\u63D0\u6548\u6838\u5F39\uFF1A\u201C\u91CD\u578B\u201D\u7F16\u8F91\u5668\u4E0E\u6D6E\u5C42\u7CFB\u7EDF</h2><p>\u666E\u901A\u7684 UI \u5E93\u901A\u5E38\u53EA\u63D0\u4F9B\u57FA\u7840\u96F6\u6563\u7684\u79EF\u6728\u7EC4\u4EF6\uFF0C\u4F46 Lupine.components \u91CC\u85CF\u7740\u597D\u51E0\u4E2A\u80FD\u76F4\u63A5\u5F53\u4F5C\u72EC\u7ACB\u5E94\u7528\u4EA4\u4ED8\u7684\u201C\u5927\u6740\u5668\u201D\u3002</p>\n<p><img src="/lupine.js/assets/components-heditor.png" alt="Lupine.Press">\n<img src="/lupine.js/assets/components-ieditor.png" alt="Lupine.Press"></p>\n<ul>\n<li><p><strong>\u7F16\u8F91\u5668\u4E09\u677F\u65A7 (Editors &amp; Viewers)</strong>\uFF1A</p>\n<ul>\n<li><strong>\u5BCC\u6587\u672C HTML \u7F16\u8F91\u5668 (Rich Text Editor)</strong>\uFF1A\u8F7B\u91CF\u597D\u7528\uFF0C\u8BE5\u6709\u7684\u6392\u7248\u529F\u80FD\u90FD\u6709\u3002</li>\n<li><strong>\u5F3A\u5927\u7684\u56FE\u7247\u7F16\u8F91\u5668 (Image Editor)</strong>\uFF1A\u652F\u6301\u88C1\u526A\u3001\u65CB\u8F6C\u3001\u753B\u7B14\u6D82\u9E26\u3001\u52A0\u8D34\u7EB8\u548C\u5199\u5B57\u3002</li>\n<li><strong>PDF \u4F53\u7CFB</strong>\uFF1A\u4E0D\u4EC5\u6709\u7528\u4E8E\u6D4F\u89C8 PDF \u7684 <strong>PDF Viewer</strong>\uFF0C\u751A\u81F3\u8FD8\u5185\u7F6E\u4E86\u80FD\u591F\u62C6\u89E3\u7EC4\u5408 PDF \u9875\u9762\u7684 <strong>PDF Editor</strong>\uFF01</li>\n</ul>\n</li>\n<li><p><strong>\u5168\u573A\u666F\u6D6E\u5C42\u4E0E\u53CD\u9988 (Overlays &amp; Feedback)</strong>\uFF1A</p>\n<ul>\n<li><strong>\u6A21\u6001\u5F39\u7A97 (Modal Window)</strong>\u3001<strong>\u7CFB\u7EDF\u7EA7\u6D88\u606F\u63D0\u793A (Message Box / Notice Message)</strong> \u662F\u6807\u914D\u3002</li>\n<li>\u8FDE\u957F\u5217\u8868\u5E38\u89C1\u7684 <strong>\u4E0B\u62C9\u5237\u65B0 (Pull to Refresh)</strong>\u3001\u4EE5\u53CA\u5F15\u5BFC\u7528\u6237\u719F\u6089\u5E94\u7528\u529F\u80FD\u7684 <strong>\u4EA7\u54C1\u5BFC\u89C8\u7EC4\u4EF6 (Tour)</strong> \u4E5F\u65E0\u9700\u518D\u53BB npm \u5927\u6D77\u635E\u9488\u3002</li>\n</ul>\n</li>\n<li><p><strong>\u590D\u6742\u5E03\u5C40\u6846\u67B6 (Layout &amp; Frames)</strong>\uFF1A</p>\n<ul>\n<li>\u5199\u8FC7\u4E2D\u540E\u53F0\u7BA1\u7406\u7CFB\u7EDF\u7684\u90FD\u61C2\uFF0C\u600E\u4E48\u8BA9\u4FA7\u8FB9\u680F\u53EF\u62D6\u52A8\u6539\u53D8\u5BBD\u5EA6\uFF1F<strong>\u53EF\u62D6\u62FD\u5206\u5272\u9762\u677F (Resizable Splitter)</strong> \u5B8C\u7F8E\u89E3\u51B3\u3002</li>\n<li>\u9700\u8981\u56FA\u5B9A\u5BBD\u9AD8\u6BD4\u94FA\u6EE1\u5C4F\u5E55\uFF1F\u7528 <strong>\u7EB5\u6A2A\u6BD4\u7EC4\u4EF6 (Aspect Ratio)</strong> \u8F7B\u677E\u641E\u5B9A\u3002\u8FD8\u6709\u5404\u79CD\u57FA\u4E8E Tab \u6216 Slide \u673A\u5236\u7684\u54CD\u5E94\u5F0F Frame \u6A21\u7248\u4EFB\u4F60\u6311\u9009\u3002</li>\n<li>\u89C9\u5F97\u9875\u9762\u6587\u5B57\u592A\u5E73\u6DE1\uFF1F\u5C1D\u8BD5\u4E00\u4E0B\u5185\u7F6E\u7279\u6548\u5DE5\u5177\uFF1A\u6587\u5B57\u6CE2\u6D6A\u7FFB\u6EDA <strong>(Text Wave)</strong>\u3001\u6D41\u5149\u6548\u679C <strong>(Text Glow)</strong> \u4EE5\u53CA \u7F29\u653E\u52A8\u6548 <strong>(Text Scale)</strong>\u3002</li>\n</ul>\n</li>\n</ul>\n<hr>\n<h2 id="\u603B\u7ED3-\u4E3A\u4EC0\u4E48\u4F60\u5E94\u8BE5\u8BD5\u8BD5-lupine-js"><a class="header-anchor" href="#\u603B\u7ED3-\u4E3A\u4EC0\u4E48\u4F60\u5E94\u8BE5\u8BD5\u8BD5-lupine-js">#</a>\u{1F31F} \u603B\u7ED3\uFF1A\u4E3A\u4EC0\u4E48\u4F60\u5E94\u8BE5\u8BD5\u8BD5 Lupine.js</h2><p>\u4EE5\u4E0A\u63D0\u53CA\u7684\u8FD9\u6D77\u91CF\u7EC4\u4EF6\uFF0C\u7EDD\u5927\u591A\u6570\u5E93\u5149\u662F\u6253\u5305\u4F53\u79EF\u53EF\u80FD\u5C31\u5DF2\u7ECF\u4E0A MB \u4E86\u3002\u4F46\u7531\u4E8E <strong>Lupine.js</strong> \u672C\u8EAB\u5185\u6838\uFF08\u4E0D\u542B\u7EC4\u4EF6\uFF09\u4E0D\u8FC7 7kb \u5DE6\u53F3\uFF0C\u5373\u4F7F\u662F\u52A0\u8F7D\u8FD9\u4E9B\u590D\u6742\u7684\u7EC4\u4EF6\uFF0C\u4E5F\u4F9D\u7136\u4FDD\u6301\u7740\u6781\u4E3A\u5F3A\u608D\u7684\u6E32\u67D3\u6027\u80FD\u3002\u800C\u4E14\u6253\u5305\u65F6\u53EA\u5305\u542B\u4F60\u5B9E\u9645\u7528\u5230\u7684\u7EC4\u4EF6\uFF0C\u4E0D\u4F1A\u5BFC\u81F4\u4F53\u79EF\u81A8\u80C0\u3002</p>\n<p>\u4F60\u53EF\u4EE5\u5728\u4EFB\u4F55\u73B0\u6709\u7684\u9879\u76EE\u4E2D\u5355\u72EC\u5C06\u90E8\u5206\u7EC4\u4EF6\u62BD\u51FA\u6765\u4F7F\u7528\uFF0C\u4E5F\u53EF\u4EE5\u5E72\u8106\u4EE5\u5B83\u4E3A\u57FA\u7840\uFF0C\u4F7F\u7528\u811A\u624B\u67B6\u5FEB\u901F\u642D\u5EFA\u4F60\u81EA\u5DF1\u7684\u9AD8\u6027\u80FD\u591A\u6A21\u6001\u5168\u6808\u5E94\u7528\u3002</p>\n<p>\u5982\u679C\u4F60\u7ECF\u5E38\u4E3A\u4E86\u627E\u4E00\u4E2A\u9002\u5408\u7684\u5C0F\u7EC4\u4EF6\u800C\u53D1\u6101\uFF0C\u6216\u8005\u4F60\u60F3\u5728\u5F00\u53D1\u4E1A\u52A1\u7684\u65F6\u5019\u6446\u8131\u7E41\u6742\u5197\u4F59\u7684\u4EE3\u7801\uFF0C\u90A3\u4E48\u4E0D\u59A8\u7ED9 Lupine.js \u4E00\u4E2A\u673A\u4F1A\u3002</p>\n<hr>\n<p><strong>\u5FEB\u901F\u4F53\u9A8C\uFF0C\u773C\u89C1\u4E3A\u5B9E\uFF1A</strong></p>\n<ul>\n<li>\u{1F3AE} <strong>Lupine.components \u6240\u6709\u7EC4\u4EF6\u5728\u7EBF\u6F14\u793A</strong>\uFF1A<a href="https://uuware.github.io/lupine.js/?redirect=/lupine.js/demo">https://uuware.github.io/lupine.js/demo</a></li>\n<li>\u{1F4BB} <strong>\u6E90\u7801\u4ED3\u5E93\u4E0E\u6587\u6863 (GitHub)</strong>\uFF1A<a href="https://github.com/uuware/lupine.js">https://github.com/uuware/lupine.js</a></li>\n</ul>\n<blockquote>\n<p>\u{1F4A1} \u5F00\u6E90\u4E0D\u6613\uFF0C\u5982\u679C\u4F60\u4E5F\u89C9\u5F97\u8FD9\u4E2A\u5168\u6808\u6846\u67B6\u6709\u610F\u601D\uFF0C\u6B22\u8FCE\u6765 GitHub \u4ED3\u5E93\u70B9\u4E0A\u4E00\u9897 \u2B50 <strong>Star</strong>\uFF01\u8FD9\u662F\u5BF9\u5F00\u6E90\u521B\u4F5C\u8005\u6700\u68D2\u7684\u9F13\u52B1\uFF01</p>\n</blockquote>\n';

  // apps/doc/web/src/markdown-built/zh/articles/lupine-image-editor.html
  var lupine_image_editor_default2 = '<h1 id="\u524D\u7AEF\u4E5F\u80FD\u8F7B\u677E\u63A5\u624B-\u91CD\u6D3B-lupine-image-editor-\u5F00\u6E90\u56FE\u7247\u7F16\u8F91\u5668\u4F53\u9A8C"><a class="header-anchor" href="#\u524D\u7AEF\u4E5F\u80FD\u8F7B\u677E\u63A5\u624B-\u91CD\u6D3B-lupine-image-editor-\u5F00\u6E90\u56FE\u7247\u7F16\u8F91\u5668\u4F53\u9A8C">#</a>\u524D\u7AEF\u4E5F\u80FD\u8F7B\u677E\u63A5\u624B\u201C\u91CD\u6D3B\u201D\uFF1FLupine Image Editor \u5F00\u6E90\u56FE\u7247\u7F16\u8F91\u5668\u4F53\u9A8C</h1><p>\u5728\u524D\u7AEF\u5F00\u53D1\u4E2D\uFF0C\u5982\u679C\u6709\u4EA7\u54C1\u7ECF\u7406\u8D70\u8FC7\u6765\u548C\u4F60\u8BF4\uFF1A\u201C\u6211\u4EEC\u9700\u8981\u5728\u7F51\u9875\u91CC\u52A0\u4E0A\u4E00\u4E2A\u56FE\u7247\u7F16\u8F91\u5668\uFF0C\u80FD\u88C1\u526A\u3001\u6D82\u9E26\u3001\u52A0\u6587\u5B57\u3001\u52A0\u8D34\u7EB8\u5C31\u884C\u2026\u2026\u5BF9\u4E86\uFF0C\u8981\u8F7B\u91CF\u4E00\u70B9\uFF0C\u522B\u5F15\u5165\u592A\u5927\u7684\u5E93\u3002\u201D \u76F8\u4FE1\u5F88\u591A\u524D\u7AEF\u540C\u5B66\u5FC3\u91CC\u90FD\u4F1A\u201C\u54AF\u5654\u201D\u4E00\u4E0B\u3002</p>\n<p>\u56FE\u7247\u5904\u7406\u3001Canvas \u72B6\u6001\u7BA1\u7406\u3001\u64A4\u9500/\u91CD\u505A\u903B\u8F91\u3001\u4EE5\u53CA\u90A3\u4E00\u5806\u590D\u6742\u7684\u5DE5\u5177\u680F UI\uFF0C\u4ECE\u5934\u624B\u6413\u7B80\u76F4\u662F\u5669\u68A6\u3002\u800C\u5E02\u9762\u4E0A\u6210\u719F\u7684\u5E93\u5F80\u5F80\u4F53\u79EF\u5E9E\u5927\uFF0C\u6216\u8005\u4E0E\u73B0\u6709\u7684\u6846\u67B6\uFF08\u6BD4\u5982 React/Vue\uFF09\u96BE\u4EE5\u65E0\u7F1D\u878D\u5408\u3002</p>\n<p>\u4ECA\u5929\uFF0C\u7ED9\u5927\u5BB6\u63A8\u8350\u4E00\u4E2A\u57FA\u4E8E <strong>Lupine.js</strong> \u6784\u5EFA\u7684\u5F00\u6E90\u8F7B\u91CF\u7EA7\u56FE\u7247\u7F16\u8F91\u5E94\u7528\u6A21\u677F \u2014\u2014 <strong>Lupine Image Editor</strong>\u3002\u5B83\u4E0D\u4EC5\u529F\u80FD\u9F50\u5168\uFF0C\u800C\u4E14\u5F97\u76CA\u4E8E Lupine.js \u7684\u8D85\u8F7B\u91CF\u7279\u6027\uFF0C\u6027\u80FD\u6781\u5176\u4F18\u5F02\u3002</p>\n<hr>\n<h2 id="\u6838\u5FC3\u529F\u80FD\u4EAE\u70B9\u901F\u89C8"><a class="header-anchor" href="#\u6838\u5FC3\u529F\u80FD\u4EAE\u70B9\u901F\u89C8">#</a>\u{1F3A8} \u6838\u5FC3\u529F\u80FD\u4EAE\u70B9\u901F\u89C8</h2><p>Lupine Image Editor \u81F4\u529B\u4E8E\u5728\u6D4F\u89C8\u5668\u4E2D\u63D0\u4F9B\u6D41\u7545\u7684\u56FE\u7247\u64CD\u4F5C\u4F53\u9A8C\u3002\u4F60\u53EF\u4EE5\u6BEB\u4E0D\u8D39\u529B\u5730\u628A\u5B83\u4F5C\u4E3A\u4E00\u4E2A\u72EC\u7ACB\u5E94\u7528\uFF0C\u6216\u8005\u76F4\u63A5\u62BD\u53D6\u5176\u4E2D\u7684\u6838\u5FC3\u7EC4\u4EF6 <code>iEditor</code> \u5D4C\u5165\u5230\u4F60\u81EA\u5DF1\u7684\u4E1A\u52A1\u9879\u76EE\u4E2D\u3002</p>\n<h3 id="1-\u753B\u5E03\u57FA\u7840\u64CD\u4F5C"><a class="header-anchor" href="#1-\u753B\u5E03\u57FA\u7840\u64CD\u4F5C">#</a>1. \u{1F5BC}\uFE0F \u753B\u5E03\u57FA\u7840\u64CD\u4F5C</h3><p>\u652F\u6301\u76F4\u63A5\u4E0A\u4F20\u672C\u5730\u56FE\u7247\u8FDB\u884C\u7F16\u8F91\uFF0C\u6216\u8005\u65B0\u5EFA\u4E00\u4E2A\u7EAF\u8272/\u900F\u660E\u7684\u7A7A\u767D\u753B\u5E03\u3002\u6240\u6709\u7684\u64CD\u4F5C\u90FD\u5728\u524D\u7AEF\u79BB\u7EBF\u5B8C\u6210\uFF0C\u4FDD\u62A4\u7528\u6237\u9690\u79C1\u7684\u540C\u65F6\uFF0C\u4FDD\u8BC1\u4E86\u201C\u4E1D\u6ED1\u201D\u7684\u54CD\u5E94\u901F\u5EA6\u3002</p>\n<h3 id="2-\u88C1\u526A-\u7F29\u653E\u4E0E\u65CB\u8F6C"><a class="header-anchor" href="#2-\u88C1\u526A-\u7F29\u653E\u4E0E\u65CB\u8F6C">#</a>2. \u2702\uFE0F \u88C1\u526A\u3001\u7F29\u653E\u4E0E\u65CB\u8F6C</h3><p><img src="/lupine.js/assets/ieditor-rotate.png" alt="Lupine.Press"></p>\n<p>\u6DB5\u76D6\u4E86\u56FE\u7247\u7F16\u8F91\u6700\u521A\u9700\u7684\u529F\u80FD\uFF1A</p>\n<ul>\n<li><strong>\u81EA\u7531\u88C1\u526A</strong>\u4E0E<strong>\u6309\u6BD4\u4F8B\u88C1\u526A</strong>\uFF1A\u62D6\u62FD\u9009\u6846\uFF0C\u968F\u5FC3\u6784\u56FE\u3002</li>\n<li><strong>\u65CB\u8F6C\u4E0E\u955C\u50CF\u7FFB\u8F6C</strong>\uFF1A\u4E00\u952E\u8C03\u6574\u56FE\u7247\u5230\u6B63\u786E\u7684\u65B9\u5411\u3002</li>\n<li><strong>\u4EFB\u610F\u7F29\u653E</strong>\uFF1A\u4E0D\u4E22\u5931\u6838\u5FC3\u7EC6\u8282\u3002</li>\n</ul>\n<h3 id="3-\u81EA\u7531\u6D82\u9E26\u4E0E\u5F3A\u5927\u5F62\u72B6\u5DE5\u5177"><a class="header-anchor" href="#3-\u81EA\u7531\u6D82\u9E26\u4E0E\u5F3A\u5927\u5F62\u72B6\u5DE5\u5177">#</a>3. \u270F\uFE0F \u81EA\u7531\u6D82\u9E26\u4E0E\u5F3A\u5927\u5F62\u72B6\u5DE5\u5177</h3><p><img src="/lupine.js/assets/ieditor-draw.png" alt="Lupine.Press"></p>\n<p>\u5185\u7F6E\u4E86\u5B8C\u5584\u7684\u7ED8\u56FE\u7CFB\u7EDF\uFF1A</p>\n<ul>\n<li><strong>\u94C5\u7B14\u5DE5\u5177</strong>\uFF1A\u652F\u6301\u81EA\u7531\u624B\u7ED8\uFF0C\u505A\u6807\u8BB0\u3001\u5199\u5B57\u975E\u5E38\u65B9\u4FBF\u3002</li>\n<li><strong>\u51E0\u4F55\u5F62\u72B6</strong>\uFF1A\u5185\u7F6E\u76F4\u7EBF\u3001\u7BAD\u5934\u3001\u77E9\u5F62\u3001\u5706\u5F62\u3001\u692D\u5706\u7B49\u5E38\u7528\u5F62\u72B6\u3002</li>\n<li><strong>\u6837\u5F0F\u81EA\u5B9A\u4E49</strong>\uFF1A\u4F60\u53EF\u4EE5\u81EA\u7531\u8C03\u6574\u7EBF\u6761\u7C97\u7EC6\u3001\u989C\u8272\u3001\u751A\u81F3\u900F\u660E\u5EA6\uFF0C\u6EE1\u8DB3\u5404\u79CD\u6279\u6CE8\u548C\u4F5C\u56FE\u9700\u6C42\u3002</li>\n</ul>\n<h3 id="4-\u4E30\u5BCC\u7684\u6587\u5B57\u4E0E\u8D34\u7EB8\u5957\u4EF6"><a class="header-anchor" href="#4-\u4E30\u5BCC\u7684\u6587\u5B57\u4E0E\u8D34\u7EB8\u5957\u4EF6">#</a>4. \u{1F4DD} \u4E30\u5BCC\u7684\u6587\u5B57\u4E0E\u8D34\u7EB8\u5957\u4EF6</h3><p><img src="/lupine.js/assets/ieditor-text.png" alt="Lupine.Press"></p>\n<p>\u7ED9\u56FE\u7247\u52A0\u70B9\u201C\u7075\u9B42\u201D\uFF1A</p>\n<ul>\n<li><strong>\u6587\u672C\u8F93\u5165</strong>\uFF1A\u652F\u6301\u591A\u884C\u6587\u672C\u8F93\u5165\uFF0C\u81EA\u7531\u8C03\u6574\u5B57\u4F53\u989C\u8272\u3001\u80CC\u666F\u8272\u548C\u5927\u5C0F\u3002\u70B9\u54EA\u91CC\u5199\u54EA\u91CC\u3002</li>\n<li><strong>\u8D34\u7EB8\u529F\u80FD</strong>\uFF1A\u5185\u7F6E\u4E30\u5BCC\u7684\u8868\u60C5\u548C\u6807\u7B7E\u8D34\u7EB8\uFF0C\u4E0D\u4EC5\u80FD\u8BA9\u56FE\u7247\u66F4\u6709\u8DA3\uFF0C\u8FD8\u80FD\u7528\u4E8E\u4EA7\u54C1\u6F14\u793A\u56FE\u7684\u906E\u6321\u4E0E\u6807\u6CE8\u3002</li>\n</ul>\n<h3 id="5-\u5386\u53F2\u8BB0\u5F55-\u64A4\u9500-\u91CD\u505A"><a class="header-anchor" href="#5-\u5386\u53F2\u8BB0\u5F55-\u64A4\u9500-\u91CD\u505A">#</a>5. \u23F3 \u5386\u53F2\u8BB0\u5F55\uFF08\u64A4\u9500/\u91CD\u505A\uFF09</h3><p>\u624B\u6ED1\u753B\u9519\u4E86\uFF1F\u4E0D\u5B58\u5728\u7684\u3002\u7F16\u8F91\u5668\u5185\u7F6E\u4E86\u5B8C\u6574\u7684\u64A4\u9500\uFF08Undo\uFF09\u4E0E\u91CD\u505A\uFF08Redo\uFF09\u6808\uFF0C\u8BA9\u4F60\u53EF\u4EE5\u653E\u5FC3\u5927\u80C6\u5730\u8FDB\u884C\u4EFB\u4F55\u5C1D\u8BD5\u3002</p>\n<hr>\n<h2 id="\u4E3A\u4EC0\u4E48\u9009\u62E9\u57FA\u4E8E-lupine-js"><a class="header-anchor" href="#\u4E3A\u4EC0\u4E48\u9009\u62E9\u57FA\u4E8E-lupine-js">#</a>\u{1F680} \u4E3A\u4EC0\u4E48\u9009\u62E9\u57FA\u4E8E Lupine.js\uFF1F</h2><p>\u53EF\u80FD\u6709\u4E9B\u540C\u5B66\u4F1A\u95EE\uFF0C<strong>Lupine.js</strong> \u662F\u4EC0\u4E48\uFF1F</p>\n<p>Lupine.js \u662F\u4E00\u4E2A <strong>\u517C\u5177 React \u822C\u524D\u7AEF\u4F53\u9A8C \u4E0E Express \u822C\u540E\u7AEF\u80FD\u529B</strong> \u7684\u5168\u6808\u8D85\u8F7B\u91CF Web \u6846\u67B6\u3002\u5B83\u7684\u6838\u5FC3\u538B\u7F29\u540E\u4EC5\u4EC5\u53EA\u6709 <strong>7kb</strong>\uFF0C\u4F46\u5374\u539F\u751F\u63D0\u4F9B\u4E86\uFF1A</p>\n<ul>\n<li>\u5B8C\u6574\u7684\u7EC4\u4EF6\u5316\u5F00\u53D1\uFF08TSX \u652F\u6301\uFF09</li>\n<li>\u7EC6\u7C92\u5EA6\u7684\u72B6\u6001\u54CD\u5E94\u5F0F\u7CFB\u7EDF</li>\n<li>\u5F00\u7BB1\u5373\u7528\u7684 CSS-in-JS \u4E0E\u4E3B\u9898\u5207\u6362</li>\n<li>SSR\uFF08\u670D\u52A1\u7AEF\u6E32\u67D3\uFF09\u4E0E\u6587\u4EF6\u7CFB\u7EDF\u8DEF\u7531</li>\n</ul>\n<p>\u56E0\u4E3A\u6CA1\u6709\u643A\u5E26\u6C89\u91CD\u7684\u865A\u62DF DOM \u548C\u590D\u6742\u7684\u8C03\u5EA6\u5668\u5386\u53F2\u5305\u88B1\uFF0C\u5728 Lupine.js \u4E4B\u4E0A\u6784\u5EFA\u590D\u6742\u7684\u5BCC\u4EA4\u4E92\u5E94\u7528\uFF08\u5982\u56FE\u5F62\u7F16\u8F91\u5668\u3001\u5404\u79CD\u56FE\u8868\u7B49\uFF09\uFF0C\u6027\u80FD\u8868\u73B0\u5C24\u4E3A\u7A81\u51FA\u3002</p>\n<p>\u800C <code>Lupine Image Editor</code> \u4EC5\u4EC5\u662F Lupine \u4E30\u5BCC\u7EC4\u4EF6\u5E93 <code>Lupine.components</code> \u4E2D\u7684\u51B0\u5C71\u4E00\u89D2\u3002</p>\n<hr>\n<h2 id="\u5982\u4F55\u5FEB\u901F\u4F53\u9A8C"><a class="header-anchor" href="#\u5982\u4F55\u5FEB\u901F\u4F53\u9A8C">#</a>\u{1F4E6} \u5982\u4F55\u5FEB\u901F\u4F53\u9A8C\uFF1F</h2><p>\u767E\u95FB\u4E0D\u5982\u4E00\u8BD5\uFF0C\u4F60\u53EF\u4EE5\u76F4\u63A5\u901A\u8FC7\u4EE5\u4E0B\u94FE\u63A5\u5728\u7EBF\u4F53\u9A8C\uFF0C\u6216\u8005\u4E00\u952E\u521D\u59CB\u5316\u5230\u672C\u5730\uFF1A</p>\n<ul>\n<li>\u{1F3AE} <strong>\u5728\u7EBF Live Demo</strong>\uFF1A<a href="https://uuware.github.io/lupine-image-editor/">https://uuware.github.io/lupine-image-editor/</a></li>\n<li>\u{1F4BB} <strong>\u6E90\u7801\u4ED3\u5E93 (GitHub)</strong>\uFF1A<a href="https://github.com/uuware/lupine-image-editor">https://github.com/uuware/lupine-image-editor</a></li>\n</ul>\n<p><strong>\u672C\u5730\u4E00\u952E\u521D\u59CB\u5316\uFF1A</strong></p>\n<p>\u514B\u9686\u9879\u76EE\u540E\uFF0C\u4F60\u53EF\u4EE5\u5728\u4E00\u5206\u949F\u5185\u628A\u8FD9\u4E2A\u56FE\u7247\u7F16\u8F91\u5668\u8DD1\u5728\u4F60\u7684\u672C\u5730\uFF1A</p>\n<pre><code class="language-bash">npm install\nnpm run dev\n</code></pre>\n<hr>\n<h2 id="\u7ED3\u8BED"><a class="header-anchor" href="#\u7ED3\u8BED">#</a>\u7ED3\u8BED</h2><p>\u5982\u679C\u4F60\u6B63\u5728\u5BFB\u627E\u4E00\u4E2A\u8F7B\u91CF\u7EA7\u3001\u65E0\u4F9D\u8D56\u5305\u88B1\u7684\u7F51\u9875\u7AEF\u56FE\u7247\u7F16\u8F91\u5668\uFF0C\u6216\u8005\u4F60\u5BF9\u8FD9\u5957\u62E5\u6709 7kb \u6781\u7B80\u5185\u6838\u7684 <strong>Lupine.js</strong> \u6846\u67B6\u611F\u5174\u8DA3\uFF0C\u4E0D\u59A8\u70B9\u8FDB\u9879\u76EE\u53BB\u770B\u770B\u6E90\u7801\u3002</p>\n<blockquote>\n<p>\u{1F308} \u5F00\u6E90\u4E0D\u6613\uFF0C\u5982\u679C\u8FD9\u4E2A\u9879\u76EE\u6709\u5E2E\u52A9\u5230\u4F60\uFF0C\u6B22\u8FCE\u5728 <a href="https://github.com/uuware/lupine.js">GitHub - Lupine.js</a> \u7559\u4E0B\u4F60\u7684 \u2B50 <strong>Star</strong>\uFF01\u8FD9\u4F1A\u662F\u5BF9\u4F5C\u8005\u6700\u5927\u7684\u9F13\u52B1\uFF01</p>\n</blockquote>\n';

  // apps/doc/web/src/markdown-built/zh/articles/ssr-comparison.html
  var ssr_comparison_default2 = '<p>\u670D\u52A1\u7AEF\u6E32\u67D3 (SSR) \u5DF2\u7ECF\u4ECE\u901A\u8FC7 SEO \u9526\u4E0A\u6DFB\u82B1\u7684\u201C\u53EF\u9009\u9879\u201D\uFF0C\u53D8\u6210\u4E86\u73B0\u4EE3 Web \u67B6\u6784\u4E2D\u63D0\u5347\u6027\u80FD\u548C\u7528\u6237\u4F53\u9A8C\u7684\u201C\u5FC5\u9009\u9879\u201D\u3002</p>\n<p>\u5728 2026 \u5E74\uFF0C\u5F00\u53D1\u8005\u901A\u5E38\u4F1A\u9996\u9009 <strong>Next.js</strong> (React \u751F\u6001) \u6216 <strong>Angular SSR</strong> (\u524D\u8EAB\u662F Universal)\u3002\u4F46\u662F\uFF0C\u8FD9\u4E9B\u91CD\u91CF\u7EA7\u6846\u67B6\u4E0E\u50CF <strong>Lupine.js</strong> \u8FD9\u6837\u4E13\u4E3A\u6027\u80FD\u6253\u9020\u7684\u8F7B\u91CF\u7EA7\u6846\u67B6\u76F8\u6BD4\uFF0C\u7A76\u7ADF\u8868\u73B0\u5982\u4F55\uFF1F</p>\n<p>\u672C\u6587\u5C06\u6DF1\u5EA6\u89E3\u6790\u5B83\u4EEC\u5728\u67B6\u6784\u8BBE\u8BA1\u3001\u6C34\u5408 (Hydration) \u6210\u672C\u4EE5\u53CA\u5F00\u53D1\u4F53\u9A8C\u4E0A\u7684\u5DEE\u5F02\u3002</p>\n<p><img src="/lupine.js/assets/ssr.png" alt="Lupine.js Architecture"></p>\n<h2 id="1-\u6E32\u67D3\u67B6\u6784\u5BF9\u6BD4"><a class="header-anchor" href="#1-\u6E32\u67D3\u67B6\u6784\u5BF9\u6BD4">#</a>1. \u6E32\u67D3\u67B6\u6784\u5BF9\u6BD4</h2><h3 id="react-next-js-remix"><a class="header-anchor" href="#react-next-js-remix">#</a>React (Next.js/Remix)</h3><p>React \u672C\u8EAB\u53EA\u662F\u4E00\u4E2A UI \u5E93\u3002\u8981\u5B9E\u73B0 SSR\uFF0C\u4F60\u901A\u5E38\u9700\u8981\u5F15\u5165\u4E00\u4E2A\u5143\u6846\u67B6 (Meta-framework)\u3002</p>\n<ul>\n<li><strong>\u673A\u5236</strong>: \u670D\u52A1\u7AEF\u5C06\u7EC4\u4EF6\u6811\u6E32\u67D3\u6210 HTML \u5B57\u7B26\u4E32\u3002</li>\n<li><strong>\u6210\u672C</strong>: \u5728\u5BA2\u6237\u7AEF\uFF0CReact \u5FC5\u987B\u4E0B\u8F7D\u5B8C\u6574\u7684 JS \u5305\uFF0C\u91CD\u65B0\u8FD0\u884C\u7EC4\u4EF6\u903B\u8F91\u4EE5\u6784\u5EFA\u865A\u62DF DOM (VDOM)\uFF0C\u7136\u540E\u8FDB\u884C\u201C\u6C34\u5408\u201D (Hydrate) \u2014\u2014 \u5373\u628A\u4E8B\u4EF6\u76D1\u542C\u5668\u6302\u8F7D\u5230\u73B0\u6709\u7684 HTML \u4E0A\u3002</li>\n<li><strong>\u6F14\u8FDB</strong>: React \u670D\u52A1\u7AEF\u7EC4\u4EF6 (RSC) \u901A\u8FC7\u4FDD\u7559\u90E8\u5206\u903B\u8F91\u5728\u670D\u52A1\u7AEF\u6765\u51CF\u5C11\u5305\u4F53\u79EF\uFF0C\u4F46\u968F\u4E4B\u800C\u6765\u7684\u662F\u6D41\u5F0F\u4F20\u8F93\u3001Suspense \u8FB9\u754C\u4EE5\u53CA\u5BA2\u6237\u7AEF/\u670D\u52A1\u7AEF\u7EC4\u4EF6\u62C6\u5206\u7684\u9AD8\u590D\u6742\u5EA6\u3002</li>\n</ul>\n<h3 id="angular-ssr-modern-hydration"><a class="header-anchor" href="#angular-ssr-modern-hydration">#</a>Angular (SSR / Modern Hydration)</h3><p>Angular \u5DF2\u7ECF\u8F6C\u5411\u201C\u975E\u7834\u574F\u6027\u6C34\u5408\u201D\u548C\u90E8\u5206\u6C34\u5408\u3002</p>\n<ul>\n<li><strong>\u673A\u5236</strong>: Angular \u4F7F\u7528 TransferState \u5E8F\u5217\u5316\u72B6\u6001\u4F20\u8F93\uFF0C\u907F\u514D\u5BA2\u6237\u7AEF\u91CD\u590D\u8BF7\u6C42\u6570\u636E\u3002</li>\n<li><strong>\u6210\u672C</strong>: \u5386\u53F2\u4E0A\uFF0CAngular SSR \u4F1A\u5BFC\u81F4\u201C\u95EA\u70C1\u201D\uFF0C\u56E0\u4E3A\u5B83\u4F1A\u9500\u6BC1\u670D\u52A1\u7AEF HTML \u5E76\u91CD\u65B0\u6E32\u67D3\u3002\u73B0\u4EE3\u7248\u672C\u867D\u7136\u4FEE\u590D\u4E86\u8FD9\u4E2A\u95EE\u9898\uFF0C\u4F46\u6846\u67B6\u672C\u8EAB\u7684\u5F00\u9500 (Zone.js, \u4F9D\u8D56\u6CE8\u5165\u7CFB\u7EDF) \u5BF9\u4E8E\u6D4F\u89C8\u5668\u4E3B\u7EBF\u7A0B\u6765\u8BF4\u4ECD\u7136\u662F\u4E00\u4E2A\u4E0D\u5C0F\u7684\u8D1F\u62C5\u3002</li>\n</ul>\n<h3 id="lupine-js"><a class="header-anchor" href="#lupine-js">#</a>Lupine.js</h3><p>Lupine \u91C7\u53D6\u4E86\u6839\u672C\u4E0D\u540C\u7684\u67B6\u6784\u3002\u5B83\u4ECE\u7B2C\u4E00\u884C\u4EE3\u7801\u5F00\u59CB\uFF0C\u5C31\u662F\u4F5C\u4E3A\u4E00\u4E2A<strong>\u5168\u6808\u7EC4\u4EF6\u6846\u67B6</strong>\u8BBE\u8BA1\u7684\u3002</p>\n<ul>\n<li><strong>\u673A\u5236</strong>: <code>serverSideRenderPage</code> \u51FD\u6570 (\u5728 <code>lupine.api</code> \u4E2D) \u76F4\u63A5\u6267\u884C\u7EC4\u4EF6\u903B\u8F91\u3002\u5B83\u7CBE\u51C6\u8BC6\u522B\u5E76\u9884\u7559\u4E86\u5173\u952E\u8D44\u6E90\uFF08CSS, Meta, Title\uFF09\u7684\u201C\u63D2\u69FD\u201D\u3002</li>\n<li><strong>\u65E0 VDOM</strong>: Lupine <strong>\u4E0D\u4F7F\u7528\u865A\u62DF DOM</strong>\u3002\u5728\u670D\u52A1\u7AEF\uFF0C\u5B83\u9AD8\u6548\u5730\u62FC\u63A5\u5B57\u7B26\u4E32\u3002\u5728\u5BA2\u6237\u7AEF\uFF0C\u5B83\u76F4\u63A5\u7ED1\u5B9A\u5230\u771F\u5B9E\u7684 DOM \u8282\u70B9\u3002</li>\n<li><strong>\u7ED3\u679C</strong>: \u670D\u52A1\u7AEF\u53D1\u9001\u7684\u662F\u5B8C\u5168\u6837\u5F0F\u5316\u7684 HTML \u9875\u9762\u3002\u5BA2\u6237\u7AEF\u811A\u672C (~7kb) \u52A0\u8F7D\u540E\uFF0C\u4EC5\u4EC5\u662F\u201C\u7ED1\u5B9A\u201D\u5230\u73B0\u6709\u5143\u7D20\u4E0A\u3002\u56E0\u4E3A\u6CA1\u6709 VDOM \u9700\u8981\u91CD\u5EFA\uFF0C\u6240\u4EE5\u6CA1\u6709\u7E41\u91CD\u7684\u201C\u91CD\u8BA1\u7B97\u201D\u8FC7\u7A0B\u3002</li>\n</ul>\n<h2 id="2-\u89E3\u51B3-fouc-\u65E0\u6837\u5F0F\u5185\u5BB9\u95EA\u70C1"><a class="header-anchor" href="#2-\u89E3\u51B3-fouc-\u65E0\u6837\u5F0F\u5185\u5BB9\u95EA\u70C1">#</a>2. \u89E3\u51B3 &quot;FOUC&quot; (\u65E0\u6837\u5F0F\u5185\u5BB9\u95EA\u70C1)</h2><h3 id="\u95EE\u9898"><a class="header-anchor" href="#\u95EE\u9898">#</a>\u95EE\u9898</h3><p>SSR \u7684 HTML \u5148\u5230\u8FBE\u6D4F\u89C8\u5668\uFF0C\u7136\u540E\u529F\u80FD\u52A0\u8F7D\uFF0C\u6700\u540E\u6837\u5F0F\u52A0\u8F7D\u3002\u5982\u679C\u6837\u5F0F\u52A0\u8F7D\u665A\u4E86\uFF0C\u7528\u6237\u5C31\u4F1A\u770B\u5230\u51E0\u6BEB\u79D2\u7684\u9875\u9762\u9519\u4E71 (FOUC)\u3002</p>\n<h3 id="react-next-js"><a class="header-anchor" href="#react-next-js">#</a>React / Next.js</h3><p>Next.js \u4F1A\u6536\u96C6\u6837\u5F0F\uFF08\u4F8B\u5982\u6765\u81EA CSS Modules \u6216 Tailwind\uFF09\u5E76\u6CE8\u5165\u3002\u4F46\u662F\uFF0C\u5982\u679C\u4F7F\u7528\u8FD0\u884C\u65F6\u7684 CSS-in-JS\uFF08\u50CF\u65E7\u7248\u7684 styled-components\uFF09\uFF0C\u5728\u6C34\u5408\u671F\u95F4\u91CD\u65B0\u8BA1\u7B97\u6837\u5F0F\u53EF\u80FD\u4F1A\u5E26\u6765\u6027\u80FD\u60E9\u7F5A\u3002</p>\n<h3 id="lupine-js"><a class="header-anchor" href="#lupine-js">#</a>Lupine.js</h3><p>Lupine \u7684 <code>BindStyles</code> \u548C <code>CssProps</code> \u5F15\u64CE\u4F1A\u5728\u670D\u52A1\u7AEF\u6E32\u67D3\u671F\u95F4\u6536\u96C6\u6240\u6709\u9759\u6001\u548C\u52A8\u6001\u6837\u5F0F\u3002\n\u5B83\u4F1A\u81EA\u52A8\u751F\u6210\u5173\u952E CSS \u4EE3\u7801\u5757\uFF0C\u5E76\u76F4\u63A5\u6CE8\u5165\u5230\u521D\u59CB HTML \u54CD\u5E94\u7684 <code>&lt;head&gt;</code> \u4E2D\u3002\n<strong>\u7ED3\u679C</strong>: \u9875\u9762\u4ECE\u7B2C\u4E00\u4E2A\u5B57\u8282\u5F00\u59CB\u5C31\u662F\u5B8C\u7F8E\u7684\u3002\u65E0\u9700\u7B49\u5F85 JS \u52A0\u8F7D\uFF0C\u5E03\u5C40\u5C31\u662F\u6B63\u786E\u7684\u3002</p>\n<h2 id="3-\u6570\u636E\u83B7\u53D6\u4E0E\u6C34\u5408"><a class="header-anchor" href="#3-\u6570\u636E\u83B7\u53D6\u4E0E\u6C34\u5408">#</a>3. \u6570\u636E\u83B7\u53D6\u4E0E\u6C34\u5408</h2><p>\u5982\u4F55\u4ECE\u6570\u636E\u5E93\u83B7\u53D6\u6570\u636E\u5E76\u663E\u793A\u5728\u5C4F\u5E55\u4E0A\uFF1F</p>\n<h3 id="react-next-js-app-router"><a class="header-anchor" href="#react-next-js-app-router">#</a>React (Next.js App Router)</h3><pre><code class="language-tsx">// Server Component\nasync function Page() {\n  const data = await db.query();\n  return &lt;ClientComponent data={data} /&gt;;\n}\n</code></pre>\n<ul>\n<li><strong>\u4F18\u70B9</strong>: \u6570\u636E\u548C UI \u7D27\u5BC6\u914D\u5408 (Co-location)\u3002</li>\n<li><strong>\u7F3A\u70B9</strong>: \u670D\u52A1\u7AEF\u7EC4\u4EF6\u548C\u5BA2\u6237\u7AEF\u7EC4\u4EF6\u4E4B\u95F4\u6709\u4E25\u683C\u7684\u8FB9\u754C\u3002\u4F60\u4E0D\u80FD\u5728\u670D\u52A1\u7AEF\u7EC4\u4EF6\u4E2D\u4F7F\u7528 State \u6216 Effect\u3002</li>\n</ul>\n<h3 id="lupine-js"><a class="header-anchor" href="#lupine-js">#</a>Lupine.js</h3><p>Lupine \u652F\u6301\u9875\u9762\u7EA7\u7684 <code>async</code> \u7EC4\u4EF6\uFF0C\u8FD9\u4F7F\u5F97\u540C\u4E00\u5957\u903B\u8F91\u53EF\u4EE5\u65E0\u7F1D\u8FD0\u884C\u5728\u670D\u52A1\u7AEF\u548C\u5BA2\u6237\u7AEF\uFF08SPA \u5BFC\u822A\u671F\u95F4\uFF09\u3002</p>\n<pre><code class="language-tsx">// \u65E2\u8FD0\u884C\u5728\u670D\u52A1\u7AEF (SSR)\uFF0C\u4E5F\u8FD0\u884C\u5728\u5BA2\u6237\u7AEF (SPA \u5207\u6362)\nexport const ProductPage = async (props: PageProps) =&gt; {\n  // SSR: \u5728\u670D\u52A1\u7AEF\u8BF7\u6C42\uFF0C\u53D1\u9001 HTML\u3002\n  // CSR: \u5728\u5BA2\u6237\u7AEF\u8BF7\u6C42\uFF0C\u66F4\u65B0 DOM\u3002\n  const data = await fetch(`/api/products/${props.urlParameters.id}`);\n\n  return &lt;div&gt;{data.title}&lt;/div&gt;;\n};\n</code></pre>\n<ul>\n<li><strong>\u8BBE\u8BA1\u54F2\u5B66</strong>: &quot;\u540C\u6784\u903B\u8F91 (Isomorphic Logic)&quot;\u3002\u4F60\u53EA\u5199\u4E00\u4E2A\u51FD\u6570\u3002\u5B83\u5728\u4E24\u79CD\u73AF\u5883\u4E2D\u90FD\u80FD\u9AD8\u6548\u8FD0\u884C\uFF0C\u4F60\u65E0\u9700\u5173\u5FC3\u201C\u5E8F\u5217\u5316\u8FB9\u754C\u201D\u6216\u201C\u5BA2\u6237\u7AEF\u5305\u88C5\u5668\u201D\u3002</li>\n</ul>\n<h2 id="4-\u6027\u80FD\u4E0E\u5305\u4F53\u79EF"><a class="header-anchor" href="#4-\u6027\u80FD\u4E0E\u5305\u4F53\u79EF">#</a>4. \u6027\u80FD\u4E0E\u5305\u4F53\u79EF</h2><p>\u8FD9\u662F\u6700\u663E\u8457\u7684\u5DEE\u5F02\u3002</p>\n<table>\n<thead>\n<tr>\n<th align="left">\u6307\u6807</th>\n<th align="left">Next.js / React</th>\n<th align="left">Angular</th>\n<th align="left">Lupine.js</th>\n</tr>\n</thead>\n<tbody><tr>\n<td align="left"><strong>Hello World \u4F53\u79EF</strong></td>\n<td align="left">~70kb - 200kb</td>\n<td align="left">~100kb+</td>\n<td align="left"><strong>~7kb</strong></td>\n</tr>\n<tr>\n<td align="left"><strong>\u6C34\u5408\u7B56\u7565</strong></td>\n<td align="left">VDOM \u534F\u8C03 (Reconciliation)</td>\n<td align="left">Zone.js / \u4E8B\u4EF6\u56DE\u653E</td>\n<td align="left"><strong>\u76F4\u63A5\u8282\u70B9\u7ED1\u5B9A</strong></td>\n</tr>\n<tr>\n<td align="left"><strong>\u590D\u6742\u5EA6</strong></td>\n<td align="left">\u9AD8 (Server Actions, RSC)</td>\n<td align="left">\u9AD8 (\u6A21\u5757, DI)</td>\n<td align="left"><strong>\u4F4E (\u51FD\u6570, \u4FE1\u53F7\u91CF)</strong></td>\n</tr>\n</tbody></table>\n<h2 id="\u603B\u7ED3-\u5982\u4F55\u9009\u62E9"><a class="header-anchor" href="#\u603B\u7ED3-\u5982\u4F55\u9009\u62E9">#</a>\u603B\u7ED3: \u5982\u4F55\u9009\u62E9\uFF1F</h2><ul>\n<li><strong>\u9009\u62E9 React/Next.js \u5982\u679C</strong>: \u4F60\u6709\u5E9E\u5927\u7684 React \u5F00\u53D1\u56E2\u961F\uFF0C\u9700\u8981\u6D77\u91CF\u7684\u7B2C\u4E09\u65B9\u5E93\u751F\u6001\uFF0C\u4E14\u6781\u5EA6\u4F9D\u8D56 Vercel \u7B49\u5E73\u53F0\u7684\u96C6\u6210\u3002</li>\n<li><strong>\u9009\u62E9 Angular \u5982\u679C</strong>: \u4F60\u5728\u6784\u5EFA\u4F01\u4E1A\u7EA7\u8F6F\u4EF6\uFF0C\u9700\u8981\u4E25\u683C\u7684\u7C7B\u578B\u7EA6\u675F\u3001\u4F9D\u8D56\u6CE8\u5165\u7CFB\u7EDF\uFF0C\u4E14\u56E2\u961F\u89C4\u6A21\u8F83\u5927\u3002</li>\n<li><strong>\u9009\u62E9 Lupine.js \u5982\u679C</strong>:<ul>\n<li><strong>\u6027\u80FD\u81F3\u4E0A</strong>: \u4F60\u8FFD\u6C42\u6700\u5FEB\u7684\u9996\u5C4F\u5185\u5BB9\u7ED8\u5236 (FCP)\u3002</li>\n<li><strong>\u5D07\u5C1A\u7B80\u7EA6</strong>: \u4F60\u4E0D\u60F3\u914D\u7F6E Webpack, Babel \u6216\u590D\u6742\u7684\u8DEF\u7531\u4E2D\u95F4\u4EF6\u3002</li>\n<li><strong>SEO \u5F88\u5173\u952E</strong>: \u4F60\u9700\u8981\u7B80\u5355\u3001\u53EF\u9884\u6D4B\u7684 Meta \u6807\u7B7E\u63A7\u5236\u3002</li>\n<li><strong>\u5168\u6808\u638C\u63A7</strong>: \u4F60\u5E0C\u671B\u524D\u540E\u7AEF\u4F7F\u7528\u540C\u4E00\u5957\u6781\u7B80\u6846\u67B6\u3002</li>\n</ul>\n</li>\n</ul>\n<p>Lupine.js \u8BC1\u660E\u4E86\u5728 2026 \u5E74\uFF0C\u6784\u5EFA\u73B0\u4EE3\u9AD8\u6027\u80FD SSR \u5E94\u7528\u5E76\u4E0D\u9700\u8981\u6C89\u91CD\u7684\u6846\u67B6\u3002\u6709\u4E9B\u65F6\u5019\uFF0C<strong>\u5C11\u5373\u662F\u591A</strong>\u3002</p>\n';

  // apps/doc/web/src/markdown-built/zh/essentials/api.html
  var api_default3 = '<h3 id="\u67B6\u6784\u4E0E\u5DE5\u4F5C\u6D41-architecture-workflow"><a class="header-anchor" href="#\u67B6\u6784\u4E0E\u5DE5\u4F5C\u6D41-architecture-workflow">#</a>\u{1F3D7}\uFE0F \u67B6\u6784\u4E0E\u5DE5\u4F5C\u6D41 (Architecture &amp; Workflow)</h3><p>Lupine.js \u8FD0\u884C\u4E00\u4E2A\u5355\u4F8B\u670D\u52A1\u5668\u5B9E\u4F8B\uFF0C\u53EF\u4EE5\u540C\u65F6\u670D\u52A1\u591A\u4E2A\u57DF\u540D\u548C\u5E94\u7528\u7A0B\u5E8F\u3002</p>\n<p><strong>1. \u5E94\u7528\u5B9A\u4E49 (App Definition)</strong>\n\u5E94\u7528\u5728 <code>.env</code> \u6587\u4EF6\u4E2D\u901A\u8FC7 <code>APPS</code> \u53D8\u91CF\u5B9A\u4E49\uFF08\u4F8B\u5982 <code>APPS=doc,demo.app</code>\uFF09\u3002\u57DF\u540D\u6620\u5C04\u4E5F\u5728 <code>.env</code> \u4E2D\u914D\u7F6E\uFF08\u4F8B\u5982 <code>DOMAINS@demo.app=example.com</code>\uFF09\u3002</p>\n<p><strong>2. \u7F16\u8BD1 (Compilation)</strong>\n\u5728\u6784\u5EFA/\u5F00\u53D1\u671F\u95F4\uFF0C<code>dev-watch.js</code> \u8BFB\u53D6\u6BCF\u4E2A\u5E94\u7528\u76EE\u5F55\u4E0B\u7684 <code>lupine.json</code> \u4EE5\u627E\u5230 <code>webEntryPoints</code> \u5E76\u8FDB\u884C\u7F16\u8BD1\u3002</p>\n<p><strong>3. \u8BF7\u6C42\u6D41\u7A0B (Request Flow)</strong>\n\u5F53\u8BF7\u6C42\u5230\u8FBE\u65F6\uFF1A</p>\n<ol>\n<li><strong>\u5E94\u7528\u89E3\u6790</strong>: <code>AppHelper</code> \u6839\u636E\u8BF7\u6C42\u7684\u4E3B\u673A\u540D\u8BC6\u522B\u76EE\u6807\u5E94\u7528\u3002</li>\n<li><strong>\u6A21\u5757\u52A0\u8F7D</strong>: \u52A0\u8F7D\u5BF9\u5E94\u7684 <code>ApiModule</code> (\u5728 <code>api/src/index.ts</code> \u4E2D\u5B9A\u4E49)\u3002</li>\n<li><strong>\u8DEF\u7531</strong>: <code>RootApi</code> \u5C1D\u8BD5\u5339\u914D API \u8DEF\u7531\u3002\u5982\u679C\u672A\u5339\u914D\uFF0C\u5219\u56DE\u9000\u5230 <code>StaticServer</code>\u3002</li>\n</ol>\n<p><strong>4. \u9759\u6001\u670D\u52A1\u4E0E SSR</strong>\n<code>StaticServer</code>:</p>\n<ul>\n<li>\u68C0\u67E5\u8BF7\u6C42\u7684\u9759\u6001\u6587\u4EF6\u662F\u5426\u5B58\u5728\u3002</li>\n<li>\u5982\u679C\u672A\u627E\u5230\uFF0C\u5B83\u5C06\u89E6\u53D1 <strong>SSR</strong> (<code>serverSideRenderPage</code>)\u3002</li>\n</ul>\n<p>\u8FD9\u786E\u4FDD\u4E86\u4E00\u4E2A\u5355\u4E00\u5165\u53E3\u70B9\u53EF\u4EE5\u65E0\u7F1D\u5904\u7406 API\u3001\u9759\u6001\u8D44\u6E90\u548C SSR \u9875\u9762\u751F\u6210\u3002</p>\n<p>\u540E\u7AEF\u670D\u52A1\u7684\u4E3B\u6A21\u5757\u3002\u6BCF\u4E00\u4E2A\u6709\u540E\u7AEF\u7684 App \u90FD\u5FC5\u987B\u5B9E\u88C5\u4E00\u4E2A <code>ApiModule</code>\u3002</p>\n<pre><code class="language-typescript">import { ApiModule } from &#39;lupine.api&#39;;\nimport { RootApi } from &#39;./service/root-api&#39;;\n\nexport const apiModule = new ApiModule(new RootApi());\n</code></pre>\n<h3 id="rootapi-\u4E0E-staticserver"><a class="header-anchor" href="#rootapi-\u4E0E-staticserver">#</a>\u{1F333} RootApi \u4E0E StaticServer</h3><p><code>RootApi</code> \u662F\u5E94\u7528\u7A0B\u5E8F\u903B\u8F91\u7684\u5165\u53E3\u70B9\u3002\u5B83\u901A\u5E38\u6302\u8F7D\u7279\u5B9A\u7684 API \u4EE5\u53CA <code>StaticServer</code> \u6765\u5904\u7406\u6587\u4EF6\u8BF7\u6C42\u548C SSR \u56DE\u9000\u3002</p>\n<pre><code class="language-typescript">// src/service/root-api.ts\nimport { IApiBase, ApiRouter, StaticServer } from &#39;lupine.api&#39;;\n\nexport class RootApi implements IApiBase {\n  protected router = new ApiRouter();\n\n  constructor() {\n    this.mountRoutes();\n  }\n\n  protected mountRoutes() {\n    // 1. \u6302\u8F7D\u4F60\u7684 App API\n    this.router.use(&#39;/api&#39;, new Api().getRouter());\n\n    // 2. \u6302\u8F7D\u9759\u6001\u670D\u52A1\u5668 (Static Server) (\u5904\u7406\u9759\u6001\u6587\u4EF6 + SSR)\n    // \u91CD\u8981\uFF1A\u5FC5\u987B\u653E\u5728\u6700\u540E\u4EE5\u6355\u83B7\u975E API \u8BF7\u6C42\n    const staticServer = new StaticServer();\n    this.router.use(&#39;*&#39;, staticServer.processRequest.bind(staticServer));\n  }\n}\n</code></pre>\n<h3 id="\u5065\u5EB7\u68C0\u67E5\u793A\u4F8B-health-check"><a class="header-anchor" href="#\u5065\u5EB7\u68C0\u67E5\u793A\u4F8B-health-check">#</a>\u{1F3E5} \u5065\u5EB7\u68C0\u67E5\u793A\u4F8B (Health Check)</h3><p>\u8FD9\u662F\u4E00\u4E2A\u7B80\u5355\u7684 API \u7AEF\u70B9\u793A\u4F8B\uFF08\u4F8B\u5982\u7528\u4E8E\u5065\u5EB7\u68C0\u67E5\uFF09\u3002</p>\n<pre><code class="language-typescript">// src/service/api.ts\nimport { IApiBase, ApiRouter, ServerRequest } from &#39;lupine.api&#39;;\nimport { ServerResponse } from &#39;http&#39;;\n\nexport class Api implements IApiBase {\n  protected router = new ApiRouter();\n\n  constructor() {\n    this.router.use(&#39;/health-check&#39;, this.healthCheck.bind(this));\n  }\n\n  async healthCheck(req: ServerRequest, res: ServerResponse) {\n    res.writeHead(200, { &#39;Content-Type&#39;: &#39;application/json&#39; });\n    res.write(JSON.stringify({ status: &#39;OK&#39;, uptime: process.uptime() }));\n    res.end();\n    return true; // \u8FD4\u56DE true \u8868\u793A\u8BF7\u6C42\u5DF2\u88AB\u5904\u7406\n  }\n\n  public getRouter() {\n    return this.router;\n  }\n}\n</code></pre>\n';

  // apps/doc/web/src/markdown-built/zh/essentials/css-in-js.html
  var css_in_js_default2 = '<h1 id="css-in-js"><a class="header-anchor" href="#css-in-js">#</a>CSS-in-JS</h1><p>Lupine.js \u5185\u7F6E\u6216\u8005\u8BF4\u81EA\u5E26\u4E86\u4E00\u4E2A\u8F7B\u91CF\u7EA7\u7684 <strong>CSS-in-JS</strong> \u5F15\u64CE\u3002\u5B83\u652F\u6301\u5D4C\u5957\u3001\u4F2A\u9009\u62E9\u5668\u3001\u5A92\u4F53\u67E5\u8BE2\u548C\u4F5C\u7528\u57DF\u52A8\u753B\u7B49\u5F3A\u5927\u529F\u80FD\uFF0C\u4E14\u65E0\u9700\u4F9D\u8D56 styled-components \u6216 emotion \u7B49\u5916\u90E8\u5E93\u3002</p>\n<h2 id="1-\u57FA\u672C\u7528\u6CD5"><a class="header-anchor" href="#1-\u57FA\u672C\u7528\u6CD5">#</a>1. \u{1F423} \u57FA\u672C\u7528\u6CD5</h2><p>\u4F60\u53EF\u4EE5\u5C06 CSS \u5BF9\u8C61\u76F4\u63A5\u4F20\u7ED9\u4EFB\u4F55\u5143\u7D20\u7684 <code>css</code> \u5C5E\u6027\u3002Lupine \u4F1A\u81EA\u52A8\u751F\u6210\u4E00\u4E2A\u552F\u4E00\u7684 Class ID\uFF0C\u9632\u6B62\u6837\u5F0F\u51B2\u7A81\u3002</p>\n<pre><code class="language-tsx">const MyComponent = () =&gt; {\n  const css: CssProps = {\n    // \u57FA\u672C\u5C5E\u6027\u4F7F\u7528\u9A7C\u5CF0\u547D\u540D\n    backgroundColor: &#39;#f0f0f0&#39;,\n    padding: &#39;20px&#39;,\n    borderRadius: &#39;8px&#39;,\n\n    // \u5D4C\u5957\u9009\u62E9\u5668\n    h1: {\n      color: &#39;blue&#39;,\n    },\n\n    // \u4F2A\u7C7B\n    &#39;&amp;:hover&#39;: {\n      backgroundColor: &#39;#e0e0e0&#39;,\n    },\n  };\n\n  return (\n    &lt;div css={css}&gt;\n      &lt;h1&gt;Hello&lt;/h1&gt;\n    &lt;/div&gt;\n  );\n};\n</code></pre>\n<h2 id="2-\u9AD8\u7EA7\u7279\u6027"><a class="header-anchor" href="#2-\u9AD8\u7EA7\u7279\u6027">#</a>2. \u{1F680} \u9AD8\u7EA7\u7279\u6027</h2><h3 id="2-1-\u5D4C\u5957\u4E0E\u7236\u9009\u62E9\u5668"><a class="header-anchor" href="#2-1-\u5D4C\u5957\u4E0E\u7236\u9009\u62E9\u5668">#</a>2.1 \u{1F38E} \u5D4C\u5957\u4E0E\u7236\u9009\u62E9\u5668 (<code>&amp;</code>)</h3><p>\u7C7B\u4F3C\u4E8E SCSS/Less\uFF0C\u4F7F\u7528 <code>&amp;</code> \u6765\u5F15\u7528\u7236\u9009\u62E9\u5668\u3002</p>\n<pre><code class="language-tsx">const css: CssProps = {\n  color: &#39;black&#39;,\n\n  // \u76EE\u6807\u5B50\u5143\u7D20\n  &#39;.child&#39;: { fontWeight: &#39;bold&#39; },\n\n  // \u81EA\u8EAB\u72B6\u6001\n  &#39;&amp;:hover&#39;: { color: &#39;red&#39; },\n\n  // \u591A\u4E2A\u9009\u62E9\u5668\n  &#39;&amp;:hover, &amp;.active&#39;: {\n    border: &#39;1px solid blue&#39;,\n  },\n};\n</code></pre>\n<h3 id="2-2-\u4F7F\u7528-\u8FDB\u884C\u4F5C\u7528\u57DF\u7BA1\u7406-\u52A8\u6001\u7EC4\u4EF6-id"><a class="header-anchor" href="#2-2-\u4F7F\u7528-\u8FDB\u884C\u4F5C\u7528\u57DF\u7BA1\u7406-\u52A8\u6001\u7EC4\u4EF6-id">#</a>2.2 \u{1F6E1}\uFE0F \u4F7F\u7528 <code>&amp;</code> \u8FDB\u884C\u4F5C\u7528\u57DF\u7BA1\u7406 (\u52A8\u6001\u7EC4\u4EF6 ID)</h3><p>Lupine \u4F7F\u7528\u4E00\u79CD\u5DE7\u5999\u7684\u66FF\u6362\u7CFB\u7EDF\u6765\u5904\u7406 <code>&amp;</code> (\u6216 <code>$</code>)\u3002</p>\n<ol>\n<li><p><strong>\u524D\u7F00\u5316</strong>\uFF1A\u5982\u679C\u9009\u62E9\u5668\u4EE5 <code>&amp;</code> \u5F00\u5934\uFF08\u4F8B\u5982 <code>&amp;-item</code>\uFF09\uFF0C\u5B83\u4F1A\u5C06\u7EC4\u4EF6\u7684\u552F\u4E00 ID \u89C6\u4E3A\u524D\u7F00\u3002</p>\n<ul>\n<li><code>&amp;-item</code> -&gt; <code>.LUPINE_ID-item</code></li>\n<li>\u8FD9\u5BF9\u4E8E\u7F16\u5199\u7C7B\u4F3C BEM \u547D\u540D\u89C4\u8303\u7684\u6837\u5F0F\u975E\u5E38\u6709\u7528\uFF0C\u800C\u65E0\u9700\u624B\u52A8\u7F16\u5199\u957F\u540D\u79F0\u3002</li>\n</ul>\n</li>\n<li><p><strong>\u66FF\u6362</strong>\uFF1A\u5982\u679C <code>&amp;</code> \u5728\u5176\u4ED6\u5730\u65B9\u4F7F\u7528\uFF08\u4F8B\u5982 <code>.parent &amp;</code>\uFF09\uFF0C\u5B83\u4F1A\u5728\u8BE5\u4F4D\u7F6E\u63D2\u5165\u552F\u4E00 ID\u3002</p>\n</li>\n</ol>\n<pre><code class="language-tsx">// \u4F7F\u7528 &quot;$-item&quot; \u6216 &quot;&amp;-item&quot; \u6A21\u5F0F\u5B9A\u4E49\u4F5C\u7528\u57DF Class\nconst css = {\n  // \u5B9A\u4E49\u4E00\u4E2A\u4F5C\u7528\u57DF Class\uFF0C\u5982 .L123-item\n  &#39;&amp;-item&#39;: {\n    color: &#39;gray&#39;,\n  },\n\n  // \u4F60\u4E5F\u53EF\u4EE5\u5F15\u7528\u4E3A .&amp;-item\uFF0C\u610F\u5473\u7740 .L123 .L123-item (\u5D4C\u5957)\n  &#39;.&amp;-item&#39;: {\n    color: &#39;black&#39;, // \u5982\u679C\u9700\u8981\u66F4\u5F3A\u7684\u7279\u5F02\u6027\n  },\n};\n\nreturn (\n  &lt;div css={css}&gt;\n    {/* \u5E94\u7528\u4F5C\u7528\u57DF Class */}\n    &lt;a class=&#39;&amp;-item&#39;&gt;Link&lt;/a&gt;\n  &lt;/div&gt;\n);\n</code></pre>\n<h3 id="2-3-\u5355\u884C\u591A\u5B9A\u4E49"><a class="header-anchor" href="#2-3-\u5355\u884C\u591A\u5B9A\u4E49">#</a>2.3 \u26A1 \u5355\u884C\u591A\u5B9A\u4E49</h3><p>\u4F60\u53EF\u4EE5\u5728\u4E00\u884C\u4E2D\u5B9A\u4E49\u591A\u4E2A\u5C5E\u6027\uFF08\u9017\u53F7\u5206\u9694\u7684\u9009\u62E9\u5668\uFF09\uFF0C\u4EE5\u7B80\u5316\u8BED\u6CD5\u3002</p>\n<pre><code class="language-tsx">const css = {\n  // \u591A\u4E2A\u9009\u62E9\u5668\u5171\u4EAB\u6837\u5F0F\n  &#39;.header, .footer&#39;: {\n    background: &#39;#333&#39;,\n    color: &#39;white&#39;,\n  },\n};\n</code></pre>\n<h3 id="2-4-\u5A92\u4F53\u67E5\u8BE2-media"><a class="header-anchor" href="#2-4-\u5A92\u4F53\u67E5\u8BE2-media">#</a>2.4 \u{1F4F1} \u5A92\u4F53\u67E5\u8BE2 (<code>@media</code>)</h3><p>\u5A92\u4F53\u67E5\u8BE2\u53EF\u4EE5\u5D4C\u5957\u5728\u9009\u62E9\u5668 <em>\u5185\u90E8</em> \u6216\u5728\u9876\u5C42\u4F7F\u7528\u3002</p>\n<pre><code class="language-tsx">const css = {\n  fontSize: &#39;16px&#39;,\n\n  // \u5D4C\u5957\u5728\u7EC4\u4EF6\u903B\u8F91\u5185\u90E8\n  &#39;@media (max-width: 600px)&#39;: {\n    fontSize: &#39;14px&#39;,\n    padding: &#39;10px&#39;,\n  },\n};\n// \u6216\u8005\u4F7F\u7528\u8F85\u52A9\u5E38\u91CF\uFF0C\u5982 [MediaQueryRange.DesktopAbove]\n</code></pre>\n<h3 id="2-5-\u5173\u952E\u5E27\u52A8\u753B-keyframes"><a class="header-anchor" href="#2-5-\u5173\u952E\u5E27\u52A8\u753B-keyframes">#</a>2.5 \u{1F3AC} \u5173\u952E\u5E27\u52A8\u753B (<code>@keyframes</code>)</h3><p>\u5728\u7EC4\u4EF6\u5185\u5C40\u90E8\u5B9A\u4E49\u52A8\u753B\u3002</p>\n<pre><code class="language-tsx">const css = {\n  &#39;@keyframes slide-in&#39;: {\n    &#39;0%&#39;: { transform: &#39;translateX(-100%)&#39; },\n    &#39;100%&#39;: { transform: &#39;translateX(0)&#39; },\n  },\n  animation: &#39;slide-in 0.5s ease-out&#39;,\n};\n</code></pre>\n<h2 id="3-\u5168\u5C40\u6837\u5F0F-bindglobalstyle"><a class="header-anchor" href="#3-\u5168\u5C40\u6837\u5F0F-bindglobalstyle">#</a>3. \u{1F30F} \u5168\u5C40\u6837\u5F0F (<code>bindGlobalStyle</code>)</h2><p>\u6709\u65F6\u4F60\u9700\u8981\u4E00\u4E9B <strong>\u53EF\u91CD\u7528</strong> \u6216 <strong>\u5168\u5C40</strong> \u7684\u6837\u5F0F\uFF0C\u4F46\u4F60\u4ECD\u7136\u5E0C\u671B\u5728 TypeScript/JS \u4E2D\u5B9A\u4E49\u5B83\u4EEC\u3002<code>bindGlobalStyle</code> \u786E\u4FDD\u6837\u5F0F\u53EA\u751F\u6210\u4E00\u6B21\u5E76\u6CE8\u5165\u5230 <code>&lt;head&gt;</code> \u4E2D\uFF0C\u5373\u4F7F\u8BE5\u7EC4\u4EF6\u88AB\u4F7F\u7528\u4E86\u591A\u6B21\u3002</p>\n<blockquote>\n<p><strong>\u9002\u7528\u573A\u666F\uFF1A</strong> \u52A8\u753B\u5B9A\u4E49\u3001\u5DE5\u5177\u7C7B\u3001CSS \u91CD\u7F6E\u3002</p>\n</blockquote>\n<pre><code class="language-tsx">import { bindGlobalStyle } from &#39;lupine.web&#39;;\n\nconst TextWave = () =&gt; {\n  // 1. \u5B9A\u4E49\u6837\u5F0F\n  const css = {\n    &#39;@keyframes wave&#39;: {\n      /* ... */\n    },\n    &#39;.wave-text&#39;: { animation: &#39;wave 1s infinite&#39; },\n  };\n\n  // 2. \u5C06\u5176\u5168\u5C40\u7ED1\u5B9A\uFF0C\u4F7F\u7528\u552F\u4E00\u952E &#39;text-wave-style&#39;\n  // \u8FD9\u786E\u4FDD\u4E86\u5B83\u5728\u9875\u9762\u4E2D\u53EA\u88AB\u6CE8\u5165\u4E00\u6B21\n  bindGlobalStyle(&#39;text-wave-style&#39;, css);\n\n  return (\n    // 3. \u4F7F\u7528\u4E0A\u9762\u5B9A\u4E49\u7684 Class\n    &lt;div class=&#39;text-wave-style&#39;&gt;\n      &lt;span class=&#39;wave-text&#39;&gt;Hello&lt;/span&gt;\n    &lt;/div&gt;\n  );\n};\n</code></pre>\n';

  // apps/doc/web/src/markdown-built/zh/essentials/dashboard.html
  var dashboard_default3 = '<h1 id="dashboard"><a class="header-anchor" href="#dashboard">#</a>Dashboard</h1><p>lupine.api \u81EA\u5E26\u4E00\u4E2A\u53EF\u4EE5\u6269\u5145\u7684 dashboard\uFF0C\u7528\u4E8E\u7BA1\u7406 api \u670D\u52A1\u3002dashboard \u5DE6\u8FB9\u662F\u4F17\u591A\u7BA1\u7406\u83DC\u5355\uFF0C\u53F3\u8FB9\u662F\u591A\u9875\u9762\u7684 tab \u5185\u5BB9\u9875\u9762\u3002</p>\n<h2 id="\u529F\u80FD\u7279\u6027-features"><a class="header-anchor" href="#\u529F\u80FD\u7279\u6027-features">#</a>\u529F\u80FD\u7279\u6027 (Features)</h2><p>Dashboard \u63D0\u4F9B\u4E86\u5168\u9762\u7684\u540E\u53F0\u7BA1\u7406\u529F\u80FD\uFF0C\u6309\u529F\u80FD\u6A21\u5757\u5206\u7C7B\u5982\u4E0B\uFF1A</p>\n<h3 id="1-\u6570\u636E\u5E93\u7BA1\u7406-db"><a class="header-anchor" href="#1-\u6570\u636E\u5E93\u7BA1\u7406-db">#</a>1. \u6570\u636E\u5E93\u7BA1\u7406 (DB)</h3><p>\u63D0\u4F9B\u76F4\u63A5\u64CD\u4F5C\u6570\u636E\u5E93\u7684\u5DE5\u5177\uFF0C\u65B9\u4FBF\u8C03\u8BD5\u548C\u7EF4\u62A4\u3002</p>\n<ul>\n<li><strong>Table List (\u8868\u5217\u8868)</strong>: \u6D4F\u89C8\u6570\u636E\u5E93\u4E2D\u7684\u8868\uFF0C\u652F\u6301\u67E5\u770B\u8868\u6570\u636E\u3002</li>\n<li><strong>Create Tables (\u521B\u5EFA\u8868)</strong>: \u8FD0\u884C\u9884\u8BBE\u811A\u672C\u521D\u59CB\u5316\u6216\u4FEE\u590D\u6570\u636E\u5E93\u8868\u7ED3\u6784\u3002</li>\n<li><strong>Run SQL (\u8FD0\u884C SQL)</strong>: \u63D0\u4F9B\u4E00\u4E2A SQL \u6267\u884C\u7A97\u53E3\uFF0C\u53EF\u4EE5\u8FD0\u884C\u4EFB\u610F SQL \u8BED\u53E5\u5E76\u76F4\u63A5\u67E5\u770B JSON \u683C\u5F0F\u7684\u8FD4\u56DE\u7ED3\u679C\u3002</li>\n</ul>\n<h3 id="2-\u8FD0\u7EF4\u4E0E\u670D\u52A1\u5668\u7BA1\u7406-access-server-info"><a class="header-anchor" href="#2-\u8FD0\u7EF4\u4E0E\u670D\u52A1\u5668\u7BA1\u7406-access-server-info">#</a>2. \u8FD0\u7EF4\u4E0E\u670D\u52A1\u5668\u7BA1\u7406 (Access &amp; Server Info)</h3><p>\u6838\u5FC3\u7684\u8FD0\u7EF4\u5DE5\u5177\u96C6\uFF0C\u652F\u6301\u8FDC\u7A0B\u7BA1\u7406\u548C\u76D1\u63A7\u3002</p>\n<h4 id="release-\u53D1\u5E03\u7BA1\u7406"><a class="header-anchor" href="#release-\u53D1\u5E03\u7BA1\u7406">#</a>Release (\u53D1\u5E03\u7BA1\u7406)</h4><p>\u5F3A\u5927\u7684\u53D1\u5E03\u5DE5\u5177\uFF0C\u652F\u6301\u591A\u8282\u70B9/\u591A\u73AF\u5883\u7BA1\u7406\u3002</p>\n<ul>\n<li><strong>\u7248\u672C\u540C\u6B65</strong>: \u652F\u6301\u5C06\u4EE3\u7801\u6216\u8D44\u6E90\u4ECE\u6E90\u73AF\u5883 (From) \u540C\u6B65\u5230\u76EE\u6807\u73AF\u5883 (To)\u3002</li>\n<li><strong>\u5168\u6808\u66F4\u65B0</strong>: \u53EF\u9009\u62E9\u66F4\u65B0 Server (\u6838\u5FC3\u670D\u52A1), Api (\u4E1A\u52A1\u903B\u8F91), Env (\u73AF\u5883\u53D8\u91CF) \u7B49\u3002</li>\n<li><strong>Web \u66F4\u65B0</strong>: \u652F\u6301\u6309\u5B50\u76EE\u5F55 (Web Sub-folder) \u72EC\u7ACB\u66F4\u65B0\u524D\u7AEF\u8D44\u6E90\u3002</li>\n<li><strong>\u64CD\u4F5C\u63A7\u5236</strong>:<ul>\n<li><strong>Check</strong>: \u68C0\u67E5\u66F4\u65B0\u72B6\u6001\u3002</li>\n<li><strong>Refresh Cache</strong>: \u5237\u65B0\u670D\u52A1\u5668\u7F13\u5B58 (\u652F\u6301\u8FDC\u7A0B/\u672C\u5730)\u3002</li>\n<li><strong>Restart App</strong>: \u91CD\u542F\u5E94\u7528\u7A0B\u5E8F (\u652F\u6301\u8FDC\u7A0B/\u672C\u5730)\u3002</li>\n<li><strong>Run Cmd</strong>: \u76F4\u63A5\u5728\u670D\u52A1\u5668\u6267\u884C Shell \u547D\u4EE4\u3002</li>\n</ul>\n</li>\n<li><strong>\u65E5\u5FD7</strong>: \u67E5\u770B\u548C\u4E0B\u8F7D\u53D1\u5E03\u64CD\u4F5C\u7684\u5386\u53F2\u65E5\u5FD7\u3002</li>\n</ul>\n<h4 id="utilities-\u5DE5\u5177"><a class="header-anchor" href="#utilities-\u5DE5\u5177">#</a>Utilities (\u5DE5\u5177)</h4><ul>\n<li><strong>Tokens (\u4EE4\u724C\u7BA1\u7406)</strong>: \u7BA1\u7406 API \u8BBF\u95EE\u4EE4\u724C\u3002</li>\n<li><strong>Shell (\u5728\u7EBF\u7EC8\u7AEF)</strong>: \u57FA\u4E8E WebSocket \u7684\u5728\u7EBF\u7EC8\u7AEF\uFF0C\u53EF\u5B9E\u65F6\u4E0E\u670D\u52A1\u5668\u4EA4\u4E92\uFF0C\u6267\u884C\u901A\u8FC7\u9A8C\u8BC1\u7684\u547D\u4EE4\u3002</li>\n<li><strong>Resources (\u8D44\u6E90\u7BA1\u7406)</strong>: \u6D4F\u89C8\u3001\u4E0A\u4F20\u3001\u4E0B\u8F7D\u670D\u52A1\u5668\u6587\u4EF6\u7CFB\u7EDF\u4E2D\u7684\u8D44\u6E90\u6587\u4EF6\u3002</li>\n<li><strong>Config (\u914D\u7F6E\u7BA1\u7406)</strong>: \u67E5\u770B\u548C\u70ED\u4FEE\u6539\u7CFB\u7EDF\u8FD0\u884C\u65F6\u914D\u7F6E\u3002</li>\n<li><strong>Performance (\u6027\u80FD\u76D1\u63A7)</strong>: \u76D1\u63A7\u670D\u52A1\u5668\u7684\u5185\u5B58\u3001CPU \u7B49\u6027\u80FD\u6307\u6807\u3002</li>\n</ul>\n<h3 id="3-\u5F00\u53D1\u4E0E\u6D4B\u8BD5-test"><a class="header-anchor" href="#3-\u5F00\u53D1\u4E0E\u6D4B\u8BD5-test">#</a>3. \u5F00\u53D1\u4E0E\u6D4B\u8BD5 (Test)</h3><p>\u7528\u4E8E\u5F00\u53D1\u9636\u6BB5\u8C03\u8BD5\u7EC4\u4EF6\u548C UI\u3002</p>\n<ul>\n<li><strong>Test Themes</strong>: \u9884\u89C8\u548C\u6D4B\u8BD5\u4E0D\u540C\u7684 UI \u4E3B\u9898\u914D\u7F6E\u3002</li>\n<li><strong>Test Component</strong>: \u6D4B\u8BD5\u901A\u7528 UI \u7EC4\u4EF6\u7684\u4EA4\u4E92\u548C\u6E32\u67D3\u3002</li>\n<li><strong>Test Animations</strong>: \u6F14\u793A\u548C\u8C03\u8BD5 CSS/JS \u52A8\u753B\u6548\u679C\u3002</li>\n<li><strong>Test Edit</strong>: \u6D4B\u8BD5\u5BCC\u6587\u672C\u7F16\u8F91\u5668\u6216\u8868\u5355\u7F16\u8F91\u529F\u80FD\u3002</li>\n</ul>\n<hr>\n<h2 id="\u6269\u5C55\u5F00\u53D1"><a class="header-anchor" href="#\u6269\u5C55\u5F00\u53D1">#</a>\u6269\u5C55\u5F00\u53D1</h2><p>Dashboard \u662F\u9AD8\u5EA6\u53EF\u6269\u5C55\u7684\u3002\u6838\u5FC3\u903B\u8F91\u4F4D\u4E8E <code>packages/lupine.api/admin</code> \u76EE\u5F55\u4E0B\u3002</p>\n<h3 id="\u83DC\u5355\u914D\u7F6E"><a class="header-anchor" href="#\u83DC\u5355\u914D\u7F6E">#</a>\u83DC\u5355\u914D\u7F6E</h3><p>\u83DC\u5355\u901A\u8FC7 <code>admin-frame-helper.tsx</code> \u4E2D\u7684 <code>adminTopMenu</code> \u6570\u7EC4\u8FDB\u884C\u914D\u7F6E\u3002\u4F60\u53EF\u4EE5\u8F7B\u677E\u6DFB\u52A0\u65B0\u7684\u83DC\u5355\u9879\uFF1A</p>\n<pre><code class="language-typescript">const myMenu = {\n  id: &#39;my-feature&#39;,\n  text: &#39;My Feature&#39;,\n  items: [\n    {\n      id: &#39;my-page&#39;,\n      text: &#39;My Page&#39;,\n      js: () =&gt; this.addPanel(&#39;My Page&#39;, &lt;MyComponent /&gt;),\n    },\n  ],\n};\n</code></pre>\n<h3 id="\u9875\u9762\u5F00\u53D1"><a class="header-anchor" href="#\u9875\u9762\u5F00\u53D1">#</a>\u9875\u9762\u5F00\u53D1</h3><p>\u6BCF\u4E2A\u7BA1\u7406\u9875\u9762\u90FD\u662F\u4E00\u4E2A\u6807\u51C6\u7684 <code>lupine.components</code> \u7EC4\u4EF6\u3002\u4F7F\u7528 <code>AdminPanel</code> \u548C <code>Tabs</code> \u7EC4\u4EF6\u6765\u7BA1\u7406\u591A\u6807\u7B7E\u9875\u4F53\u9A8C\u3002</p>\n';

  // apps/doc/web/src/markdown-built/zh/essentials/icons.html
  var icons_default2 = '<h2 id="\u56FE\u6807\u5B57\u4F53\u5B9A\u5236"><a class="header-anchor" href="#\u56FE\u6807\u5B57\u4F53\u5B9A\u5236">#</a>\u56FE\u6807\u5B57\u4F53\u5B9A\u5236</h2><p>Lupine.js \u53EF\u4EE5\u5B8C\u7F8E\u96C6\u6210\u6211\u7684\u53E6\u4E00\u4E2A\u72EC\u7ACB\u9879\u76EE <a href="https://github.com/uuware/icons-font-customization">Icons Font Customization</a> \uFF0C\u4E3A\u60A8\u63D0\u4F9B\u8D85\u8FC7 78,000 \u4E2A\u9AD8\u8D28\u91CF\u7684\u514D\u8D39\u56FE\u6807\u3002</p>\n<p><a href="https://github.com/uuware/icons-font-customization">Icons Font Customization</a> \u662F\u4E00\u4E2A\u5F3A\u5927\u7684\u56FE\u6807\u96C6\u5408\u548C\u5DE5\u5177\uFF0C\u5B83\u5141\u8BB8\u60A8\uFF1A</p>\n<ul>\n<li><strong>\u6D77\u91CF\u8D44\u6E90</strong>\uFF1A\u8BBF\u95EE\u6765\u81EA Font Awesome, Material Design \u7B49\u591A\u8FBE 78,000+ \u4E2A\u56FE\u6807\u3002</li>\n<li><strong>\u81EA\u7531\u5B9A\u5236</strong>\uFF1A\u60A8\u53EF\u4EE5\u6DF7\u5408\u4F7F\u7528\u4E0D\u540C\u6765\u6E90\u7684\u56FE\u6807\uFF0C\u53EA\u9009\u62E9\u60A8\u771F\u6B63\u9700\u8981\u7684\u56FE\u6807\uFF0C\u4ECE\u800C\u6781\u5927\u51CF\u5C0F\u5B57\u4F53\u6587\u4EF6\u7684\u5927\u5C0F\u3002</li>\n<li><strong>\u81EA\u5B9A\u4E49\u6837\u5F0F</strong>\uFF1A\u652F\u6301\u5728\u751F\u6210\u524D\u8C03\u6574\u56FE\u6807\u7684\u989C\u8272\u3001\u80CC\u666F\u548C\u5927\u5C0F\u3002</li>\n<li><strong>\u81EA\u52A8\u5316\u751F\u6210</strong>\uFF1A\u4E00\u952E\u751F\u6210\u5B57\u4F53\u6587\u4EF6\uFF08woff2, woff, ttf\uFF09\u548C\u914D\u5957\u7684 CSS/HTML\u3002</li>\n</ul>\n<p>\u8BF7\u8BBF\u95EE\u9879\u76EE\u67E5\u770B\u6587\u6863\u548C\u6240\u6709\u56FE\u6807\uFF1A<a href="https://github.com/uuware/icons-font-customization">Icons Font Customization</a>\u3002</p>\n';

  // apps/doc/web/src/markdown-built/zh/essentials/index.html
  var essentials_default2 = "";

  // apps/doc/web/src/markdown-built/zh/essentials/list.html
  var list_default2 = `<h1 id="\u9AD8\u6027\u80FD\u5217\u8868\u6E32\u67D3\u4E0E\u7F16\u8F91"><a class="header-anchor" href="#\u9AD8\u6027\u80FD\u5217\u8868\u6E32\u67D3\u4E0E\u7F16\u8F91">#</a>\u9AD8\u6027\u80FD\u5217\u8868\u6E32\u67D3\u4E0E\u7F16\u8F91</h1><p>Lupine.js \u91C7\u7528\u4E86\u4E00\u79CD\u72EC\u7279\u7684 <strong>&quot;\u7EC4\u4EF6\u7EA7\u6E32\u67D3 (Component-Level Rendering)&quot;</strong> \u7B56\u7565\uFF0C\u8FD9\u4E0E React \u6216 Vue \u7B49\u4F20\u7EDF\u7684\u865A\u62DF DOM \u6846\u67B6\u6709\u663E\u8457\u4E0D\u540C\u3002\u8FD9\u79CD\u65B9\u6CD5\u5728\u5904\u7406\u5927\u578B\u5217\u8868\u548C\u590D\u6742\u6570\u636E\u8868\u683C\uFF08\u4F8B\u5982\u7BA1\u7406\u540E\u53F0 Admin Panel\uFF09\u65F6\u7279\u522B\u5F3A\u5927\u3002</p>
<h2 id="1-\u4E3A\u4EC0\u4E48\u5B83\u5F88\u5FEB"><a class="header-anchor" href="#1-\u4E3A\u4EC0\u4E48\u5B83\u5F88\u5FEB">#</a>1. \u26A1 \u4E3A\u4EC0\u4E48\u5B83\u5F88\u5FEB\uFF1F</h2><p>\u5728\u4F20\u7EDF\u6846\u67B6\uFF08\u5982 React\uFF09\u4E2D\uFF0C\u5F53\u4F60\u66F4\u65B0\u5217\u8868\u4E2D\u7684\u67D0\u4E00\u9879\u65F6\uFF1A</p>
<ol>
<li>\u4F60\u8C03\u7528 <code>setState</code>\u3002</li>
<li>\u6846\u67B6\u91CD\u65B0\u6E32\u67D3 <strong>\u6574\u4E2A\u5217\u8868\u7EC4\u4EF6 (List Component)</strong>\u3002</li>
<li>\u5B83\u8FD0\u884C\u201CDiff \u7B97\u6CD5\u201D\uFF0C\u5C06\u5305\u542B 100 \u591A\u4E2A\u9879\u76EE\u7684\u65B0\u865A\u62DF\u6811\u4E0E\u65E7\u6811\u8FDB\u884C\u5BF9\u6BD4\u3002</li>
<li>\u6700\u540E\uFF0C\u5B83\u66F4\u65B0\u90A3\u4E00\u4E2A\u53D1\u751F\u53D8\u5316\u7684 DOM \u5143\u7D20\u3002</li>
</ol>
<p><strong>\u5728 Lupine.js \u4E2D\uFF0C\u6211\u4EEC\u5B8C\u5168\u8DF3\u8FC7\u4E86\u7B2C 2 \u6B65\u548C\u7B2C 3 \u6B65\u3002</strong></p>
<p>\u56E0\u4E3A Lupine \u4F7F\u7528 <strong>\u624B\u52A8\u54CD\u5E94\u5F0F (HtmlVar<a href="javascript:lpPressLoad('/zh/lupine.components/html-var')">\u{1F517}</a>)</strong>\uFF0C\u4F60\u53EF\u4EE5\u76F4\u63A5\u901A\u8FC7 <code>dom.value = &lt;&gt;...&lt;/&gt;</code> \u6765\u66F4\u65B0\u7279\u5B9A\u7684 DOM \u5143\u7D20\uFF0C\u800C\u65E0\u9700\u89E6\u53D1\u81EA\u4E0A\u800C\u4E0B\u7684\u91CD\u6E32\u67D3\u3002\u8FD9\u7C7B\u4F3C\u4E8E\u5728 React \u4E2D\u4F7F\u7528\u6781\u5176\u4F18\u5316\u7684 <code>React.memo</code> \u7EC4\u4EF6\uFF0C\u4F46\u5728 Lupine.js \u4E2D\uFF0C\u8FD9\u662F <strong>\u9ED8\u8BA4\u884C\u4E3A</strong>\uFF0C\u800C\u975E\u4E00\u79CD\u53EF\u9009\u7684\u4F18\u5316\u624B\u6BB5\u3002</p>
<h2 id="2-\u70B9\u5BF9\u70B9\u66F4\u65B0-spot-update-\u7B56\u7565"><a class="header-anchor" href="#2-\u70B9\u5BF9\u70B9\u66F4\u65B0-spot-update-\u7B56\u7565">#</a>2. \u{1F3AF} &quot;\u70B9\u5BF9\u70B9\u66F4\u65B0 (Spot-Update)&quot; \u7B56\u7565</h2><p>\u5217\u8868\u4E2D\u7684\u6BCF\u4E00\u884C\u90FD\u5145\u5F53\u4E00\u4E2A\u5B64\u5C9B\u3002\u5B83\u62E5\u6709\u81EA\u5DF1\u7684 <code>HtmlVar</code> \u548C <code>ref</code>\u3002\u5F53\u6570\u636E\u53D1\u751F\u53D8\u5316\u65F6\uFF0C\u4F60\u53EA\u9700\u5728\u8BE5\u7279\u5B9A\u884C\u7684\u53D8\u91CF\u4E0A\u8C03\u7528 <code>.value = ...</code>\u3002\u9875\u9762\u7684\u5176\u4F59\u90E8\u5206\u4FDD\u6301\u4E3A\u9759\u6001\u7684 HTML \u5B57\u7B26\u4E32\uFF0C\u7EF4\u62A4\u6210\u672C\u4E3A <strong>\u96F6</strong>\u3002</p>
<h3 id="\u4F18\u52BF"><a class="header-anchor" href="#\u4F18\u52BF">#</a>\u4F18\u52BF</h3><ul>
<li><strong>\u96F6 Diff \u6210\u672C</strong>\uFF1A\u6539\u53D8\u4E00\u884C\u7684\u5F00\u9500\u662F <code>O(1)</code>\uFF0C\u800C\u4E0D\u662F <code>O(N)</code>\uFF08N \u4E3A\u5217\u8868\u5927\u5C0F\uFF09\u3002</li>
<li><strong>\u53EF\u9884\u6D4B\u7684\u6027\u80FD</strong>\uFF1A\u6CA1\u6709\u201C\u6D6A\u8D39\u7684\u6E32\u67D3 (wasted renders)\u201D\u3002</li>
<li><strong>\u4F4E\u5185\u5B58\u5360\u7528</strong>\uFF1A\u6211\u4EEC\u4E0D\u9700\u8981\u4E3A\u5217\u8868\u7684\u9759\u6001\u90E8\u5206\u5728\u5185\u5B58\u4E2D\u7EF4\u62A4\u4E00\u68F5\u6C89\u91CD\u7684\u865A\u62DF DOM \u6811\u3002</li>
</ul>
<hr>
<h2 id="3-\u4EE3\u7801\u793A\u4F8B-\u53EF\u7F16\u8F91\u5217\u8868"><a class="header-anchor" href="#3-\u4EE3\u7801\u793A\u4F8B-\u53EF\u7F16\u8F91\u5217\u8868">#</a>3. \u{1F4BB} \u4EE3\u7801\u793A\u4F8B\uFF1A\u53EF\u7F16\u8F91\u5217\u8868</h2><p>\u4E0B\u9762\u5C55\u793A\u4E86\u5982\u4F55\u5B9E\u73B0\u4E00\u4E2A\u9AD8\u6027\u80FD\u7684\u53EF\u7F16\u8F91\u5217\u8868\u3002</p>
<h3 id="\u7B2C\u4E00\u6B65-\u5217\u8868\u5BB9\u5668-\u7236\u7EC4\u4EF6"><a class="header-anchor" href="#\u7B2C\u4E00\u6B65-\u5217\u8868\u5BB9\u5668-\u7236\u7EC4\u4EF6">#</a>\u{1F4E6} \u7B2C\u4E00\u6B65\uFF1A\u5217\u8868\u5BB9\u5668\uFF08\u7236\u7EC4\u4EF6\uFF09</h3><p>\u7236\u7EC4\u4EF6\u8D1F\u8D23\u521D\u59CB\u5316\u6E32\u67D3\u5217\u8868\uFF0C\u4F46\u5F53\u5B50\u9879\u53D1\u751F\u53D8\u5316\u65F6\uFF0C<strong>\u4E0D\u9700\u8981</strong>\u91CD\u65B0\u6E32\u67D3\u3002</p>
<pre><code class="language-tsx">// BookList.tsx
export const BookList = () =&gt; {
  // 1. \u521D\u59CB\u6570\u636E\u52A0\u8F7D
  let items = getSampleData();

  // 2. \u6E32\u67D3\u9759\u6001\u5217\u8868
  // \u6CE8\u610F\uFF1A\u5982\u679C\u6211\u4EEC\u53EA\u662F\u7F16\u8F91\u9879\u76EE\uFF0C\u6211\u4EEC\u4E0D\u9700\u8981\u4E3A\u6574\u4E2A\u5217\u8868\u7EF4\u62A4 State\uFF01
  return (
    &lt;div class=&#39;list&#39;&gt;
      {items.map((item) =&gt; (
        &lt;BookShowItem key={item.id} item={item} /&gt;
      ))}
    &lt;/div&gt;
  );
};
</code></pre>
<h3 id="\u7B2C\u4E8C\u6B65-\u4F18\u5316\u540E\u7684\u884C-\u5B50\u7EC4\u4EF6"><a class="header-anchor" href="#\u7B2C\u4E8C\u6B65-\u4F18\u5316\u540E\u7684\u884C-\u5B50\u7EC4\u4EF6">#</a>\u26A1 \u7B2C\u4E8C\u6B65\uFF1A\u4F18\u5316\u540E\u7684\u884C\uFF08\u5B50\u7EC4\u4EF6\uFF09</h3><p>\u5B50\u7EC4\u4EF6\u5C06\u5185\u5BB9\u5305\u88F9\u5728 <code>HtmlVar</code> \u4E2D\u3002\u8FD9\u5141\u8BB8\u5B83\u72EC\u7ACB\u5730\u201C\u91CD\u7ED8\u201D\u81EA\u5DF1\u3002</p>
<pre><code class="language-tsx">// BookShowItem.tsx
import { HtmlVar, RefProps } from &#39;lupine.components&#39;;

export const BookShowItem = (props: { item: SampleDataProps }) =&gt; {
  const ref: RefProps = { id: &#39;&#39; };

  // 1. \u5B9A\u4E49\u5185\u90E8\u6E32\u67D3\u903B\u8F91
  const makeDom = (item: SampleDataProps) =&gt; (
    &lt;div class=&#39;row-box&#39;&gt;
      &lt;div&gt;Name: {item.name}&lt;/div&gt;
      &lt;button onClick={onEdit}&gt;\u7F16\u8F91&lt;/button&gt;
    &lt;/div&gt;
  );

  // 2. \u4E3A\u8FD9\u4E00\u884C\u521B\u5EFA\u4E00\u4E2A &quot;\u54CD\u5E94\u5F0F\u76D2\u5B50 (Reactive Box)&quot;
  const dom = new HtmlVar(makeDom(props.item));

  // 3. \u66F4\u65B0\u903B\u8F91\uFF1A\u53EA\u66F4\u65B0\u8FD9\u4E00\u4E2A DOM\uFF01
  const update = (newItem: SampleDataProps) =&gt; {
    // \u624B\u52A8\u89E6\u53D1\u4EC5\u9488\u5BF9\u6B64\u884C\u7684\u66F4\u65B0
    dom.value = makeDom(newItem);
  };

  const onEdit = () =&gt; {
    // \u663E\u793A\u6A21\u6001\u6846\uFF0C\u83B7\u53D6\u65B0\u6570\u636E\uFF0C\u7136\u540E\u8C03\u7528 update(newItem)
    showEditModal(props.item, (newItem) =&gt; {
      update(newItem);
    });
  };

  return (
    &lt;div ref={ref} class=&#39;sample-data-row&#39;&gt;
      {dom.node} {/* \u4F7F\u7528 dom.node \u5D4C\u5165\u54CD\u5E94\u5F0F\u63D2\u69FD */}
    &lt;/div&gt;
  );
};
</code></pre>
<h3 id="\u7B2C\u4E09\u6B65-\u884C\u5185\u7F16\u8F91-\u8FDB\u9636"><a class="header-anchor" href="#\u7B2C\u4E09\u6B65-\u884C\u5185\u7F16\u8F91-\u8FDB\u9636">#</a>\u270F\uFE0F \u7B2C\u4E09\u6B65\uFF1A\u884C\u5185\u7F16\u8F91\uFF08\u8FDB\u9636\uFF09</h3><p>\u4F60\u751A\u81F3\u53EF\u4EE5\u5B8C\u5168\u4E3A\u5355\u884C\u5207\u6362\u201C\u67E5\u770B\u6A21\u5F0F\u201D\u4E0E\u201C\u7F16\u8F91\u6A21\u5F0F\u201D\uFF0C\u800C\u4E0D\u5F71\u54CD\u5176\u4ED6\u884C\u3002</p>
<pre><code class="language-tsx">// BookShowItem \u5185\u90E8
const onToggleEdit = () =&gt; {
  if (isEditing) {
    dom.value = makeViewMode(item);
  } else {
    dom.value = makeEditMode(item);
  }
  isEditing = !isEditing;
};
</code></pre>
<h2 id="\u603B\u7ED3"><a class="header-anchor" href="#\u603B\u7ED3">#</a>\u603B\u7ED3</h2><p>\u867D\u7136\u8FD9\u79CD\u65B9\u6CD5\u9700\u8981\u7F16\u5199\u7A0D\u5FAE\u591A\u4E00\u70B9\u7684\u201C\u663E\u5F0F\u201D\u4EE3\u7801\uFF08\u5B9A\u4E49 <code>HtmlVar</code> \u548C <code>makeDom</code>\uFF09\uFF0C\u4F46\u5B83\u4E3A\u4F60\u63D0\u4F9B\u4E86\u5728\u91CD\u6570\u636E\u5E94\u7528\u4E2D\u96BE\u4EE5\u5339\u654C\u7684 <strong>\u63A7\u5236\u529B</strong> \u548C <strong>\u9AD8\u6027\u80FD</strong>\u3002\u5B9E\u9645\u4E0A\uFF0C\u4F60\u5C31\u50CF\u662F\u81EA\u5DF1\u7684\u201C\u7F16\u8BD1\u5668\u201D\uFF0C\u7CBE\u786E\u5730\u544A\u8BC9\u6D4F\u89C8\u5668\u5728\u4F55\u65F6\u66F4\u65B0\u4EC0\u4E48\u5185\u5BB9\u3002</p>
`;

  // apps/doc/web/src/markdown-built/zh/essentials/mobile-desktop.html
  var mobile_desktop_default2 = '<h1 id="\u79FB\u52A8\u7AEF\u548C\u684C\u9762\u7AEF\u9002\u914D-mobile-desktop"><a class="header-anchor" href="#\u79FB\u52A8\u7AEF\u548C\u684C\u9762\u7AEF\u9002\u914D-mobile-desktop">#</a>\u79FB\u52A8\u7AEF\u548C\u684C\u9762\u7AEF\u9002\u914D (Mobile &amp; Desktop)</h1><p>Lupine.js \u7684\u6838\u5FC3\u8BBE\u8BA1\u7406\u5FF5\u4E4B\u4E00\u662F\u201C\u4E00\u5957\u4EE3\u7801\uFF0C\u591A\u7AEF\u8FD0\u884C\u201D\u3002\u901A\u8FC7\u5185\u7F6E\u7684\u54CD\u5E94\u5F0F\u8BBE\u8BA1\u5DE5\u5177\u548C\u7EC4\u4EF6\uFF0C\u4F60\u53EF\u4EE5\u8F7B\u677E\u6784\u5EFA\u540C\u65F6\u9002\u5E94 Web\u3001\u79FB\u52A8\u7AEF\uFF08iOS/Android\uFF09\u548C\u684C\u9762\u7AEF\uFF08Electron\uFF09\u7684\u5E94\u7528\u7A0B\u5E8F\u3002</p>\n<h2 id="1-\u54CD\u5E94\u5F0F\u5E03\u5C40-media-query"><a class="header-anchor" href="#1-\u54CD\u5E94\u5F0F\u5E03\u5C40-media-query">#</a>1. \u54CD\u5E94\u5F0F\u5E03\u5C40 (Media Query)</h2><p><code>lupine.components</code> \u63D0\u4F9B\u4E86\u5F3A\u5927\u7684\u5A92\u4F53\u67E5\u8BE2\u5DE5\u5177\uFF0C\u5E2E\u52A9\u4F60\u6839\u636E\u5C4F\u5E55\u5BBD\u5EA6\u8C03\u6574\u5E03\u5C40\u3002</p>\n<h3 id="\u65AD\u70B9\u5B9A\u4E49-breakpoints"><a class="header-anchor" href="#\u65AD\u70B9\u5B9A\u4E49-breakpoints">#</a>\u65AD\u70B9\u5B9A\u4E49 (Breakpoints)</h3><p>\u7CFB\u7EDF\u9884\u5B9A\u4E49\u4E86\u4EE5\u4E0B\u65AD\u70B9\uFF08\u53EF\u5728 <code>MediaQueryMaxWidth</code> \u4E2D\u81EA\u5B9A\u4E49\uFF09\uFF1A</p>\n<ul>\n<li><strong>ExtraSmall</strong>: &lt; 480px</li>\n<li><strong>Mobile</strong>: &lt; 767px (Grid: col-1)</li>\n<li><strong>Tablet</strong>: &lt; 991px (Grid: col-1-md)</li>\n<li><strong>Desktop</strong>: &lt; 1399px (Grid: col-1-lg)</li>\n</ul>\n<h3 id="\u5728-css-in-js-\u4E2D\u4F7F\u7528"><a class="header-anchor" href="#\u5728-css-in-js-\u4E2D\u4F7F\u7528">#</a>\u5728 CSS-in-JS \u4E2D\u4F7F\u7528</h3><p>\u4F60\u53EF\u4EE5\u4F7F\u7528 <code>MediaQueryRange</code> \u8F7B\u677E\u7F16\u5199\u54CD\u5E94\u5F0F\u6837\u5F0F\uFF1A</p>\n<pre><code class="language-tsx">import { MediaQueryRange, MediaQueryMaxWidth } from &#39;lupine.components&#39;;\n\nconst css: CssProps = {\n  width: &#39;100%&#39;,\n  // \u9ED8\u8BA4\u684C\u9762\u7AEF\u6837\u5F0F\n  maxWidth: MediaQueryMaxWidth.DesktopMax,\n\n  // \u9488\u5BF9\u8D85\u5C0F\u5C4F\u5E55\uFF08\u624B\u673A\u7AD6\u5C4F\uFF09\u7684\u8C03\u6574\n  [MediaQueryRange.ExtraSmallBelow]: {\n    padding: &#39;10px&#39;,\n    fontSize: &#39;14px&#39;,\n  },\n\n  // \u9488\u5BF9\u5E73\u677F\u53CA\u4EE5\u4E0B\n  [MediaQueryRange.TabletBelow]: {\n    flexDirection: &#39;column&#39;,\n  },\n};\n</code></pre>\n<h2 id="2-\u81EA\u9002\u5E94\u6846\u67B6-adaptive-frames"><a class="header-anchor" href="#2-\u81EA\u9002\u5E94\u6846\u67B6-adaptive-frames">#</a>2. \u81EA\u9002\u5E94\u6846\u67B6 (Adaptive Frames)</h2><p>Lupine \u63D0\u4F9B\u4E86\u4E13\u95E8\u7528\u4E8E\u6784\u5EFA\u54CD\u5E94\u5F0F\u5E94\u7528\u7684\u6846\u67B6\u7EC4\u4EF6\u3002</p>\n<h3 id="responsiveframe"><a class="header-anchor" href="#responsiveframe">#</a>ResponsiveFrame</h3><p><code>ResponsiveFrame</code> \u662F\u5904\u7406\u6DF7\u5408\u5E03\u5C40\u7684\u7EC8\u6781\u89E3\u51B3\u65B9\u6848\u3002\u5B83\u80FD\u81EA\u52A8\u6839\u636E\u8BBE\u5907\u7C7B\u578B\u5207\u6362 UI \u7ED3\u6784\uFF1A</p>\n<ul>\n<li><strong>\u684C\u9762\u7AEF</strong>: \u663E\u793A\u9876\u90E8\u83DC\u5355 (<code>DesktopHeader</code>)\u3001\u5E95\u90E8\u9875\u811A (<code>DesktopFooter</code>) \u548C\u4FA7\u8FB9\u680F\u3002</li>\n<li><strong>\u79FB\u52A8\u7AEF</strong>: \u81EA\u52A8\u5207\u6362\u4E3A\u79FB\u52A8\u7AEF\u5E03\u5C40\uFF0C\u9690\u85CF\u684C\u9762\u7AEF\u7279\u6709\u5143\u7D20\uFF0C\u542F\u7528\u79FB\u52A8\u7AEF\u7279\u5B9A\u7684\u5BFC\u822A (<code>MobileBottomMenu</code>)\u3002</li>\n</ul>\n<pre><code class="language-tsx">&lt;ResponsiveFrame\n  desktopHeaderTitle=&quot;\u6211\u7684\u5E94\u7528&quot;\n  desktopTopMenu={[...]}\n  mobileBottomMenu={[...]}\n  mainContent={&lt;MyPageContent /&gt;}\n/&gt;\n</code></pre>\n<h3 id="sliderframe"><a class="header-anchor" href="#sliderframe">#</a>SliderFrame</h3><p><code>SliderFrame</code> \u5B9E\u73B0\u4E86\u79FB\u52A8\u7AEF\u5E38\u89C1\u7684\u201C\u4FA7\u6ED1\u201D\u4EA4\u4E92\u4F53\u9A8C\u3002\u5B83\u901A\u5E38\u7528\u4E8E\u4ECE\u53F3\u4FA7\u6ED1\u51FA\u8BE6\u7EC6\u9875\u9762\uFF0C\u6216\u4ECE\u5E95\u90E8\u6ED1\u51FA\u83DC\u5355\u3002</p>\n<ul>\n<li>\u652F\u6301 <code>Right-to-Left</code> (\u53F3\u6ED1\u5165) \u548C <code>Bottom-to-Top</code> (\u4E0A\u6ED1\u5165) \u52A8\u753B\u3002</li>\n<li>\u5728\u684C\u9762\u7AEF\u53EF\u914D\u7F6E\u4E3A\u4FA7\u8FB9\u680F\u5F39\u51FA\u6A21\u5F0F\u3002</li>\n</ul>\n<h2 id="3-\u79FB\u52A8\u7AEF\u5BFC\u822A\u4E0E\u4EA4\u4E92"><a class="header-anchor" href="#3-\u79FB\u52A8\u7AEF\u5BFC\u822A\u4E0E\u4EA4\u4E92">#</a>3. \u79FB\u52A8\u7AEF\u5BFC\u822A\u4E0E\u4EA4\u4E92</h2><h3 id="\u5168\u5C40\u8FD4\u56DE\u952E\u5904\u7406-backactionhelper"><a class="header-anchor" href="#\u5168\u5C40\u8FD4\u56DE\u952E\u5904\u7406-backactionhelper">#</a>\u5168\u5C40\u8FD4\u56DE\u952E\u5904\u7406 (BackActionHelper)</h3><p>\u5728\u79FB\u52A8\u5E94\u7528\uFF08\u7279\u522B\u662F Android\uFF09\u4E2D\uFF0C\u5904\u7406\u7269\u7406\u8FD4\u56DE\u952E\u81F3\u5173\u91CD\u8981\u3002<code>BackActionHelper</code> \u63D0\u4F9B\u4E86\u4E00\u4E2A\u5168\u5C40\u961F\u5217\u6765\u7BA1\u7406\u8FD4\u56DE\u884C\u4E3A\uFF0C\u786E\u4FDD\u7528\u6237\u4F53\u9A8C\u6D41\u7545\u3002</p>\n<p><strong>\u4F7F\u7528\u793A\u4F8B</strong>:</p>\n<pre><code class="language-typescript">import { backActionHelper } from &#39;lupine.components&#39;;\n\n// \u76D1\u542C\u786C\u4EF6\u8FD4\u56DE\u952E\uFF08\u901A\u5E38\u5728 index.ts \u6216 app-listeners.ts \u4E2D\uFF09\nApp.addListener(&#39;backButton&#39;, async () =&gt; {\n  // \u5982\u679C helper \u5904\u7406\u4E86\u8FD4\u56DE\u52A8\u4F5C\uFF08\u4F8B\u5982\u5173\u95ED\u4E86\u4E00\u4E2A\u5F39\u7A97\uFF09\uFF0C\u5219\u505C\u6B62\n  if (await backActionHelper.processBackAction()) {\n    return;\n  }\n  // \u5426\u5219\u6267\u884C\u9000\u51FA\u5E94\u7528\u6216\u5176\u4ED6\u903B\u8F91\n});\n</code></pre>\n<h3 id="actionsheet-\u52A8\u4F5C\u9762\u677F"><a class="header-anchor" href="#actionsheet-\u52A8\u4F5C\u9762\u677F">#</a>ActionSheet (\u52A8\u4F5C\u9762\u677F)</h3><p><code>ActionSheet</code> \u662F\u79FB\u52A8\u7AEF\u975E\u5E38\u5E38\u7528\u7684\u5E95\u90E8\u5F39\u7A97\u7EC4\u4EF6\uFF0C\u7528\u4E8E\u9009\u9879\u9009\u62E9\u3001\u4FE1\u606F\u63D0\u793A\u6216\u7B80\u5355\u7684\u8F93\u5165\u3002</p>\n<ul>\n<li><strong>ActionSheetSelect</strong>: \u5E95\u90E8\u9009\u9879\u83DC\u5355\u3002</li>\n<li><strong>ActionSheetInput</strong>: \u5E95\u90E8\u8F93\u5165\u6846\u3002</li>\n<li><strong>ActionSheetMessage</strong>: \u5E95\u90E8\u6D88\u606F\u63D0\u793A\u3002</li>\n</ul>\n<pre><code class="language-tsx">import { ActionSheetSelectPromise } from &#39;lupine.components&#39;;\n\nconst handleSelect = async () =&gt; {\n  const index = await ActionSheetSelectPromise({\n    title: &#39;\u8BF7\u9009\u62E9\u64CD\u4F5C&#39;,\n    options: [&#39;\u7F16\u8F91&#39;, &#39;\u5220\u9664&#39;, &#39;\u5206\u4EAB&#39;],\n    cancelButtonText: &#39;\u53D6\u6D88&#39;,\n  });\n\n  if (index === 0) {\n    // \u7F16\u8F91\u903B\u8F91\n  }\n};\n</code></pre>\n<h3 id="mobileheader-\u79FB\u52A8\u7AEF\u6807\u9898\u680F"><a class="header-anchor" href="#mobileheader-\u79FB\u52A8\u7AEF\u6807\u9898\u680F">#</a>MobileHeader (\u79FB\u52A8\u7AEF\u6807\u9898\u680F)</h3><p><code>MobileHeaderComponent</code> \u63D0\u4F9B\u4E86\u7075\u6D3B\u7684\u5934\u90E8\u5B9A\u5236\u529F\u80FD\u3002\u4F60\u53EF\u4EE5\u968F\u65F6\u901A\u8FC7 <code>MobileHeaderHelper</code> \u6216\u8F85\u52A9\u7EC4\u4EF6\u66F4\u65B0\u6807\u9898\u680F\u7684\u5DE6\u3001\u4E2D\u3001\u53F3\u533A\u57DF\u3002</p>\n<pre><code class="language-tsx">// \u5728\u9875\u9762\u7EC4\u4EF6\u4E2D\u52A8\u6001\u66F4\u65B0 Header\n&lt;MobileHeaderCenter&gt;\n  &lt;MobileHeaderTitleIcon title=&#39;\u7528\u6237\u8BBE\u7F6E&#39; left={&lt;BackIcon /&gt;} right={&lt;SaveIcon /&gt;} /&gt;\n&lt;/MobileHeaderCenter&gt;\n</code></pre>\n<h3 id="slidetabcomponent-\u6ED1\u52A8\u6807\u7B7E\u9875"><a class="header-anchor" href="#slidetabcomponent-\u6ED1\u52A8\u6807\u7B7E\u9875">#</a>SlideTabComponent (\u6ED1\u52A8\u6807\u7B7E\u9875)</h3><p>\u652F\u6301\u624B\u52BF\u5DE6\u53F3\u6ED1\u52A8\u7684 Tab \u5207\u6362\u7EC4\u4EF6\uFF0C\u63D0\u4F9B\u63A5\u8FD1\u539F\u751F\u5E94\u7528\u7684\u6D41\u7545\u4F53\u9A8C\u3002</p>\n<pre><code class="language-tsx">&lt;SlideTabComponent\n  pages={[\n    { title: &#39;\u70ED\u95E8&#39;, content: &lt;HotList /&gt; },\n    { title: &#39;\u6700\u65B0&#39;, content: &lt;NewList /&gt; },\n  ]}\n/&gt;\n\n## 4. \u79FB\u52A8\u7AEF\u53D1\u5E03 (Mobile Deployment)\n\nLupine.js \u63A8\u8350\u4F7F\u7528 **Capacitor** \u5C06 Web \u5E94\u7528\u6253\u5305\u4E3A\u539F\u751F\u79FB\u52A8\u5E94\u7528\u3002\n\n### \u79FB\u52A8\u7AEF\u914D\u7F6E\n\n\u7531\u4E8E\u79FB\u52A8\u7AEF\u5E94\u7528\u901A\u5E38\u662F\u4F5C\u4E3A\u72EC\u7ACB\u6587\u4EF6\u8FD0\u884C\uFF08`file://` \u534F\u8BAE\uFF09\uFF0CAPI \u8BF7\u6C42\u4E0D\u80FD\u50CF Web \u90A3\u6837\u4F7F\u7528\u76F8\u5BF9\u8DEF\u5F84\u3002\u4F60\u9700\u8981\u914D\u7F6E `.env.mobile` \u6765\u6307\u5B9A\u7EDD\u5BF9 API \u5730\u5740\u3002\n\n**\u6784\u5EFA\u547D\u4EE4**:\n```bash\n# \u4F7F\u7528 .env.mobile \u914D\u7F6E\u8FDB\u884C\u6784\u5EFA\nnpm run build-mobile\n</code></pre>\n<p>\u6B64\u547D\u4EE4\u5BF9\u5E94 <code>package.json</code> \u4E2D\u7684\u811A\u672C\uFF1A\n<code>node ./dev/dev-watch --env=.env.mobile --dev=0 --mobile=1</code></p>\n<h3 id="\u6761\u4EF6\u7F16\u8BD1-conditional-compilation"><a class="header-anchor" href="#\u6761\u4EF6\u7F16\u8BD1-conditional-compilation">#</a>\u6761\u4EF6\u7F16\u8BD1 (Conditional Compilation)</h3><p>Lupine \u63D0\u4F9B\u4E86 <code>pluginIfelse</code> \u63D2\u4EF6\uFF0C\u5141\u8BB8\u4F60\u7F16\u5199\u9488\u5BF9\u7279\u5B9A\u5E73\u53F0\u7684\u903B\u8F91\u4EE3\u7801\u3002\u8FD9\u5BF9\u4E8E\u5904\u7406\u79FB\u52A8\u7AEF\u7279\u6709\u7684 API \u7AEF\u70B9\u6216\u903B\u8F91\u975E\u5E38\u6709\u7528\u3002</p>\n<p><strong>\u4F7F\u7528\u793A\u4F8B</strong>:</p>\n<pre><code class="language-javascript">// #if MOBILE\nconst apiBase = &#39;https://api.myapp.com&#39;;\n// #else\nconst apiBase = &#39;/api&#39;;\n// #endif\n\n// #if DEV\nconsole.log(&#39;Debug mode&#39;);\n// #endif\n</code></pre>\n<blockquote>\n<p>\u53EA\u6709\u6EE1\u8DB3\u6761\u4EF6\u7684\u4EE3\u7801\u5757\u4F1A\u88AB\u7F16\u8BD1\u5230\u6700\u7EC8\u4EA7\u7269\u4E2D\uFF0C\u4ECE\u800C\u51CF\u5C0F\u5305\u4F53\u79EF\u5E76\u907F\u514D\u8FD0\u884C\u65F6\u9519\u8BEF\u3002</p>\n</blockquote>\n<h3 id="\u6DFB\u52A0-ios-\u548C-android"><a class="header-anchor" href="#\u6DFB\u52A0-ios-\u548C-android">#</a>\u6DFB\u52A0 iOS \u548C Android</h3><p>\u8BF7\u53C2\u8003 Capacitor \u5B98\u65B9\u6587\u6863\u4E86\u89E3\u8BE6\u7EC6\u7684\u6DFB\u52A0\u5E73\u53F0\u6B65\u9AA4\uFF1A\n<a href="https://capacitorjs.com/docs/getting-started">https://capacitorjs.com/docs/getting-started</a></p>\n<h2 id="5-\u684C\u9762\u7AEF\u53D1\u5E03-desktop-deployment"><a class="header-anchor" href="#5-\u684C\u9762\u7AEF\u53D1\u5E03-desktop-deployment">#</a>5. \u684C\u9762\u7AEF\u53D1\u5E03 (Desktop Deployment)</h2><p>Lupine.js \u4F7F\u7528 <strong>Electron</strong> \u6765\u6784\u5EFA\u8DE8\u5E73\u53F0\u684C\u9762\u5E94\u7528\u3002</p>\n<h3 id="\u684C\u9762\u7AEF\u7ED3\u6784"><a class="header-anchor" href="#\u684C\u9762\u7AEF\u7ED3\u6784">#</a>\u684C\u9762\u7AEF\u7ED3\u6784</h3><p>\u5F53\u4F60\u521B\u5EFA\u4E00\u4E2A\u65B0\u7684 Lupine \u9879\u76EE\u65F6\uFF0C\u5B83\u4F1A\u81EA\u52A8\u5305\u542B\u4E00\u4E2A <code>electron</code> \u76EE\u5F55\uFF08\u4F8B\u5982 <code>apps/your-app/electron</code>\uFF09\uFF0C\u5176\u4E2D\u5305\u542B\u4E86\u684C\u9762\u7AEF\u6240\u9700\u7684\u4E3B\u8FDB\u7A0B\u4EE3\u7801\u548C\u8D44\u6E90\u3002</p>\n<ul>\n<li>\u60A8\u7684 Web \u4EE3\u7801\u76F4\u63A5\u4F5C\u4E3A Electron \u7684\u6E32\u67D3\u8FDB\u7A0B\u8FD0\u884C\u3002</li>\n<li><code>lupine.components</code> \u80FD\u591F\u81EA\u52A8\u68C0\u6D4B\u8FD0\u884C\u73AF\u5883\uFF0C\u9002\u914D\u684C\u9762\u7AEF UI\uFF08\u5982\u9690\u85CF\u4E0D\u5FC5\u8981\u7684\u79FB\u52A8\u7AEF Tab\uFF09\u3002</li>\n</ul>\n<h3 id="\u6784\u5EFA\u547D\u4EE4"><a class="header-anchor" href="#\u6784\u5EFA\u547D\u4EE4">#</a>\u6784\u5EFA\u547D\u4EE4</h3><p><code>package.json</code> \u63D0\u4F9B\u4E86\u9884\u7F6E\u7684\u6784\u5EFA\u811A\u672C\uFF0C\u7528\u4E8E\u7F16\u8BD1\u4E0D\u540C\u5E73\u53F0\u7684\u5B89\u88C5\u5305\uFF1A</p>\n<pre><code class="language-bash"># Windows\nnpm run app1:build-win\n\n# Linux\nnpm run app1:build-linux\n\n# macOS\nnpm run app1:build-mac\n</code></pre>\n<p>\u60A8\u53EF\u4EE5\u5728 <code>package.json</code> \u7684 <code>scripts</code> \u533A\u57DF\u627E\u5230\u5E76\u81EA\u5B9A\u4E49\u8FD9\u4E9B\u547D\u4EE4\u3002</p>\n';

  // apps/doc/web/src/markdown-built/zh/essentials/page-route.html
  var page_route_default2 = '<h1 id="page-router-\u9875\u9762\u8DEF\u7531"><a class="header-anchor" href="#page-router-\u9875\u9762\u8DEF\u7531">#</a>Page Router (\u9875\u9762\u8DEF\u7531)</h1><p><strong>Lupine.web</strong> \u4E2D\u7684 <code>PageRouter</code> \u662F\u4E00\u4E2A\u5F3A\u5927\u7684\u5BA2\u6237\u7AEF\u8DEF\u7531\u7CFB\u7EDF\uFF0C\u5176\u903B\u8F91\u8BBE\u8BA1\u4E0E\u540E\u7AEF\u7684 <code>ApiRouter</code> (\u4F4D\u4E8E <code>lupine.api</code> \u4E2D) \u4FDD\u6301 <strong>\u540C\u6784</strong>\u3002\u5B83\u652F\u6301\u5D4C\u5957\u8DEF\u7531\u3001\u4E2D\u95F4\u4EF6\u8FC7\u6EE4\u5668\u3001\u52A8\u6001\u53C2\u6570\u548C\u5E03\u5C40\u6846\u67B6 (Layout Frames)\u3002</p>\n<h2 id="1-\u4E0E\u5176\u4ED6\u6846\u67B6\u7684\u5BF9\u6BD4"><a class="header-anchor" href="#1-\u4E0E\u5176\u4ED6\u6846\u67B6\u7684\u5BF9\u6BD4">#</a>1. \u2696\uFE0F \u4E0E\u5176\u4ED6\u6846\u67B6\u7684\u5BF9\u6BD4</h2><p>\u4E0E\u901A\u7528\u7684\u8DEF\u7531\u5668\uFF08\u5982 <code>react-router</code> \u6216 <code>vue-router</code>\uFF09\u76F8\u6BD4\uFF1A</p>\n<ul>\n<li><strong>\u903B\u8F91\u4E00\u81F4\u6027</strong>\uFF1A\u5B83\u4E0E\u540E\u7AEF\u7684 <code>ApiRouter</code> \u5171\u4EAB\u5B8C\u5168\u76F8\u540C\u7684\u8DEF\u7531\u54F2\u5B66\u3002\u5982\u679C\u4F60\u77E5\u9053\u5982\u4F55\u7F16\u5199 Lupine \u540E\u7AEF API\uFF0C\u4F60\u5C31\u77E5\u9053\u5982\u4F55\u7F16\u5199\u524D\u7AEF\u8DEF\u7531\u3002</li>\n<li><strong>\u771F\u6B63\u7684\u5D4C\u5957</strong>\uFF1A\u4F60\u53EF\u4EE5\u5C06\u4E00\u4E2A\u5B8C\u6574\u7684 <code>PageRouter</code> \u5B9E\u4F8B\u6302\u8F7D\u5230\u53E6\u4E00\u4E2A\u8DEF\u7531\u5668\u7684\u7279\u5B9A\u8DEF\u5F84\u4E0A\uFF08\u4F8B\u5982\uFF1A<code>router.use(&#39;/user&#39;, userRouter)</code>\uFF09\uFF0C\u4ECE\u800C\u5B9E\u73B0\u771F\u6B63\u7684\u6A21\u5757\u5316\u3002</li>\n<li><strong>\u5185\u7F6E\u5E03\u5C40</strong>\uFF1A<code>setFramePage</code> \u5C06\u5E03\u5C40\u89C6\u4E3A\u4E00\u7B49\u516C\u6C11\uFF0C\u80FD\u591F\u5C06\u5185\u5BB9\u6CE8\u5165\u5230\u7279\u5B9A\u7684\u5360\u4F4D\u7B26\u7C7B\u4E2D\u3002</li>\n</ul>\n<h2 id="2-\u57FA\u672C\u7528\u6CD5"><a class="header-anchor" href="#2-\u57FA\u672C\u7528\u6CD5">#</a>2. \u{1F423} \u57FA\u672C\u7528\u6CD5</h2><p>\u6700\u7B80\u5355\u7684\u5F00\u59CB\u65B9\u6CD5\u662F\u5C06\u8DEF\u5F84\u6620\u5C04\u5230\u9875\u9762\u7EC4\u4EF6\u3002</p>\n<pre><code class="language-tsx">import { PageRouter, bindRouter } from &#39;lupine.web&#39;;\n\n// 1. \u521B\u5EFA Router\nconst pageRouter = new PageRouter();\n\n// 2. \u5B9A\u4E49\u8DEF\u7531\npageRouter.use(&#39;/home&#39;, HomePage);\npageRouter.use(&#39;/about&#39;, AboutPage);\n// 404 \u901A\u914D\u7B26\npageRouter.use(&#39;*&#39;, NotFoundPage);\n\n// 3. \u7ED1\u5B9A\u5230\u7CFB\u7EDF\nbindRouter(pageRouter);\n</code></pre>\n<h2 id="3-\u52A8\u6001\u53C2\u6570"><a class="header-anchor" href="#3-\u52A8\u6001\u53C2\u6570">#</a>3. \u{1F527} \u52A8\u6001\u53C2\u6570</h2><p>Lupine \u76F4\u63A5\u5728 URL \u5B57\u7B26\u4E32\u4E2D\u652F\u6301\u5FC5\u9009\u548C\u53EF\u9009\u53C2\u6570\u3002\u6240\u6709\u6355\u83B7\u7684\u53C2\u6570\u90FD\u53EF\u4EE5\u5728 <code>props.urlParameters</code> \u4E2D\u83B7\u53D6\u3002</p>\n<h3 id="\u8BED\u6CD5"><a class="header-anchor" href="#\u8BED\u6CD5">#</a>\u8BED\u6CD5</h3><ul>\n<li><code>/:id</code> : \u5FC5\u9009\u53C2\u6570\u3002</li>\n<li><code>/?id</code> : \u53EF\u9009\u53C2\u6570\u3002\uFF08\u6240\u6709\u540E\u7EED\u53C2\u6570\u4E5F\u5FC5\u987B\u662F\u53EF\u9009\u7684\uFF09\u3002</li>\n<li><code>?key=value</code> : \u4E5F\u652F\u6301\u6807\u51C6\u7684\u67E5\u8BE2\u5B57\u7B26\u4E32\uFF08\u5355\u72EC\u89E3\u6790\uFF09\u3002</li>\n</ul>\n<h3 id="\u793A\u4F8B"><a class="header-anchor" href="#\u793A\u4F8B">#</a>\u793A\u4F8B</h3><pre><code class="language-tsx">// \u5B9A\u4E49:\npageRouter.use(&#39;/share/:type/:id/&#39;, ShareContentPage);\n\n// \u5728 ShareContentPage \u4E2D\u4F7F\u7528:\nexport const ShareContentPage = (props: PageProps) =&gt; {\n  // \u83B7\u53D6\u53C2\u6570\n  const type = props.urlParameters[&#39;type&#39;];\n  const id = props.urlParameters[&#39;id&#39;];\n\n  return (\n    &lt;div&gt;\n      \u6B63\u5728\u67E5\u770B {type}\uFF0CID\u4E3A: {id}\n    &lt;/div&gt;\n  );\n};\n</code></pre>\n<h2 id="4-\u9AD8\u7EA7\u7279\u6027"><a class="header-anchor" href="#4-\u9AD8\u7EA7\u7279\u6027">#</a>4. \u{1F680} \u9AD8\u7EA7\u7279\u6027</h2><h3 id="4-1-\u5D4C\u5957\u8DEF\u7531-\u6A21\u5757\u5316"><a class="header-anchor" href="#4-1-\u5D4C\u5957\u8DEF\u7531-\u6A21\u5757\u5316">#</a>4.1 \u{1F38E} \u5D4C\u5957\u8DEF\u7531 (\u6A21\u5757\u5316)</h3><p>\u4F60\u53EF\u4EE5\u5C06\u5E94\u7528\u7A0B\u5E8F\u62C6\u5206\u4E3A\u5B50\u6A21\u5757\u3002</p>\n<pre><code class="language-tsx">// 1. \u4E3A\u7528\u6237\u4E2A\u4EBA\u8D44\u6599\u533A\u57DF\u521B\u5EFA\u4E00\u4E2A\u5B50\u8DEF\u7531\u5668\nconst userPageRouter = new PageRouter();\nuserPageRouter.use(&#39;/profile&#39;, UserProfilePage);\nuserPageRouter.use(&#39;/settings&#39;, UserSettingsPage);\n\n// 2. \u5C06\u5176\u6302\u8F7D\u5230\u4E3B\u8DEF\u7531\u5668\u4E0B\u7684 &#39;/user&#39; \u8DEF\u5F84\nconst mainRouter = new PageRouter();\nmainRouter.use(&#39;/user&#39;, userPageRouter);\n\n// \u73B0\u5728\u7684 URL \u662F: /user/profile, /user/settings\n</code></pre>\n<h3 id="4-2-\u4E2D\u95F4\u4EF6\u8FC7\u6EE4\u5668-\u9274\u6743"><a class="header-anchor" href="#4-2-\u4E2D\u95F4\u4EF6\u8FC7\u6EE4\u5668-\u9274\u6743">#</a>4.2 \u{1F6E1}\uFE0F \u4E2D\u95F4\u4EF6\u8FC7\u6EE4\u5668 (\u9274\u6743)</h3><p>\u4F60\u53EF\u4EE5\u9644\u52A0\u4E00\u4E2A\u201C\u8FC7\u6EE4\u5668 (Filter)\u201D\u51FD\u6570\uFF0C\u8BE5\u51FD\u6570\u4F1A\u5728 <em>\u4EFB\u4F55</em> \u8DEF\u7531\u89E3\u6790\u4E4B\u524D\u8FD0\u884C\u3002\u5982\u679C\u8FC7\u6EE4\u5668\u5904\u7406\u4E86\u8BF7\u6C42\uFF08\u4F8B\u5982\uFF0C\u91CD\u5B9A\u5411\u5230\u767B\u5F55\uFF09\u6216\u8FD4\u56DE\u4E86\u4E00\u4E2A\u8282\u70B9\uFF0C\u8DEF\u7531\u5C06\u505C\u6B62\u3002\u5982\u679C\u5B83\u8FD4\u56DE <code>null</code>\uFF0C\u8DEF\u7531\u5C06\u7EE7\u7EED\u3002</p>\n<pre><code class="language-tsx">// \u5168\u5C40\u8FC7\u6EE4\u5668\npageRouter.setFilter(checkAgreement);\n\n// \u7279\u5B9A\u8DEF\u7531\u8FC7\u6EE4\u5668 (\u4E2D\u95F4\u4EF6\u6A21\u5F0F)\nconst checkAuth = async (props) =&gt; {\n  if (!isLoggedIn()) {\n    // \u6E32\u67D3\u767B\u5F55\u9875\u9762\u6216\u91CD\u5B9A\u5411\n    return &lt;LoginPage /&gt;;\n  }\n  return null; // \u7EE7\u7EED\u6267\u884C\u4E0B\u4E00\u4E2A\u5904\u7406\u7A0B\u5E8F\n};\n\n// \u7528\u6CD5: checkAuth \u5148\u8FD0\u884C\uFF0C\u7136\u540E\u624D\u662F UserMinePage\nuserPageRouter.use(&#39;/mine&#39;, checkAuth, UserMinePage);\n</code></pre>\n<h3 id="4-3-\u6846\u67B6\u9875\u9762-\u5E03\u5C40"><a class="header-anchor" href="#4-3-\u6846\u67B6\u9875\u9762-\u5E03\u5C40">#</a>4.3 \u{1F5BC}\uFE0F \u6846\u67B6\u9875\u9762 (\u5E03\u5C40)</h3><p>\u4E0E React Router \u5D4C\u5957 <code>&lt;Outlet /&gt;</code> \u4E0D\u540C\uFF0CLupine \u4F7F\u7528 <code>setFramePage</code> \u65B9\u6CD5\u4E3A\u8BE5 Router \u5185\u7684\u6240\u6709\u8DEF\u7531\u5B9A\u4E49\u4E00\u4E2A\u201C\u5305\u88C5\u5668\u201D\u6216\u201C\u5E03\u5C40\u201D\u3002</p>\n<pre><code class="language-tsx">// 1. \u5B9A\u4E49\u6846\u67B6\nconst TopFrame = (placeholderClass, childNode) =&gt; {\n  return (\n    &lt;div class=&#39;app-container&#39;&gt;\n      &lt;Header /&gt;\n      &lt;Sidebar /&gt;\n      {/* \u5185\u5BB9\u6CE8\u5165\u70B9 */}\n      &lt;div class={placeholderClass}&gt;{childNode}&lt;/div&gt;\n    &lt;/div&gt;\n  );\n};\n\n// 2. \u5E94\u7528\u5230 Router\nconst pageRouter = new PageRouter();\npageRouter.setFramePage({\n  component: TopFrame,\n  placeholderClassname: &#39;app-content-area&#39;, // \u5339\u914D\u4E0A\u9762\u7684 class\n});\n\npageRouter.use(&#39;/dashboard&#39;, DashboardPage);\n// \u7ED3\u679C: DashboardPage \u88AB\u6E32\u67D3\u5728 TopFrame \u7684 &#39;app-content-area&#39; div \u5185\u90E8\u3002\n</code></pre>\n<h3 id="4-4-\u5B50\u76EE\u5F55\u90E8\u7F72"><a class="header-anchor" href="#4-4-\u5B50\u76EE\u5F55\u90E8\u7F72">#</a>4.4 \u{1F4C2} \u5B50\u76EE\u5F55\u90E8\u7F72</h3><p>\u5982\u679C\u4F60\u7684\u5E94\u7528\u90E8\u7F72\u5728 <code>example.com/my-app/</code>\uFF0C\u4F60\u9700\u8981\u544A\u8BC9\u8DEF\u7531\u5668\u5FFD\u7565 <code>/my-app</code> \u524D\u7F00\u3002</p>\n<pre><code class="language-typescript">// \u5982\u679C\u7269\u7406\u8DEF\u5F84\u5B58\u5728\uFF0C\u8DEF\u7531\u5668\u9700\u8981\u77E5\u9053\u8981\u5FFD\u7565\u5B83\npageRouter.setSubDir(&#39;/my-app&#39;);\n</code></pre>\n';

  // apps/doc/web/src/markdown-built/zh/essentials/ssr.html
  var ssr_default2 = '<h1 id="ssr-\u670D\u52A1\u7AEF\u6E32\u67D3"><a class="header-anchor" href="#ssr-\u670D\u52A1\u7AEF\u6E32\u67D3">#</a>SSR (\u670D\u52A1\u7AEF\u6E32\u67D3)</h1><p>Lupine.js \u4ECE\u4E00\u5F00\u59CB\u5C31\u5C06 <strong>\u670D\u52A1\u7AEF\u6E32\u67D3 (SSR)</strong> \u89C6\u4E3A\u4E00\u7B49\u516C\u6C11\u3002\u5927\u591A\u6570 SPA \u6846\u67B6\u5C06 SSR \u89C6\u4E3A\u4E8B\u540E\u7684\u8865\u5145\uFF0C\u6216\u8005\u9700\u8981\u590D\u6742\u7684\u5143\u6846\u67B6\uFF08\u5982 React \u7684 Next.js\uFF09\u652F\u6301\uFF0C\u800C Lupine \u5219\u76F4\u63A5\u5C06 SSR \u96C6\u6210\u5230\u5176\u6838\u5FC3\u67B6\u6784\u4E2D\uFF08<code>lupine.api</code> \u548C <code>lupine.web</code>\uFF09\u3002</p>\n<h2 id="1-\u5DE5\u4F5C\u539F\u7406"><a class="header-anchor" href="#1-\u5DE5\u4F5C\u539F\u7406">#</a>1. \u2699\uFE0F \u5DE5\u4F5C\u539F\u7406</h2><p>\u5F53\u7528\u6237\u8BF7\u6C42\u4E00\u4E2A\u4E0D\u5BF9\u5E94\u9759\u6001\u6587\u4EF6\uFF08\u5982\u56FE\u7247\u6216 JS \u6587\u4EF6\uFF09\u7684 URL \u65F6\uFF0C<code>serverSideRenderPage</code> \u51FD\u6570\u5C31\u4F1A\u63A5\u7BA1\u5904\u7406\u3002</p>\n<h3 id="\u6D41\u7A0B"><a class="header-anchor" href="#\u6D41\u7A0B">#</a>\u6D41\u7A0B\uFF1A</h3><ol>\n<li><strong>\u8BF7\u6C42\u62E6\u622A</strong>: \u670D\u52A1\u7AEF\u62E6\u622A HTTP \u8BF7\u6C42\u3002</li>\n<li><strong>\u73AF\u5883\u6CE8\u5165</strong>: \u5B83\u5C06\u670D\u52A1\u7AEF\u73AF\u5883\u53D8\u91CF\uFF08\u4EE5 <code>WEB.</code> \u5F00\u5934\uFF09\u6CE8\u5165\u5230\u8FD0\u884C\u65F6\u3002</li>\n<li><strong>\u9875\u9762\u751F\u6210</strong>: \u5B83\u8C03\u7528 <code>_lupineJs.generatePage</code> <strong>\u5728\u670D\u52A1\u7AEF</strong> \u6267\u884C\u4F60\u7684\u524D\u7AEF\u903B\u8F91\u3002</li>\n<li><strong>HTML \u6784\u5EFA</strong>: \u5B83\u5C06\u6700\u7EC8\u7684 HTML \u62FC\u63A5\u5728\u4E00\u8D77\uFF0C\u5305\u62EC\uFF1A<ul>\n<li><strong>\u4E3B\u9898\u4E0E\u6837\u5F0F</strong>: \u5173\u952E CSS \u548C\u5F53\u524D\u4E3B\u9898\u88AB\u76F4\u63A5\u6CE8\u5165\uFF0C\u9632\u6B62\u201C\u5185\u5BB9\u65E0\u6837\u5F0F\u95EA\u70C1\u201D (FOUC)\u3002</li>\n<li><strong>\u5143\u6570\u636E</strong>: \u8BA1\u7B97\u5E76\u63D2\u5165 SEO \u6807\u9898\u548C\u63CF\u8FF0\u3002</li>\n<li><strong>\u72B6\u6001\u6CE8\u6C34 (Hydration)</strong>: \u9875\u9762\u88AB\u52A0\u8F7D\u4E4B\u540E\uFF0C\u524D\u7AEF\u4F1A\u81EA\u52A8\u7ED1\u5B9A\u4E8B\u4EF6\u3002</li>\n</ul>\n</li>\n</ol>\n<h2 id="2-\u96F6\u914D\u7F6E-seo"><a class="header-anchor" href="#2-\u96F6\u914D\u7F6E-seo">#</a>2. \u{1F50D} \u96F6\u914D\u7F6E SEO</h2><p>Lupine SSR \u7684\u6700\u5927\u597D\u5904\u4E4B\u4E00\u662F\u81EA\u52A8\u652F\u6301 SEO\u3002\u901A\u8FC7\u4F7F\u7528 <code>MetaData</code> \u7B49\u7EC4\u4EF6\uFF0C\u4F60\u7684\u9875\u9762\u5728\u5BA2\u6237\u7AEF\u8FD0\u884C\u4EFB\u4F55 JavaScript <strong>\u4E4B\u524D</strong>\uFF0C\u5C31\u5DF2\u7ECF\u544A\u8BC9\u4E86\u641C\u7D22\u5F15\u64CE\u5B83\u4EEC\u9700\u8981\u77E5\u9053\u7684\u786E\u5207\u5185\u5BB9\u3002</p>\n<h3 id="\u793A\u4F8B-\u793E\u4EA4\u5206\u4EAB-opengraph"><a class="header-anchor" href="#\u793A\u4F8B-\u793E\u4EA4\u5206\u4EAB-opengraph">#</a>\u793A\u4F8B\uFF1A\u793E\u4EA4\u5206\u4EAB (OpenGraph)</h3><p>\u5728 <code>share-content.tsx</code> \u4E2D\uFF0C\u4F60\u53EF\u4EE5\u6839\u636E\u6B63\u5728\u67E5\u770B\u7684\u5185\u5BB9\u52A8\u6001\u8BBE\u7F6E meta \u6807\u7B7E\uFF1A</p>\n<pre><code class="language-tsx">export const ShareContentPage = async (props: PageProps) =&gt; {\n  // 1. \u83B7\u53D6\u6570\u636E (\u5728\u670D\u52A1\u7AEF\u4E5F\u53EF\u884C\uFF01)\n  const record = await fetchRecord(props.urlParameters[&#39;id&#39;]);\n\n  // 2. \u5B9A\u4E49 SEO/\u793E\u4EA4\u5A92\u4F53\u5143\u6570\u636E\n  return (\n    &lt;div&gt;\n      &lt;MetaData property=&#39;og:title&#39; content={record.title} /&gt;\n      &lt;MetaData property=&#39;og:description&#39; content={record.description} /&gt;\n      &lt;MetaData property=&#39;og:image&#39; content={record.imageUrl} /&gt;\n      &lt;MetaData property=&#39;og:url&#39; content={props.url} /&gt;\n\n      &lt;h1&gt;{record.title}&lt;/h1&gt;\n      {/* ... \u5185\u5BB9 ... */}\n    &lt;/div&gt;\n  );\n};\n</code></pre>\n<h2 id="3-\u73AF\u5883\u53D8\u91CF"><a class="header-anchor" href="#3-\u73AF\u5883\u53D8\u91CF">#</a>3. \u{1F6E0}\uFE0F \u73AF\u5883\u53D8\u91CF</h2><p>Lupine \u81EA\u52A8\u5C06\u4F60\u7684\u670D\u52A1\u7AEF\u73AF\u5883\u6865\u63A5\u5230\u524D\u7AEF\u3002</p>\n<h3 id="\u5B9A\u4E49\u53D8\u91CF"><a class="header-anchor" href="#\u5B9A\u4E49\u53D8\u91CF">#</a>\u5B9A\u4E49\u53D8\u91CF</h3><p>\u5728 <code>.env</code> \u6587\u4EF6\u4E2D\uFF0C\u4EE5 <code>WEB.</code> \u5F00\u5934\u7684\u53D8\u91CF\u88AB\u6807\u8BB0\u4E3A\u524D\u7AEF\u53EF\u7528\uFF1A</p>\n<pre><code class="language-ini"># .env\nWEB.API_BASE_URL=https://api.example.com\nWEB.SITE_NAME=My Awesome App\nSECRET_KEY=xxxx  &lt;-- \u8FD9\u4E2A\u4FDD\u7559\u5728\u670D\u52A1\u7AEF\uFF01\n</code></pre>\n<h3 id="\u8BBF\u95EE\u53D8\u91CF"><a class="header-anchor" href="#\u8BBF\u95EE\u53D8\u91CF">#</a>\u8BBF\u95EE\u53D8\u91CF</h3><p>\u5728 SSR \u671F\u95F4\uFF08\u4EE5\u53CA\u968F\u540E\u7684\u6D4F\u89C8\u5668\u4E2D\uFF09\uFF0C\u53EF\u4EE5\u901A\u8FC7 <code>getWebEnv()</code> \u8BBF\u95EE\u8FD9\u4E9B\u53D8\u91CF\uFF1A</p>\n<pre><code class="language-typescript">// \u4EFB\u610F\u7EC4\u4EF6\nimport { getWebEnv } from &#39;lupine.web&#39;;\n\nconst env = getWebEnv();\nconsole.log(env.API_BASE_URL); // &quot;https://api.example.com&quot;\n</code></pre>\n<h2 id="4-webconfig-\u52A8\u6001\u8FD0\u884C\u65F6\u914D\u7F6E"><a class="header-anchor" href="#4-webconfig-\u52A8\u6001\u8FD0\u884C\u65F6\u914D\u7F6E">#</a>4. \u2699\uFE0F WebConfig: \u52A8\u6001\u8FD0\u884C\u65F6\u914D\u7F6E</h2><p>\u6709\u65F6\u4F60\u9700\u8981\u4E00\u4E9B\u53EF\u4EE5\u5728\u8FD0\u884C\u65F6\u66F4\u6539\u7684\u914D\u7F6E\uFF08\u4F8B\u5982\u7BA1\u7406\u540E\u53F0\u7684\u201C\u6BCF\u9875\u6700\u5927\u884C\u6570\u201D\u6216\u201C\u7EF4\u62A4\u6A21\u5F0F\u201D\uFF09\uFF0C\u800C\u65E0\u9700\u91CD\u65B0\u90E8\u7F72\u3002Lupine \u4E3A\u6B64\u63D0\u4F9B\u4E86 <code>WebConfig</code>\u3002</p>\n<p><strong>\u673A\u5236\uFF1A</strong></p>\n<ol>\n<li><strong>SSR \u6CE8\u5165</strong>: \u5728\u9996\u6B21\u52A0\u8F7D\u9875\u9762\u65F6\uFF0C\u670D\u52A1\u7AEF\u83B7\u53D6\u8FD9\u4E9B\u914D\u7F6E\u5E76\u5C06\u5176\u6CE8\u5165\u5230\u4E00\u4E2A <code>&lt;script id=&quot;web-setting&quot;&gt;</code> \u6807\u7B7E\u4E2D\u3002</li>\n<li><strong>\u6CE8\u6C34 (Hydration)</strong>: <code>WebConfig.init()</code> (\u81EA\u52A8\u8C03\u7528) \u8BFB\u53D6\u6B64\u811A\u672C\u6807\u7B7E\uFF0C\u6709\u6548\u5730\u540C\u6B65\u201C\u6CE8\u6C34\u201D\u914D\u7F6E\u3002</li>\n<li><strong>\u5F02\u6B65\u56DE\u9000</strong>: \u5982\u679C\u5E94\u7528\u4F5C\u4E3A\u7EAF SPA \u8FD0\u884C\uFF08\u4EC5\u5BA2\u6237\u7AEF\u5BFC\u822A\uFF09\uFF0C\u4E14\u7F13\u5B58\u7F3A\u5931\uFF0C<code>WebConfig.get()</code> \u4F1A\u4ECE API \u83B7\u53D6\u914D\u7F6E\u3002</li>\n</ol>\n<h3 id="\u7528\u6CD5"><a class="header-anchor" href="#\u7528\u6CD5">#</a>\u7528\u6CD5</h3><p><strong>\u7ED1\u5B9A API (\u5165\u53E3\u70B9):</strong></p>\n<pre><code class="language-tsx">// src/index.tsx\nbindWebConfigApi(&#39;/api/admin/web-config&#39;);\n</code></pre>\n<p><strong>\u4F7F\u7528\u914D\u7F6E (\u7EC4\u4EF6):</strong></p>\n<pre><code class="language-tsx">// admin-poster-page.tsx\nconst PosterList = async () =&gt; {\n  // \u5F02\u6B65\u8BBF\u95EE\u786E\u4FDD\u6570\u636E\u5DF2\u5C31\u7EEA\n  const maxRows = await WebConfig.get(&#39;poster_max_rows&#39;, 10);\n  const category = await WebConfig.get(&#39;current_category&#39;, &#39;default&#39;);\n\n  // ... \u4F7F\u7528\u914D\u7F6E ...\n};\n</code></pre>\n<blockquote>\n<p>[!IMPORTANT]\n\u7531\u4E8E <code>WebConfig</code> \u53EF\u80FD\u9700\u8981\u83B7\u53D6\u6570\u636E\uFF08\u5728\u5BA2\u6237\u7AEF\u5BFC\u822A\u65F6\uFF09\uFF0C\u5B83\u88AB\u8BBE\u8BA1\u4E3A <strong>\u5F02\u6B65 API</strong>\u3002\u8BF7\u59CB\u7EC8\u4F7F\u7528 <code>await WebConfig.get(...)</code>\u3002</p>\n</blockquote>\n<h2 id="5-\u667A\u80FD\u7F13\u5B58\u4E0E\u6027\u80FD"><a class="header-anchor" href="#5-\u667A\u80FD\u7F13\u5B58\u4E0E\u6027\u80FD">#</a>5. \u26A1 \u667A\u80FD\u7F13\u5B58\u4E0E\u6027\u80FD</h2><p>Lupine \u7684 SSR \u4E0D\u4EC5\u4EC5\u662F\u4E3A\u4E86\u6E32\u67D3\uFF0C\u66F4\u662F\u4E3A\u4E86\u901F\u5EA6\u3002</p>\n<ul>\n<li><strong>\u6A21\u677F\u7F13\u5B58</strong>: \u670D\u52A1\u7AEF\u7F13\u5B58 <code>index.html</code> \u7684\u7ED3\u6784\u4EE5\u51CF\u5C11\u6587\u4EF6\u7CFB\u7EDF\u8BFB\u53D6\u3002\u5B83\u8BC6\u522B\u6807\u9898\u3001Meta\u3001CSS \u548C\u5185\u5BB9\u7684\u201C\u63D2\u69FD\u201D (<code>packages/lupine.api/src/api/server-render.ts</code>)\u3002</li>\n<li><strong>CSS \u4E0E\u4E3B\u9898\u6CE8\u5165</strong>: \u901A\u8FC7\u5728\u670D\u52A1\u7AEF\u8BA1\u7B97\u5173\u952E CSS (<code>generateAllGlobalStyles</code>)\uFF0C\u6D4F\u89C8\u5668\u53EF\u4EE5\u7ACB\u5373\u63A5\u6536\u5230\u4E00\u4E2A\u6837\u5F0F\u5B8C\u6574\u7684\u9875\u9762\u3002\u5373\u4F7F\u7528\u6237\u7981\u7528\u4E86 JavaScript \u6216\u52A0\u8F7D\u7F13\u6162\uFF0C\u4ED6\u4EEC\u4E5F\u80FD\u770B\u5230\u5B8C\u7F8E\u7684 UI\u3002</li>\n</ul>\n';

  // apps/doc/web/src/markdown-built/zh/essentials/theme.html
  var theme_default3 = '<h1 id="theme-\u4E3B\u9898"><a class="header-anchor" href="#theme-\u4E3B\u9898">#</a>\u{1F317} Theme (\u4E3B\u9898)</h1><p>Lupine.js \u5185\u7F6E\u4E86\u5BF9\u591A\u4E3B\u9898\uFF08\u5982\u4EAE\u8272/\u6697\u8272\u6A21\u5F0F\uFF09\u7684\u652F\u6301\uFF0C\u5E76\u5B8C\u7F8E\u96C6\u6210\u4E86 SSR\u3002</p>\n<h2 id="1-\u8BBE\u7F6E-setup"><a class="header-anchor" href="#1-\u8BBE\u7F6E-setup">#</a>1. \u{1F3C1} \u8BBE\u7F6E (Setup)</h2><p>\u4F60\u9700\u8981\u5728\u5E94\u7528\u7A0B\u5E8F\u5165\u53E3\u70B9\uFF08\u901A\u5E38\u662F <code>index.tsx</code>\uFF09\u7ED1\u5B9A\u4F60\u7684\u4E3B\u9898\u3002</p>\n<h3 id="bindtheme"><a class="header-anchor" href="#bindtheme">#</a><code>bindTheme</code></h3><p>\u5C06\u4F60\u7684\u4E3B\u9898\u5B9A\u4E49\u8FDE\u63A5\u5230 Lupine \u8FD0\u884C\u65F6\u3002</p>\n<pre><code class="language-tsx">// src/index.tsx\nimport { bindTheme } from &#39;lupine.web&#39;;\nimport { lightThemes, darkThemes } from &#39;./themes&#39;;\n\n// \u7ED1\u5B9A\u9ED8\u8BA4\u4E3B\u9898\u548C\u53EF\u7528\u4E3B\u9898\nbindTheme(&#39;light&#39;, {\n  light: lightThemes,\n  dark: darkThemes,\n});\n</code></pre>\n<ul>\n<li><strong>\u76EE\u7684</strong>: \u8BA9\u7CFB\u7EDF\u77E5\u9053\u6709\u54EA\u4E9B\u53EF\u7528\u4E3B\u9898\u4EE5\u53CA\u9ED8\u8BA4\u4E3B\u9898\u662F\u4EC0\u4E48\u3002</li>\n<li><strong>\u4F4D\u7F6E</strong>: \u5728\u6E32\u67D3\u5E94\u7528\u4E4B\u524D\u8C03\u7528\u3002</li>\n</ul>\n<h2 id="2-\u7528\u6CD5-usage"><a class="header-anchor" href="#2-\u7528\u6CD5-usage">#</a>2. \u{1F3AE} \u7528\u6CD5 (Usage)</h2><h3 id="\u8BBF\u95EE\u4E0E\u66F4\u65B0"><a class="header-anchor" href="#\u8BBF\u95EE\u4E0E\u66F4\u65B0">#</a>\u8BBF\u95EE\u4E0E\u66F4\u65B0</h3><p>\u4F60\u53EF\u4EE5\u4F7F\u7528\u63D0\u4F9B\u7684\u8F85\u52A9\u51FD\u6570\u83B7\u53D6\u5F53\u524D\u4E3B\u9898\u6216\u5207\u6362\u4E3B\u9898\u3002</p>\n<pre><code class="language-tsx">import { getCurrentTheme, updateTheme } from &#39;lupine.web&#39;;\n\n// \u83B7\u53D6\u5F53\u524D\u4E3B\u9898\u4FE1\u606F\nconst { themeName, themes } = getCurrentTheme();\n\n// \u5207\u6362\u5230\u6697\u8272\u6A21\u5F0F\nconst onSwitch = () =&gt; {\n  updateTheme(&#39;dark&#39;);\n};\n</code></pre>\n<h3 id="themeselector-\u7EC4\u4EF6"><a class="header-anchor" href="#themeselector-\u7EC4\u4EF6">#</a><code>ThemeSelector</code> \u7EC4\u4EF6</h3><p>Lupine \u63D0\u4F9B\u4E86\u4E00\u4E2A\u5185\u7F6E\u7684 <code>ThemeSelector</code> \u7EC4\u4EF6\uFF0C\u7528\u4E8E\u65B9\u4FBF\u5730\u5207\u6362\u4E3B\u9898\u3002</p>\n<pre><code class="language-tsx">import { ThemeSelector } from &#39;lupine.components&#39;;\n\nconst Header = () =&gt; (\n  &lt;header&gt;\n    &lt;h1&gt;\u6211\u7684\u5E94\u7528&lt;/h1&gt;\n    &lt;ThemeSelector /&gt;\n  &lt;/header&gt;\n);\n</code></pre>\n<h2 id="3-\u670D\u52A1\u7AEF\u6E32\u67D3-ssr"><a class="header-anchor" href="#3-\u670D\u52A1\u7AEF\u6E32\u67D3-ssr">#</a>3. \u26A1 \u670D\u52A1\u7AEF\u6E32\u67D3 (SSR)</h2><p>Lupine \u6700\u5F3A\u5927\u7684\u529F\u80FD\u4E4B\u4E00\u662F\u5728 SSR \u671F\u95F4\u652F\u6301 <strong>\u65E0\u95EA\u70C1 (FOUC-free)</strong> \u4E3B\u9898\u3002</p>\n<ul>\n<li><strong>Cookie \u6CE8\u5165</strong>: \u5F53\u524D\u4E3B\u9898\u5B58\u50A8\u5728 Cookie \u4E2D\u3002</li>\n<li><strong>\u670D\u52A1\u7AEF\u5904\u7406</strong>: \u5728 SSR \u671F\u95F4\uFF0C\u670D\u52A1\u7AEF\u8BFB\u53D6\u6B64 Cookie\u3002</li>\n<li><strong>\u6837\u5F0F\u6CE8\u5165</strong>: \u670D\u52A1\u7AEF\u751F\u6210\u5F53\u524D\u6D3B\u52A8\u4E3B\u9898\u7684 CSS \u53D8\u91CF\uFF0C\u5E76\u5C06\u5176\u76F4\u63A5\u6CE8\u5165\u5230 HTML \u7684 <code>&lt;style&gt;</code> \u6807\u7B7E\u4E2D\u3002</li>\n</ul>\n<p>\u8FD9\u786E\u4FDD\u4E86\u5F53\u7528\u6237\u52A0\u8F7D\u9875\u9762\u65F6\uFF0C\u5728\u5BA2\u6237\u7AEF\u8FD0\u884C\u4EFB\u4F55 JavaScript \u4E4B\u524D\uFF0C\u9875\u9762\u5C31\u5DF2\u7ECF\u5177\u6709\u6B63\u786E\u7684\u6837\u5F0F\uFF08\u4F8B\u5982\u6697\u8272\u80CC\u666F\uFF09\u3002</p>\n<h2 id="4-\u7BA1\u7406\u5DE5\u5177-admin-tools"><a class="header-anchor" href="#4-\u7BA1\u7406\u5DE5\u5177-admin-tools">#</a>4. \u{1F6E0}\uFE0F \u7BA1\u7406\u5DE5\u5177 (Admin Tools)</h2><p>\u4E3A\u4E86\u53EF\u89C6\u5316\u4F60\u7684\u4E3B\u9898\u548C\u8C03\u8BD5\u989C\u8272\uFF0C\u4F60\u53EF\u4EE5\u4F7F\u7528\u540E\u53F0\u7BA1\u7406\u8F85\u52A9\u7EC4\u4EF6\u3002</p>\n<pre><code class="language-tsx">// \u7528\u4E8E\u5217\u51FA\u6240\u6709\u4E3B\u9898\u989C\u8272\u4EE5\u8FDB\u884C\u5BF9\u6BD4\u7684\u8F85\u52A9\u5DE5\u5177\nimport { TestThemes } from &#39;lupine.api/admin&#39;;\n</code></pre>\n<p>\u6B64\u7EC4\u4EF6\u6E32\u67D3\u4E00\u4E2A\u7F51\u683C\uFF0C\u663E\u793A\u4F60\u5B9A\u4E49\u7684\u989C\u8272\u5728\u4E0D\u540C\u4E3B\u9898\u4E0B\u7684\u5916\u89C2\uFF0C\u5E2E\u52A9\u4F60\u627E\u5230\u6B63\u786E\u7684\u952E\u503C\u548C\u5BF9\u6BD4\u5EA6\u3002</p>\n';

  // apps/doc/web/src/markdown-built/zh/guide/install.html
  var install_default2 = '<h1 id="\u5B89\u88C5\u8BF4\u660E"><a class="header-anchor" href="#\u5B89\u88C5\u8BF4\u660E">#</a>\u5B89\u88C5\u8BF4\u660E</h1><p>Lupine.js \u662F\u4E00\u4E2A\u529F\u80FD\u9F50\u5168\u7684 Web \u5E94\u7528\u7A0B\u5E8F\u6846\u67B6\uFF0C\u5305\u542B\u524D\u7AEF\u548C\u540E\u7AEF\u3002\u524D\u7AEF Lupine.web \u662F\u4E00\u4E2A\u6781\u5176\u8F7B\u91CF\u7EA7\u7684\u6846\u67B6\uFF0C\u4F7F\u7528 React TSX \u8BED\u6CD5\u3002\u540E\u7AEF Lupine.api \u662F\u4E00\u4E2A\u7C7B\u4F3C Express \u7684\u9AD8\u6548\u6781\u7B80\u6846\u67B6\u3002</p>\n<h2 id="\u5FEB\u901F\u5F00\u59CB"><a class="header-anchor" href="#\u5FEB\u901F\u5F00\u59CB">#</a>\u5FEB\u901F\u5F00\u59CB</h2><h3 id="1-\u521B\u5EFA\u9879\u76EE"><a class="header-anchor" href="#1-\u521B\u5EFA\u9879\u76EE">#</a>1. \u521B\u5EFA\u9879\u76EE</h3><p>\u6700\u7B80\u5355\u7684\u65B9\u5F0F\u5C31\u662F\u4F7F\u7528 <code>create-lupine</code> \u547D\u4EE4\u6765\u521B\u5EFA\u4E00\u4E2A\u65B0\u7684\u5E94\u7528\u7A0B\u5E8F\u3002\u5728\u521B\u5EFA\u7684\u65F6\u5019\u60A8\u53EF\u4EE5\u9009\u62E9\u6A21\u7248\u3002</p>\n<pre><code class="language-bash">npx create-lupine@latest my-app\n</code></pre>\n<p>\u5982\u679C\u60A8\u50CF\u66F4\u6DF1\u5165\u7684\u4E86\u89E3 lupine.js\uFF0C\u60A8\u53EF\u4EE5\u4ECE github \u4E0A\u514B\u9686\u4ED3\u5E93\uFF0C\u8FD9\u6837\u66F4\u65B9\u4FBF\u7684\u672C\u5730\u67E5\u770B\u6838\u5FC3\u4EE3\u7801\u3002</p>\n<pre><code class="language-bash">git clone https://github.com/uuware/lupine.js.git\n</code></pre>\n<h3 id="2-\u5B89\u88C5\u4F9D\u8D56"><a class="header-anchor" href="#2-\u5B89\u88C5\u4F9D\u8D56">#</a>2. \u5B89\u88C5\u4F9D\u8D56</h3><pre><code class="language-bash">npm install\n</code></pre>\n<h3 id="3-\u914D\u7F6E\u73AF\u5883"><a class="header-anchor" href="#3-\u914D\u7F6E\u73AF\u5883">#</a>3. \u914D\u7F6E\u73AF\u5883</h3><p>\u5982\u679C\u4F7F\u7528 <code>create-lupine</code> \u521B\u5EFA\u7684\u9879\u76EE\uFF0C <code>.env</code> \u6587\u4EF6\u5DF2\u7ECF\u751F\u6210\u3002</p>\n<p>\u5982\u679C\u4F7F\u7528 <code>git clone</code> \u521B\u5EFA\u7684\u9879\u76EE\uFF0C\u5219\u9700\u8981\u914D\u7F6E\u73AF\u5883\u3002</p>\n<p>\u5C06 <code>.env.sample</code> \u6587\u4EF6\u590D\u5236\u4E3A\u540D\u4E3A <code>.env</code> \u7684\u65B0\u6587\u4EF6\u3002</p>\n<p>\u4F7F\u7528 <code>git clone</code> \u521B\u5EFA\u7684\u9879\u76EE\uFF0C\u8FD8\u9700\u8981\u4F7F\u7528 <code>.env</code> \u6587\u4EF6\u4E2D\u7684\u793A\u4F8B\u811A\u672C\u4E3A\u4EE5\u4E0B\u53D8\u91CF\u751F\u6210\u5BC6\u94A5\uFF1A</p>\n<pre><code class="language-properties">ADMIN_PASS=\nCRYPTO_KEY=\nDEV_ADMIN_PASS=\nDEV_CRYPTO_KEY=\n</code></pre>\n<h3 id="4-\u8FD0\u884C\u5F00\u53D1\u5E94\u7528\u7A0B\u5E8F"><a class="header-anchor" href="#4-\u8FD0\u884C\u5F00\u53D1\u5E94\u7528\u7A0B\u5E8F">#</a>4. \u8FD0\u884C\u5F00\u53D1\u5E94\u7528\u7A0B\u5E8F</h3><pre><code class="language-bash">npm run dev\n</code></pre>\n<p>\u73B0\u5728\uFF0C\u60A8\u53EF\u4EE5\u901A\u8FC7 <a href="http://localhost:11080">http://localhost:11080</a> \u8BBF\u95EE\u5F00\u53D1\u5E94\u7528\u7A0B\u5E8F\u3002</p>\n<hr>\n<h2 id="\u672C\u5730-https-\u8BBE\u7F6E"><a class="header-anchor" href="#\u672C\u5730-https-\u8BBE\u7F6E">#</a>\u672C\u5730 HTTPS \u8BBE\u7F6E</h2><p>\u5BF9\u4E8E\u672C\u5730 HTTPS \u652F\u6301\uFF0C\u5EFA\u8BAE\u4F7F\u7528 <a href="https://github.com/FiloSottile/mkcert">mkcert</a>\u3002</p>\n<ol>\n<li>\u4E0B\u8F7D <code>mkcert</code> (\u4F8B\u5982 <code>mkcert-v1.4.4-windows-amd64.exe</code>)\u3002</li>\n<li>\u6253\u5F00\u7BA1\u7406\u5458\u63A7\u5236\u53F0\u5E76\u8FD0\u884C\uFF1A<pre><code class="language-bash">./mkcert-v1.4.4-windows-amd64 -install\n</code></pre>\n</li>\n<li>\u751F\u6210\u8BC1\u4E66\uFF08\u9488\u5BF9\u65B0\u8BBE\u7F6E\uFF09\uFF1A<pre><code class="language-bash">mkcert example.com &quot;*.example.com&quot; localhost 127.0.0.1 ::1\n</code></pre>\n</li>\n<li>\u5C06\u751F\u6210\u7684\u8BC1\u4E66\u6587\u4EF6\u590D\u5236\u5230 <code>/dev</code> \u6587\u4EF6\u5939\u3002</li>\n<li>\u66F4\u65B0\u60A8\u7684 <code>.env</code> \u6587\u4EF6\uFF0C\u4EE5\u5141\u8BB8\u4F7F\u7528\u81EA\u7B7E\u540D\u8BC1\u4E66\u8FDB\u884C\u672C\u5730 API \u8C03\u7528\uFF1A<pre><code class="language-properties">NODE_TLS_REJECT_UNAUTHORIZED=0\n</code></pre>\n</li>\n</ol>\n<h3 id="\u66FF\u4EE3\u65B9\u6848-\u901A\u8FC7-openssl-\u751F\u6210\u81EA\u7B7E\u540D\u8BC1\u4E66"><a class="header-anchor" href="#\u66FF\u4EE3\u65B9\u6848-\u901A\u8FC7-openssl-\u751F\u6210\u81EA\u7B7E\u540D\u8BC1\u4E66">#</a>\u66FF\u4EE3\u65B9\u6848\uFF1A\u901A\u8FC7 OpenSSL \u751F\u6210\u81EA\u7B7E\u540D\u8BC1\u4E66</h3><p>\u5982\u679C\u60A8\u66F4\u559C\u6B22 OpenSSL\uFF1A</p>\n<pre><code class="language-bash">openssl req -x509 -nodes -days 3650 -newkey rsa:2048 -keyout cert.key -out cert.pem -sha256\n</code></pre>\n<p>\u5728 Windows \u4E0A\uFF0C\u60A8\u53EF\u80FD\u9700\u8981\u4F7F\u7528\uFF1A\n<code>&quot;C:\\Program Files\\Git\\usr\\bin\\openssl.exe&quot;</code></p>\n<hr>\n<h2 id="\u8C03\u8BD5"><a class="header-anchor" href="#\u8C03\u8BD5">#</a>\u8C03\u8BD5</h2><h3 id="\u4EC5\u8C03\u8BD5\u540E\u7AEF"><a class="header-anchor" href="#\u4EC5\u8C03\u8BD5\u540E\u7AEF">#</a>\u4EC5\u8C03\u8BD5\u540E\u7AEF</h3><p>\u5728 VS Code \u4E2D\u6253\u5F00 <strong>Javascript Debug Terminal</strong> \u5E76\u8FD0\u884C\uFF1A</p>\n<pre><code class="language-bash">npm run dev\n</code></pre>\n<h3 id="\u8C03\u8BD5\u524D\u7AEF\u548C\u540E\u7AEF"><a class="header-anchor" href="#\u8C03\u8BD5\u524D\u7AEF\u548C\u540E\u7AEF">#</a>\u8C03\u8BD5\u524D\u7AEF\u548C\u540E\u7AEF</h3><ol>\n<li>\u8F6C\u5230 VS Code \u4E2D\u7684 <strong>Run and Debug</strong> \u4FA7\u8FB9\u680F\u3002</li>\n<li>\u4ECE\u4E0B\u62C9\u5217\u8868\u4E2D\u9009\u62E9 <strong>&quot;Lupine.js: Frontend &amp; Backend&quot;</strong>\u3002</li>\n<li>\u5728\u60A8\u7684\u524D\u7AEF\u6216\u540E\u7AEF\u4EE3\u7801\u4E2D\u8BBE\u7F6E\u65AD\u70B9\u5E76\u5F00\u59CB\u8C03\u8BD5\u3002</li>\n</ol>\n<hr>\n<h2 id="\u6DFB\u52A0\u65B0\u5E94\u7528"><a class="header-anchor" href="#\u6DFB\u52A0\u65B0\u5E94\u7528">#</a>\u6DFB\u52A0\u65B0\u5E94\u7528</h2><p>Lupine \u53EF\u4EE5\u5728\u540C\u4E00\u7AEF\u53E3\u4E0B\u8FD0\u884C\u591A\u4E2A\u5E94\u7528\u7A0B\u5E8F\u3002\u8981\u5728\u672C\u5730\u6DFB\u52A0\u65B0\u5E94\u7528\uFF1A</p>\n<ol>\n<li><strong>\u590D\u5236</strong>\uFF1A\u590D\u5236 <code>/apps</code> \u4E0B\u7684\u4EFB\u4F55\u5E94\u7528\u6587\u4EF6\u5939\u5E76\u91CD\u547D\u540D\u3002</li>\n<li><strong>\u66F4\u65B0\u914D\u7F6E</strong>\uFF1A\u4F7F\u7528\u65B0\u5E94\u7528\u540D\u79F0\u66F4\u65B0 <code>apps\\&lt;your-app&gt;\\lupine.json</code> \u6587\u4EF6\u3002</li>\n<li><strong>\u6CE8\u518C\u5E94\u7528</strong>\uFF1A\u5C06\u65B0\u5E94\u7528\u540D\u79F0\u6DFB\u52A0\u5230 <code>.env</code> \u6587\u4EF6\u4E2D\u7684 <code>APPS=</code>\u3002</li>\n<li><strong>\u865A\u62DF\u57DF\u540D</strong>\uFF1A\u5728 <code>.env</code> \u6587\u4EF6\u4E2D\u7684 <code>DOMAINS@[APP-NAME]=</code> \u6DFB\u52A0\u8BE5\u5E94\u7528\u7684\u865A\u62DF\u57DF\u540D\u3002</li>\n<li><strong>\u6784\u5EFA</strong>\uFF1A\u65B0\u5E94\u7528\u7684\u6E90\u4EE3\u7801\u5C06\u6784\u5EFA\u5230 <code>dist\\server_root</code>\u3002</li>\n</ol>\n<h3 id="\u672C\u5730\u865A\u62DF\u57DF\u540D\u8BBE\u7F6E"><a class="header-anchor" href="#\u672C\u5730\u865A\u62DF\u57DF\u540D\u8BBE\u7F6E">#</a>\u672C\u5730\u865A\u62DF\u57DF\u540D\u8BBE\u7F6E</h3><p>\u8981\u5728\u540C\u4E00\u7AEF\u53E3\u8BBF\u95EE\u591A\u4E2A\u5E94\u7528\uFF08\u4F8B\u5982 <code>app1.sample-domain.com</code>\uFF09\uFF0C\u8BF7\u4FEE\u6539\u60A8\u7684 hosts \u6587\u4EF6\uFF1A</p>\n<pre><code class="language-text">127.0.0.1 app1.sample-domain.com\n</code></pre>\n<p><strong>Hosts \u6587\u4EF6\u4F4D\u7F6E\uFF1A</strong></p>\n<ul>\n<li><strong>Windows</strong>: <code>C:\\Windows\\System32\\Drivers\\etc\\hosts</code></li>\n<li><strong>Linux/macOS</strong>: <code>/etc/hosts</code></li>\n</ul>\n<h3 id="\u521B\u5EFA\u5B50\u6587\u4EF6\u5939\u5E94\u7528"><a class="header-anchor" href="#\u521B\u5EFA\u5B50\u6587\u4EF6\u5939\u5E94\u7528">#</a>\u521B\u5EFA\u5B50\u6587\u4EF6\u5939\u5E94\u7528</h3><p>\u8981\u5728\u73B0\u6709\u5E94\u7528\u4E2D\u521B\u5EFA\u5B50\u5E94\u7528\u7A0B\u5E8F\uFF08\u4F8B\u5982 <code>admin_dev</code>\uFF09\uFF1A</p>\n<ol>\n<li>\u521B\u5EFA\u6587\u4EF6\u5939\uFF1A<code>apps\\[your-app-name]\\web\\src\\admin_dev</code></li>\n<li>\u6DFB\u52A0 <code>index.html</code> \u548C <code>index.tsx</code>\u3002</li>\n<li>\u66F4\u65B0 <code>apps\\[your-app-name]\\lupine.json</code> \u6761\u76EE\uFF1A<pre><code class="language-json">{\n  &quot;index&quot;: &quot;web/src/admin_dev/index.tsx&quot;,\n  &quot;html&quot;: &quot;web/src/admin_dev/index.html&quot;,\n  &quot;outdir&quot;: &quot;/admin_dev&quot;\n}\n</code></pre>\n</li>\n</ol>\n<hr>\n<h2 id="\u91CD\u8981\u63D0\u793A-ssr-\u4E2D\u7684\u5168\u5C40\u53D8\u91CF"><a class="header-anchor" href="#\u91CD\u8981\u63D0\u793A-ssr-\u4E2D\u7684\u5168\u5C40\u53D8\u91CF">#</a>\u91CD\u8981\u63D0\u793A\uFF1ASSR \u4E2D\u7684\u5168\u5C40\u53D8\u91CF</h2><p>\u7531\u4E8E Lupine \u4F7F\u7528\u670D\u52A1\u5668\u7AEF\u6E32\u67D3 (SSR)\uFF0C\u524D\u7AEF\u4EE3\u7801\u4E2D\u7684\u5168\u5C40\u53D8\u91CF\u7531<strong>\u6240\u6709\u7528\u6237\u5171\u4EAB</strong>\u3002\u8BF7\u6781\u5176\u8C28\u614E\u5730\u4F7F\u7528\u5B83\u4EEC\u3002</p>\n<p><strong>\u9519\u8BEF\u505A\u6CD5\uFF1A</strong>\n\u4EE5\u4E0B\u4EE3\u7801\u5F88\u5371\u9669\uFF0C\u56E0\u4E3A <code>cacheUser</code> \u662F\u5171\u4EAB\u7684\uFF1A</p>\n<pre><code class="language-typescript">const cacheUser: { user: null | Promise&lt;UserInfoType | null&gt; } = { user: null };\nexport const getUserInfo = (refresh?: boolean): Promise&lt;UserInfoType | null&gt; =&gt; {\n  if (!cacheUser.user || refresh) {\n    cacheUser.user = new Promise(async (resolve, reject) =&gt; {\n      // ...\n    });\n  }\n  return cacheUser.user;\n};\n</code></pre>\n<p><strong>\u6B63\u786E\u505A\u6CD5\uFF1A</strong>\n\u5728\u7EC4\u4EF6\u751F\u547D\u5468\u671F\u4E8B\u4EF6\uFF08\u5982 <code>onLoad</code>\uFF09\u4E2D\u521D\u59CB\u5316\u7279\u5B9A\u4E8E\u7528\u6237\u7684\u6570\u636E\uFF0C\u8FD9\u4E9B\u4E8B\u4EF6\u4EC5\u5728\u5BA2\u6237\u7AEF\u6267\u884C\u3002</p>\n<pre><code class="language-tsx">const cacheUser: { user: null | Promise&lt;UserInfoType | null&gt; } = { user: null };\nexport const UserInfo = (props?: any) =&gt; {\n  const ref: RefProps = {\n    onLoad: async () =&gt; {\n      // \u5728\u6B64\u5904\u8D4B\u503C\u5BF9\u4E8E\u5BA2\u6237\u7AEF\u662F\u5B89\u5168\u7684\n      cacheUser.user = ...\n    },\n  };\n  return (\n    &lt;div css={css} class=&#39;user-info-box&#39; ref={ref}&gt;\n      ...\n    &lt;/div&gt;\n  );\n};\n</code></pre>\n';

