    "/zh/articles/css-in-js-lupine.js": { html: css_in_js_lupine_js_default2, data: { "title": "\u96F6\u4F9D\u8D56\uFF0CLupine.js \u5982\u4F55\u5B9E\u73B0\u539F\u751F CSS-in-JS\uFF1F", "description": "\u6DF1\u5165\u89E3\u6790 Lupine.js \u5185\u7F6E\u7684\u9AD8\u6027\u80FD\u6837\u5F0F\u5F15\u64CE" }, headings: [{ "level": 2, "text": "1. \u544A\u522B className \u7684\u70E6\u607C", "id": "1-\u544A\u522B-classname-\u7684\u70E6\u607C" }, { "level": 2, "text": "2. \u50CF SCSS \u4E00\u6837\u5F3A\u5927\u7684\u5D4C\u5957\u529F\u80FD", "id": "2-\u50CF-scss-\u4E00\u6837\u5F3A\u5927\u7684\u5D4C\u5957\u529F\u80FD" }, { "level": 3, "text": "\u5D4C\u5957\u5B50\u5143\u7D20", "id": "\u5D4C\u5957\u5B50\u5143\u7D20" }, { "level": 3, "text": "\u7EC4\u5408\u9009\u62E9\u5668", "id": "\u7EC4\u5408\u9009\u62E9\u5668" }, { "level": 2, "text": "3. \u54CD\u5E94\u5F0F\u8BBE\u8BA1\uFF1A\u5A92\u4F53\u67E5\u8BE2\u4ECE\u672A\u5982\u6B64\u7B80\u5355", "id": "3-\u54CD\u5E94\u5F0F\u8BBE\u8BA1-\u5A92\u4F53\u67E5\u8BE2\u4ECE\u672A\u5982\u6B64\u7B80\u5355" }, { "level": 2, "text": "4. \u52A8\u753B\u5927\u5E08\uFF1A\u5185\u7F6E Keyframes \u652F\u6301", "id": "4-\u52A8\u753B\u5927\u5E08-\u5185\u7F6E-keyframes-\u652F\u6301" }, { "level": 2, "text": "5. \u52A8\u6001\u6837\u5F0F\u66F4\u65B0", "id": "5-\u52A8\u6001\u6837\u5F0F\u66F4\u65B0" }, { "level": 2, "text": "6. \u5168\u5C40\u6837\u5F0F\uFF1AbindGlobalStyle", "id": "6-\u5168\u5C40\u6837\u5F0F-bindglobalstyle" }, { "level": 2, "text": "7. \u4F20\u7EDF\u6D3E\uFF1A\u5BFC\u5165 .css \u6587\u4EF6", "id": "7-\u4F20\u7EDF\u6D3E-\u5BFC\u5165-css-\u6587\u4EF6" }, { "level": 2, "text": "\u603B\u7ED3", "id": "\u603B\u7ED3" }] },
    "/zh/articles/cv-generator": { html: cv_generator_default2, data: { "title": "\u5341\u5206\u949F\uFF01\u7528 Markdown \u6781\u901F\u6784\u5EFA\u9AD8\u989C\u503C\u7684\u4E2A\u4EBA\u7B80\u5386\u7F51\u7AD9", "description": "\u57FA\u4E8E Lupine.js \u7684 CV Starter \u6A21\u677F\uFF0C\u8BA9\u4F60\u7684\u7B80\u5386\u8131\u9896\u800C\u51FA" }, headings: [{ "level": 2, "text": "\u4E3A\u4EC0\u4E48\u9009\u62E9 Lupine CV Starter\uFF1F", "id": "\u4E3A\u4EC0\u4E48\u9009\u62E9-lupine-cv-starter" }, { "level": 2, "text": "\u{1F680} \u5FEB\u901F\u5F00\u59CB", "id": "\u5FEB\u901F\u5F00\u59CB" }, { "level": 3, "text": "1. \u521B\u5EFA\u9879\u76EE", "id": "1-\u521B\u5EFA\u9879\u76EE" }, { "level": 3, "text": "2. \u542F\u52A8\u9884\u89C8", "id": "2-\u542F\u52A8\u9884\u89C8" }, { "level": 2, "text": "\u{1F4DD} \u5B9A\u5236\u4F60\u7684\u7B80\u5386", "id": "\u5B9A\u5236\u4F60\u7684\u7B80\u5386" }, { "level": 3, "text": "\u4FEE\u6539\u5185\u5BB9", "id": "\u4FEE\u6539\u5185\u5BB9" }, { "level": 3, "text": "\u7BA1\u7406\u76EE\u5F55\u4E0E\u4FA7\u8FB9\u680F", "id": "\u7BA1\u7406\u76EE\u5F55\u4E0E\u4FA7\u8FB9\u680F" }, { "level": 3, "text": "\u914D\u7F6E\u9876\u90E8\u5BFC\u822A (\u53EF\u9009)", "id": "\u914D\u7F6E\u9876\u90E8\u5BFC\u822A-\u53EF\u9009" }, { "level": 3, "text": "\u4E2A\u6027\u5316\u8BBE\u7F6E", "id": "\u4E2A\u6027\u5316\u8BBE\u7F6E" }, { "level": 2, "text": "\u7ED3\u8BED", "id": "\u7ED3\u8BED" }] },
